// ─────────────────────────────────────────────
//  emprendy.ai — Agent 5: BE FIXER
//  Auto-corrección de bugs de Backend
// ─────────────────────────────────────────────
import { execSync } from 'child_process';
import * as fs from 'fs';
import * as path from 'path';
import Anthropic from '@anthropic-ai/sdk';
import { JiraIssue } from '../shared/types';
import { publish, notifySlack } from '../shared/bus';
import { transitionIssue, addComment } from '../shared/jira-mcp';

const client = new Anthropic();

// ─── Contexto del proyecto BE ─────────────────
function getBackendContext(): string {
  const pkg = fs.existsSync('package.json')
    ? JSON.parse(fs.readFileSync('package.json', 'utf-8'))
    : {};
  const deps = { ...pkg.dependencies, ...pkg.devDependencies };
  const stack = [];
  if (deps['express']) stack.push('Express.js');
  if (deps['fastify']) stack.push('Fastify');
  if (deps['@nestjs/core']) stack.push('NestJS');
  if (deps['prisma']) stack.push('Prisma ORM');
  if (deps['typeorm']) stack.push('TypeORM');
  if (deps['zod']) stack.push('Zod validation');
  if (deps['joi']) stack.push('Joi validation');
  if (deps['jsonwebtoken']) stack.push('JWT Auth');
  if (deps['pg']) stack.push('PostgreSQL');
  if (deps['mongoose']) stack.push('MongoDB/Mongoose');
  return stack.join(', ') || 'Node.js/Express/TypeScript';
}

// ─── Leer schema de Prisma si existe ──────────
function getPrismaSchema(): string {
  const candidates = ['prisma/schema.prisma', 'src/prisma/schema.prisma'];
  for (const p of candidates) {
    if (fs.existsSync(p)) return fs.readFileSync(p, 'utf-8');
  }
  return '';
}

// ─── Generar fix con Claude ───────────────────
async function generateFix(
  issue: JiraIssue,
  fileContent: string
): Promise<{
  fixedCode: string;
  testCode: string;
  migration?: string;
  explanation: string;
}> {
  const context = getBackendContext();
  const schema = getPrismaSchema();

  const response = await client.messages.create({
    model: 'claude-opus-4-5',
    max_tokens: 6000,
    system: `Eres un senior backend developer especializado en ${context}.
Trabajas en emprendy.ai, una plataforma para crear tiendas, restaurantes y servicios.

Al corregir un bug de backend:
1. Revisa el schema de base de datos (si aplica) para entender las relaciones
2. Asegura que los middlewares de validación estén correctos (Zod/Joi)
3. Verifica que los endpoints tengan autenticación cuando la requieren
4. El fix debe incluir manejo de errores apropiado (try/catch, status codes HTTP correctos)
5. Genera un test de integración que valide el comportamiento correcto
6. Si hay cambio en el schema DB, incluye la migración de Prisma
7. Documenta cualquier cambio de contrato en la API

Responde ÚNICAMENTE con JSON en este formato exacto:
{
  "fixedCode": "// código completo del archivo corregido",
  "testCode": "// test de integración con supertest/jest",
  "migration": "// SQL de migración si aplica, o null",
  "explanation": "// qué cambió y por qué (max 3 oraciones)"
}`,

    messages: [
      {
        role: 'user',
        content: `Issue Jira: ${issue.key}
Resumen: ${issue.summary}
Descripción: ${issue.description}
Archivo afectado: ${issue.affectedFile}
Código afectado: ${issue.codeSnippet}

Código actual del archivo:
\`\`\`typescript
${fileContent}
\`\`\`

${schema ? `Schema Prisma (referencia):\n\`\`\`\n${schema.slice(0, 3000)}\n\`\`\`` : ''}`,
      },
    ],
  });

  const text = response.content
    .filter((b) => b.type === 'text')
    .map((b) => (b as any).text)
    .join('');

  try {
    const clean = text.replace(/```json|```/g, '').trim();
    return JSON.parse(clean);
  } catch {
    throw new Error(`Could not parse Claude response: ${text.slice(0, 200)}`);
  }
}

// ─── Aplicar fix ──────────────────────────────
async function applyFix(
  issue: JiraIssue,
  fix: { fixedCode: string; testCode: string; migration?: string | null; explanation: string }
): Promise<void> {
  const branch = `fix/be-${issue.key}-${Date.now()}`;

  try {
    execSync(`git checkout -b ${branch}`, { stdio: 'inherit' });

    // Escribir código corregido
    const dir = path.dirname(issue.affectedFile);
    if (dir && dir !== '.') fs.mkdirSync(dir, { recursive: true });
    fs.writeFileSync(issue.affectedFile, fix.fixedCode);

    // Test de integración
    const testPath = issue.affectedFile
      .replace('/src/', '/src/__tests__/')
      .replace(/\.(ts)$/, '.test.ts');
    fs.mkdirSync(path.dirname(testPath), { recursive: true });
    fs.writeFileSync(testPath, fix.testCode);

    // Migración DB si hay cambios de schema
    if (fix.migration) {
      const migDir = 'prisma/migrations/manual';
      fs.mkdirSync(migDir, { recursive: true });
      const migFile = `${migDir}/${Date.now()}_${issue.key.toLowerCase()}.sql`;
      fs.writeFileSync(migFile, fix.migration);
      console.log(`[BE FIXER] Migration created: ${migFile}`);
    }

    // Type-check
    try {
      execSync('npx tsc --noEmit', { stdio: 'pipe' });
    } catch {
      console.warn('[BE FIXER] TypeScript errors — PR will flag them');
    }

    // Correr tests de integración del módulo afectado
    try {
      execSync(`npx jest ${testPath} --passWithNoTests`, { stdio: 'pipe' });
      console.log('[BE FIXER] Integration test passed ✅');
    } catch {
      console.warn('[BE FIXER] Test failed — still creating PR for review');
    }

    // Commit y push
    const filesToCommit = [
      issue.affectedFile,
      testPath,
      fix.migration ? 'prisma/migrations/manual' : '',
    ]
      .filter(Boolean)
      .join(' ');
    execSync(`git add ${filesToCommit}`, { stdio: 'inherit' });
    execSync(
      `git commit -m "fix(${issue.key}): ${issue.summary}

${fix.explanation}

Auto-fixed by BE Fixer Agent
Jira: ${issue.key}"`,
      { stdio: 'inherit' }
    );

    execSync(`git push origin ${branch}`, { stdio: 'inherit' });

    // PR
    try {
      const migrationNote = fix.migration
        ? '\n\n⚠️ **Incluye cambios de schema de base de datos. Revisar migración antes de mergear.**'
        : '';
      execSync(
        `gh pr create \
        --title "fix(${issue.key}): ${issue.summary}" \
        --body "## Auto-fix por BE Fixer Agent\n\n**Issue Jira:** ${issue.key}\n\n**Cambios:**\n${fix.explanation}${migrationNote}\n\n**Módulo:** ${issue.component}\n\n⚠️ *Revisar antes de mergear*" \
        --label "auto-fix,backend" \
        --base main`,
        { stdio: 'inherit' }
      );
    } catch {
      console.warn('[BE FIXER] gh CLI not available');
    }

    // Actualizar Jira
    await transitionIssue(issue.key, 'In Review');
    await addComment(
      issue.key,
      `🤖 *BE Fixer Agent* aplicó un fix automático.\n\n*Cambios:* ${fix.explanation}\n\n*Rama:* ${branch}${fix.migration ? '\n\n⚠️ Incluye migración de base de datos.' : ''}\n\nPR abierto para revisión.`
    );
  } catch (err) {
    try {
      execSync('git checkout main', { stdio: 'pipe' });
    } catch {}
    throw err;
  }
}

// ─── Main ─────────────────────────────────────
async function main() {
  console.log('🔧 [BE FIXER] Checking for backend issues...\n');

  const issuesFile = 'reports/be-issues.json';
  if (!fs.existsSync(issuesFile)) {
    console.log('[BE FIXER] No backend issues file found.');
    return;
  }

  const issues: JiraIssue[] = JSON.parse(fs.readFileSync(issuesFile, 'utf-8'));
  const beIssues = issues.filter(
    (i) => i.layer === 'backend' && ['Open', 'In Progress'].includes(i.status) && !i.fixBranch
  );

  console.log(`[BE FIXER] ${beIssues.length} backend issues to fix`);

  let fixed = 0;
  for (const issue of beIssues.slice(0, 3)) {
    console.log(`\n[BE FIXER] Processing ${issue.key}: ${issue.summary}`);

    const fileContent = fs.existsSync(issue.affectedFile)
      ? fs.readFileSync(issue.affectedFile, 'utf-8')
      : '';

    if (!fileContent) {
      console.warn(`[BE FIXER] File not found: ${issue.affectedFile}`);
      continue;
    }

    try {
      const fix = await generateFix(issue, fileContent);
      await applyFix(issue, fix);
      fixed++;
      console.log(`[BE FIXER] ✅ Fixed ${issue.key}`);
    } catch (err) {
      console.error(`[BE FIXER] ❌ Failed ${issue.key}:`, err);
      await addComment(
        issue.key,
        `🤖 *BE Fixer Agent* falló al aplicar fix automático.\nError: ${err}\nRequiere intervención manual.`
      ).catch(() => {});
    }
  }

  if (fixed > 0) {
    await notifySlack(
      `BE Fixer aplicó *${fixed} fixes automáticos* de backend. PRs listos para revisión.`,
      'success'
    );
  }

  publish('be-fixer', 'validator', 'FIXES_APPLIED', { layer: 'backend', count: fixed });
  console.log(`\n✅ [BE FIXER] Done. ${fixed} fixes applied.`);
}

main().catch((err) => {
  console.error('[BE FIXER] Fatal:', err);
  process.exit(1);
});

// ─────────────────────────────────────────────
//  emprendy.ai — Agent 4: FE FIXER
//  Auto-corrección local de bugs de Frontend
// ─────────────────────────────────────────────
import * as fs from 'fs';
import * as path from 'path';
import { execSync } from 'child_process';
import Anthropic from '@anthropic-ai/sdk';
import { Task } from '../shared/types';
import { getPendingTasks, updateTask, printTaskSummary } from '../shared/task-queue';
import { notifySlack } from '../shared/bus';
import { transitionIssue, addComment } from '../shared/jira-mcp';

const client = new Anthropic();
const MAX_FIXES = parseInt(process.env.MAX_FIXES ?? '5', 10);

function readFile(filePath: string): string {
  try {
    return fs.existsSync(filePath) ? fs.readFileSync(filePath, 'utf-8') : '';
  } catch {
    return '';
  }
}

function detectProjectContext(): string {
  const pkg = fs.existsSync('package.json')
    ? JSON.parse(fs.readFileSync('package.json', 'utf-8'))
    : {};
  const deps = { ...pkg.dependencies, ...pkg.devDependencies };
  const stack: string[] = [];
  if (deps['next']) stack.push('Next.js');
  if (deps['react']) stack.push('React');
  if (deps['typescript']) stack.push('TypeScript');
  if (deps['tailwindcss']) stack.push('Tailwind CSS');
  if (deps['@tanstack/react-query']) stack.push('TanStack Query');
  if (deps['zod']) stack.push('Zod');
  return stack.join(', ') || 'React/TypeScript';
}

async function generateFix(
  task: Task,
  fileContent: string
): Promise<{ fixedCode: string; explanation: string }> {
  const context = detectProjectContext();

  const response = await client.messages.create({
    model: 'claude-opus-4-5',
    max_tokens: 6000,
    system: `Eres un senior frontend developer especializado en ${context}.
Trabajas en emprendy.ai, una plataforma para crear tiendas, restaurantes y servicios.

Al corregir un bug de frontend:
1. Respeta estrictamente el estilo de código existente
2. No introduzcas nuevas dependencias
3. El fix debe ser mínimo y quirúrgico — cambia solo lo necesario
4. Asegúrate de que el TypeScript compile sin errores
5. Si hay implicaciones de accesibilidad, corrígelas también

Responde ÚNICAMENTE con JSON en este formato exacto:
{
  "fixedCode": "// código completo del archivo corregido",
  "explanation": "// qué cambió y por qué (max 3 oraciones)"
}`,
    messages: [
      {
        role: 'user',
        content: `Corrige este hallazgo de código:

Tipo:      ${task.finding.type}
Severidad: ${task.finding.severity}
Archivo:   ${task.finding.file}:${task.finding.line}
Error:     ${task.finding.description}
Regla:     ${task.finding.rule ?? 'N/A'}
${task.finding.fix ? `Fix sugerido por linter: ${task.finding.fix}` : ''}

Código actual del archivo:
\`\`\`typescript
${fileContent.slice(0, 8000)}
\`\`\``,
      },
    ],
  });

  const text = response.content
    .filter((b) => b.type === 'text')
    .map((b) => (b as any).text)
    .join('');

  const clean = text.replace(/```json|```/g, '').trim();
  return JSON.parse(clean);
}

async function applyFix(
  task: Task,
  fix: { fixedCode: string; explanation: string }
): Promise<void> {
  const filePath = task.finding.file;

  // Write the fixed code
  const dir = path.dirname(filePath);
  if (dir && dir !== '.') fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, fix.fixedCode);

  // Run eslint --fix on the file
  try {
    execSync(`npx eslint ${filePath} --fix --quiet`, { stdio: 'pipe' });
  } catch {}

  console.log(`  ✏️  Applied fix to ${filePath}`);
  console.log(`  💬 ${fix.explanation}`);
}

async function main() {
  console.log('⚛️  [FE FIXER] Looking for pending frontend tasks...\n');

  const tasks = getPendingTasks('frontend');
  if (tasks.length === 0) {
    console.log('[FE FIXER] No pending frontend tasks. Run inspector + task-manager first.');
    printTaskSummary();
    return;
  }

  console.log(`[FE FIXER] ${tasks.length} pending tasks (processing up to ${MAX_FIXES})\n`);

  let fixed = 0;
  let failed = 0;

  for (const task of tasks.slice(0, MAX_FIXES)) {
    console.log(`\n[FE FIXER] ${task.id} [${task.finding.severity}] ${task.finding.file}:${task.finding.line}`);
    console.log(`  📌 ${task.finding.description.slice(0, 100)}`);

    const fileContent = readFile(task.finding.file);
    if (!fileContent) {
      console.warn(`  ⚠️  File not found — skipping`);
      task.status = 'skipped';
      task.error = 'File not found';
      updateTask(task);
      continue;
    }

    // Mark in-progress
    task.status = 'in-progress';
    task.attempts++;
    updateTask(task);

    try {
      const fix = await generateFix(task, fileContent);
      await applyFix(task, fix);

      task.status = 'done';
      task.fix = { explanation: fix.explanation, appliedTo: task.finding.file };
      updateTask(task);

      // Update Jira if configured (best-effort)
      await transitionIssue(task.id, 'In Review').catch(() => {});
      await addComment(task.id, `🤖 FE Fixer applied local fix: ${fix.explanation}`).catch(() => {});

      fixed++;
      console.log(`  ✅ Done`);
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : String(err);
      task.status = 'failed';
      task.error = msg;
      updateTask(task);
      failed++;
      console.error(`  ❌ Failed: ${msg.slice(0, 120)}`);
    }
  }

  printTaskSummary();

  if (fixed > 0) {
    await notifySlack(
      `⚛️ *FE Fixer* — ${fixed} frontend fix(es) applied locally.\n${failed > 0 ? `⚠️ ${failed} failed — check tasks/ for details.` : ''}`,
      fixed > 0 ? 'success' : 'high'
    );
  }

  console.log(`\n✅ [FE FIXER] Done. ${fixed} fixed, ${failed} failed.`);
}

main().catch((err) => {
  console.error('[FE FIXER] Fatal:', err);
  process.exit(1);
});

// ─────────────────────────────────────────────
//  emprendy.ai — Agent 1: INSPECTOR
//  Análisis estático del repositorio en cada PR
// ─────────────────────────────────────────────
import { execSync } from 'child_process';
import * as fs from 'fs';
import * as path from 'path';
import Anthropic from '@anthropic-ai/sdk';
import { Finding, Severity, Layer, Module } from '../shared/types';
import { publish, notifySlack } from '../shared/bus';
import { createIssueFromFinding, findDuplicateIssue } from '../shared/jira-mcp';

const client = new Anthropic();
const DRY_RUN = process.argv.includes('--dry-run');
const REPORT_DIR = path.resolve(process.cwd(), 'reports');

// ─── 1. Recopilar hallazgos de herramientas ───
function runESLint(): Finding[] {
  try {
    execSync('npx eslint . --format json -o reports/eslint.json --max-warnings 0', {
      stdio: 'pipe',
    });
  } catch (_) {
    /* command can exit with code 1 when warnings are present */
  }

  if (!fs.existsSync('reports/eslint.json')) return [];
  const raw: any[] = JSON.parse(fs.readFileSync('reports/eslint.json', 'utf-8'));
  const findings: Finding[] = [];

  for (const fileResult of raw) {
    for (const msg of fileResult.messages) {
      findings.push({
        id: `eslint-${fileResult.filePath}-${msg.line}`,
        type: 'lint',
        severity: msg.severity === 2 ? 'high' : 'medium',
        layer: detectLayer(fileResult.filePath),
        module: detectModule(fileResult.filePath),
        file: fileResult.filePath,
        line: msg.line ?? 0,
        description: msg.message,
        codeSnippet: msg.source ?? '',
        rule: msg.ruleId ?? undefined,
        fix: msg.fix?.text ?? undefined,
        timestamp: new Date().toISOString(),
      });
    }
  }
  return findings;
}

function runTypeCheck(): Finding[] {
  try {
    execSync('npx tsc --noEmit --pretty false 2> reports/tsc.txt', { stdio: 'pipe' });
    return [];
  } catch (_) {}

  if (!fs.existsSync('reports/tsc.txt')) return [];
  const lines = fs.readFileSync('reports/tsc.txt', 'utf-8').split('\n');
  const findings: Finding[] = [];
  const regex = /^(.+)\((\d+),\d+\): error (TS\d+): (.+)$/;

  for (const line of lines) {
    const match = line.match(regex);
    if (!match) continue;
    const [, file, lineNum, code, msg] = match;
    findings.push({
      id: `tsc-${file}-${lineNum}`,
      type: 'type-error',
      severity: 'high',
      layer: detectLayer(file),
      module: detectModule(file),
      file,
      line: parseInt(lineNum),
      description: `${code}: ${msg}`,
      codeSnippet: '',
      timestamp: new Date().toISOString(),
    });
  }
  return findings;
}

function runDependencyAudit(): Finding[] {
  try {
    execSync('npm audit --json > reports/audit.json 2>/dev/null', { stdio: 'pipe' });
  } catch (_) {}

  if (!fs.existsSync('reports/audit.json')) return [];
  const raw = JSON.parse(fs.readFileSync('reports/audit.json', 'utf-8'));
  const findings: Finding[] = [];

  for (const [name, vuln] of Object.entries<any>(raw.vulnerabilities ?? {})) {
    if (!['critical', 'high'].includes(vuln.severity)) continue;
    findings.push({
      id: `audit-${name}`,
      type: 'vulnerability',
      severity: vuln.severity as Severity,
      layer: 'infra',
      module: 'api',
      file: 'package.json',
      line: 0,
      description: `Vulnerabilidad en dependencia "${name}": ${vuln.via?.[0]?.title ?? vuln.severity}`,
      codeSnippet: `"${name}": "${vuln.range}"`,
      timestamp: new Date().toISOString(),
    });
  }
  return findings;
}

// ─── 2. Enriquecer con Claude ─────────────────
async function enrichWithClaude(findings: Finding[]): Promise<Finding[]> {
  if (findings.length === 0) return [];

  const response = await client.messages.create({
    model: 'claude-opus-4-5',
    max_tokens: 4000,
    system: `Eres un senior developer revisando hallazgos de análisis estático para emprendy.ai.
Para cada hallazgo:
1. Ajusta la severidad si crees que está mal asignada
2. Añade contexto de impacto en el negocio
3. Sugiere el approach de fix más adecuado
4. Detecta si es un falso positivo (marca como severity: "low" y description: "FALSE_POSITIVE: ...")
Responde en JSON con el array de findings enriquecidos, misma estructura.`,

    messages: [
      {
        role: 'user',
        content: JSON.stringify(findings.slice(0, 20)), // max 20 para no exceder tokens
      },
    ],
  });

  try {
    const text = response.content
      .filter((b) => b.type === 'text')
      .map((b) => (b as any).text)
      .join('');
    const clean = text.replace(/```json|```/g, '').trim();
    return JSON.parse(clean);
  } catch {
    console.warn('[INSPECTOR] Claude enrichment parse failed, using raw findings');
    return findings;
  }
}

// ─── 3. Helpers ───────────────────────────────
function detectLayer(filePath: string): Layer {
  if (
    filePath.includes('/components/') ||
    filePath.includes('/pages/') ||
    filePath.includes('/app/') ||
    filePath.endsWith('.tsx') ||
    filePath.endsWith('.jsx')
  )
    return 'frontend';
  if (
    filePath.includes('/api/') ||
    filePath.includes('/routes/') ||
    filePath.includes('/controllers/') ||
    filePath.includes('/services/')
  )
    return 'backend';
  if (filePath.includes('docker') || filePath.includes('nginx') || filePath.includes('.yml'))
    return 'infra';
  return 'unknown';
}

function detectModule(filePath: string): Module {
  if (filePath.includes('store') || filePath.includes('tienda')) return 'store';
  if (filePath.includes('restaurant') || filePath.includes('menu')) return 'restaurant';
  if (filePath.includes('service') || filePath.includes('servicio')) return 'service';
  if (filePath.includes('dashboard') || filePath.includes('admin')) return 'dashboard';
  if (filePath.includes('auth') || filePath.includes('login')) return 'auth';
  if (filePath.includes('api') || filePath.includes('routes')) return 'api';
  if (filePath.includes('db') || filePath.includes('prisma') || filePath.includes('migration'))
    return 'db';
  return 'api';
}

// ─── 4. Slack summary ────────────────────────
async function sendSlackSummary(opts: {
  findings: Finding[];
  critical: Finding[];
  high: Finding[];
  medium: Finding[];
  low: Finding[];
  byModule: Record<string, number>;
  created: number;
  dryRun: boolean;
}): Promise<void> {
  const { findings, critical, high, medium, low, byModule, created, dryRun } = opts;

  const icon = critical.length > 0 ? '🚨' : high.length > 0 ? '⚠️' : '✅';
  const moduleLines = Object.entries(byModule)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(([mod, count]) => `  • ${mod}: ${count}`)
    .join('\n');

  const lines = [
    `${icon} *emprendy.ai — Inspector Report*${dryRun ? ' _(dry run)_' : ''}`,
    '',
    `*Findings: ${findings.length} total*`,
    `🔴 Critical: ${critical.length}   🟠 High: ${high.length}   🟡 Medium: ${medium.length}   ⚪ Low: ${low.length}`,
    '',
    `*Top modules affected:*\n${moduleLines || '  —'}`,
    '',
    created > 0
      ? `📋 ${created} Jira issue(s) created automatically.`
      : critical.length + high.length > 0
      ? `📋 Jira skipped (not configured).`
      : `✅ No critical/high issues — no Jira tickets needed.`,
  ];

  await notifySlack(lines.join('\n'), critical.length > 0 ? 'critical' : high.length > 0 ? 'high' : 'success');
}

// ─── 5. Main ─────────────────────────────────
async function main() {
  console.log('🔍 [INSPECTOR] Starting static analysis...\n');
  fs.mkdirSync(REPORT_DIR, { recursive: true });

  // Recopilar hallazgos
  const eslintFindings = runESLint();
  const tscFindings = runTypeCheck();
  const auditFindings = runDependencyAudit();
  const allRaw = [...eslintFindings, ...tscFindings, ...auditFindings];

  console.log(
    `Found: ${eslintFindings.length} lint | ${tscFindings.length} type | ${auditFindings.length} vuln`
  );

  if (allRaw.length === 0) {
    console.log('✅ No findings. Repository is clean.');
    return;
  }

  // Enriquecer con Claude
  const findings = await enrichWithClaude(allRaw);
  const critical = findings.filter((f) => f.severity === 'critical');
  const high = findings.filter((f) => f.severity === 'high');

  const medium = findings.filter((f) => f.severity === 'medium');
  const low = findings.filter((f) => f.severity === 'low');

  // Guardar reporte
  fs.writeFileSync('reports/inspector-report.json', JSON.stringify(findings, null, 2));
  console.log(
    `\n📊 Report: ${findings.length} findings — 🔴 ${critical.length} critical | 🟠 ${high.length} high | 🟡 ${medium.length} medium | ⚪ ${low.length} low`
  );

  // Resumen por módulo
  const byModule: Record<string, number> = {};
  for (const f of findings) {
    byModule[f.module] = (byModule[f.module] ?? 0) + 1;
  }
  const moduleLines = Object.entries(byModule)
    .sort((a, b) => b[1] - a[1])
    .map(([mod, count]) => `  • ${mod}: ${count}`)
    .join('\n');

  console.log('\nFindings by module:\n' + moduleLines);

  if (DRY_RUN) {
    console.log('\n[DRY RUN] Skipping Jira issue creation.');
    console.log(JSON.stringify(findings.slice(0, 3), null, 2));
    await sendSlackSummary({ findings, critical, high, medium, low, byModule, created: 0, dryRun: true });
    return;
  }

  // Crear issues en Jira (solo critical y high, con deduplicación)
  let created = 0;
  for (const finding of [...critical, ...high]) {
    if (finding.description.startsWith('FALSE_POSITIVE')) continue;

    const existing = await findDuplicateIssue(finding.description, finding.file);
    if (existing) {
      console.log(`[INSPECTOR] Duplicate found: ${existing} — skipping`);
      continue;
    }

    const key = await createIssueFromFinding(finding);
    console.log(`[INSPECTOR] Created Jira issue: ${key} for ${finding.file}:${finding.line}`);
    created++;
  }

  // Slack: resumen completo siempre
  await sendSlackSummary({ findings, critical, high, medium, low, byModule, created, dryRun: false });

  // Publicar al bus para que QA Runner pueda reaccionar
  publish('inspector', 'qa-runner', 'INSPECTION_COMPLETE', {
    total: findings.length,
    critical: critical.length,
    high: high.length,
    report: 'reports/inspector-report.json',
  });

  // Auto-generate tasks from findings
  try {
    execSync('npx ts-node --project tsconfig.agents.json agents/task-manager/index.ts', { stdio: 'inherit' });
  } catch {}

  console.log('\n✅ [INSPECTOR] Done.');
}

main().catch((err) => {
  console.error('[INSPECTOR] Fatal error:', err);
  process.exit(1);
});

// ─────────────────────────────────────────────
//  emprendy.ai — Agent 3: JIRA SCRIBE
//  Consume reportes y crea issues en Jira
// ─────────────────────────────────────────────
import * as fs from 'fs';
import { Finding, TestResult } from '../shared/types';
import { consume, publish } from '../shared/bus';
import {
  createIssueFromFinding,
  createIssueFromTestFailure,
  findDuplicateIssue,
} from '../shared/jira-mcp';

async function main() {
  console.log('📋 [JIRA SCRIBE] Processing reports...\n');

  let totalCreated = 0;

  // ── Procesar hallazgos del Inspector ──────
  if (fs.existsSync('reports/inspector-report.json')) {
    const findings: Finding[] = JSON.parse(
      fs.readFileSync('reports/inspector-report.json', 'utf-8')
    );
    const actionable = findings.filter(
      (f) =>
        ['critical', 'high'].includes(f.severity) && !f.description.startsWith('FALSE_POSITIVE')
    );

    console.log(`[JIRA SCRIBE] Inspector findings: ${actionable.length} actionable`);

    for (const f of actionable) {
      const dup = await findDuplicateIssue(f.description, f.file);
      if (dup) {
        console.log(`  ↳ Dup ${dup} — skip`);
        continue;
      }

      const key = await createIssueFromFinding(f);
      console.log(`  ↳ Created ${key} [${f.severity}] ${f.file}:${f.line}`);
      totalCreated++;
    }
  }

  // ── Procesar fallas del QA Runner ─────────
  if (fs.existsSync('reports/qa-runner-report.json')) {
    const results: TestResult[] = JSON.parse(
      fs.readFileSync('reports/qa-runner-report.json', 'utf-8')
    );
    const failed = results.filter((r) => r.status === 'failed');

    console.log(`\n[JIRA SCRIBE] QA failures: ${failed.length}`);

    for (const r of failed) {
      const dup = await findDuplicateIssue(r.error ?? r.scenario, r.module);
      if (dup) {
        console.log(`  ↳ Dup ${dup} — skip`);
        continue;
      }

      const key = await createIssueFromTestFailure(r);
      console.log(`  ↳ Created ${key} [${r.module}] "${r.scenario}"`);
      totalCreated++;
    }
  }

  console.log(`\n✅ [JIRA SCRIBE] Done. ${totalCreated} issues created.`);

  // Publicar al bus
  publish('jira-scribe', 'fe-fixer', 'ISSUES_READY', { count: totalCreated });
  publish('jira-scribe', 'be-fixer', 'ISSUES_READY', { count: totalCreated });
}

main().catch((err) => {
  console.error('[JIRA SCRIBE] Error:', err);
  process.exit(1);
});

// ─────────────────────────────────────────────
//  emprendy.ai — Agent 2: QA RUNNER
//  Regresión E2E completa con Playwright
// ─────────────────────────────────────────────
import { execSync } from 'child_process';
import * as fs from 'fs';
import * as path from 'path';
import Anthropic from '@anthropic-ai/sdk';
import { TestResult } from '../shared/types';
import { publish, consume, notifySlack } from '../shared/bus';
import { createIssueFromTestFailure, findDuplicateIssue } from '../shared/jira-mcp';

const client = new Anthropic();
const REPORT_DIR = path.resolve(process.cwd(), 'reports');
const BASE_URL = process.env.BASE_URL ?? 'http://localhost:3000';

// ─── 1. Ejecutar tests Playwright ────────────
function runPlaywright(): TestResult[] {
  try {
    execSync(`npx playwright test tests/e2e/ --reporter=json --output=reports/playwright.json`, {
      stdio: 'inherit',
    });
  } catch (_) {
    /* playwright exits 1 on test failures */
  }

  if (!fs.existsSync('reports/playwright.json')) return [];
  const raw = JSON.parse(fs.readFileSync('reports/playwright.json', 'utf-8'));

  const results: TestResult[] = [];
  for (const suite of raw.suites ?? []) {
    for (const spec of suite.specs ?? []) {
      for (const test of spec.tests ?? []) {
        const failed = test.results?.some((r: any) => r.status === 'failed');
        results.push({
          id: spec.id,
          module: detectModule(suite.file),
          scenario: spec.title,
          status: failed ? 'failed' : 'passed',
          duration: test.results?.[0]?.duration ?? 0,
          error: test.results?.[0]?.error?.message,
          screenshot: test.results?.[0]?.attachments?.find(
            (a: any) => a.contentType === 'image/png'
          )?.path,
          steps: (test.results?.[0]?.steps ?? []).map((s: any) => ({
            action: s.title,
            status: s.error ? 'failed' : 'passed',
            error: s.error?.message,
          })),
          timestamp: new Date().toISOString(),
        });
      }
    }
  }
  return results;
}

// ─── 2. Analizar fallas con Claude ───────────
async function analyzeFailures(failed: TestResult[]): Promise<TestResult[]> {
  if (failed.length === 0) return [];

  const response = await client.messages.create({
    model: 'claude-opus-4-5',
    max_tokens: 4000,
    system: `Eres un QA engineer senior analizando fallas de tests E2E en emprendy.ai.
Para cada test fallido:
1. Clasifica si es un bug real, dato de prueba incorrecto o problema de ambiente
2. Estima la severidad: critical (bloquea flujo de negocio), high, medium, low
3. Detecta si es flaky test (por timing/red)
4. Sugiere el área de código más probable del bug (frontend/backend)
Responde en JSON: array con los mismos TestResult enriquecidos con campos extra:
- analysisType: "real-bug" | "test-data" | "environment" | "flaky"
- estimatedSeverity: Severity
- suggestedLayer: Layer
- rootCauseHint: string`,

    messages: [
      {
        role: 'user',
        content: JSON.stringify(failed.slice(0, 15)),
      },
    ],
  });

  try {
    const text = response.content
      .filter((b) => b.type === 'text')
      .map((b) => (b as any).text)
      .join('');
    const clean = text.replace(/```json|```/g, '').trim();
    return JSON.parse(clean);
  } catch {
    return failed;
  }
}

// ─── 3. Helpers ──────────────────────────────
function detectModule(filePath: string): any {
  if (filePath.includes('store')) return 'store';
  if (filePath.includes('restaurant')) return 'restaurant';
  if (filePath.includes('service')) return 'service';
  if (filePath.includes('dashboard')) return 'dashboard';
  if (filePath.includes('auth')) return 'auth';
  return 'api';
}

// ─── 4. Main ─────────────────────────────────
async function main() {
  console.log('🧪 [QA RUNNER] Starting full regression suite...\n');
  fs.mkdirSync(REPORT_DIR, { recursive: true });

  // Verificar si Inspector ya corrió y hay mensajes pendientes
  const inspectorMsgs = consume('qa-runner', 'INSPECTION_COMPLETE');
  if (inspectorMsgs.length > 0) {
    console.log(`[QA RUNNER] Triggered by Inspector: ${JSON.stringify(inspectorMsgs[0].payload)}`);
  }

  // Correr la suite completa
  const results = runPlaywright();
  const failed = results.filter((r) => r.status === 'failed');
  const passed = results.filter((r) => r.status === 'passed');

  console.log(`\n📊 Results: ${passed.length} passed | ${failed.length} failed`);

  // Guardar reporte
  fs.writeFileSync('reports/qa-runner-report.json', JSON.stringify(results, null, 2));

  if (failed.length === 0) {
    console.log('✅ All tests passed! No Jira issues needed.');
    await notifySlack(
      `Regresión completa: *${passed.length} tests pasando* ✅ — 0 fallas`,
      'success'
    );
    return;
  }

  // Analizar fallas con Claude
  const analyzed = await analyzeFailures(failed);
  const realBugs = analyzed.filter((r: any) => r.analysisType === 'real-bug' || !r.analysisType);

  console.log(
    `\n🐛 Real bugs: ${realBugs.length} | Flaky/env: ${analyzed.length - realBugs.length}`
  );

  // Crear issues en Jira para bugs reales
  let created = 0;
  for (const result of realBugs) {
    const existing = await findDuplicateIssue(result.error ?? result.scenario, result.module);
    if (existing) {
      console.log(`[QA RUNNER] Duplicate: ${existing} — skipping`);
      continue;
    }

    const key = await createIssueFromTestFailure(result);
    console.log(`[QA RUNNER] Created Jira issue: ${key} for "${result.scenario}"`);
    created++;
  }

  // Notificar
  await notifySlack(
    `Regresión completa: *${failed.length} tests fallando* — ${created} issues creados en Jira.`,
    realBugs.some((r: any) => r.estimatedSeverity === 'critical') ? 'critical' : 'high'
  );

  // Publicar al bus
  publish('qa-runner', 'jira-scribe', 'REGRESSION_COMPLETE', {
    total: results.length,
    failed: failed.length,
    created,
    report: 'reports/qa-runner-report.json',
  });

  console.log('\n✅ [QA RUNNER] Done.');
}

main().catch((err) => {
  console.error('[QA RUNNER] Fatal error:', err);
  process.exit(1);
});

