// ─────────────────────────────────────────────
//  emprendy.ai — Agent Message Bus
// ─────────────────────────────────────────────
import { AgentMessage } from './types';
import * as fs from 'fs';
import * as path from 'path';

const BUS_FILE = path.resolve(process.cwd(), '.agent-bus.json');

function read(): AgentMessage[] {
  if (!fs.existsSync(BUS_FILE)) return [];
  return JSON.parse(fs.readFileSync(BUS_FILE, 'utf-8'));
}

function write(messages: AgentMessage[]): void {
  fs.writeFileSync(BUS_FILE, JSON.stringify(messages, null, 2));
}

/** Publish an event to the bus */
export function publish(from: string, to: string, event: string, payload: unknown): void {
  const messages = read();
  messages.push({ from, to, event, payload, timestamp: new Date().toISOString() });
  write(messages);
  console.log(`[BUS] ${from} → ${to} :: ${event}`);
}

/** Consume messages for a specific agent & event (removes them from bus) */
export function consume(to: string, event?: string): AgentMessage[] {
  const all = read();
  const matched = all.filter((m) => m.to === to && (!event || m.event === event));
  const remaining = all.filter((m) => !(m.to === to && (!event || m.event === event)));
  write(remaining);
  return matched;
}

/** Peek without consuming */
export function peek(to: string, event?: string): AgentMessage[] {
  return read().filter((m) => m.to === to && (!event || m.event === event));
}

/** Send Slack notification */
export async function notifySlack(message: string, severity = 'info'): Promise<void> {
  const webhookUrl = process.env.SLACK_WEBHOOK_URL;
  if (!webhookUrl) return;

  const emoji = { critical: '🚨', high: '⚠️', info: 'ℹ️', success: '✅' }[severity] ?? 'ℹ️';

  await fetch(webhookUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ text: `${emoji} *emprendy.ai agents* — ${message}` }),
  });
}

// ─────────────────────────────────────────────
//  emprendy.ai — Jira REST API Client
//  Uses Jira REST API v3 with API token auth
// ─────────────────────────────────────────────
import { Finding, TestResult } from './types';

const JIRA_BASE_URL = (process.env.JIRA_BASE_URL ?? '').replace(/\/$/, '');
const JIRA_USER_EMAIL = process.env.JIRA_USER_EMAIL ?? '';
const JIRA_API_TOKEN = process.env.JIRA_API_TOKEN ?? '';
const JIRA_PROJECT_KEY = process.env.JIRA_PROJECT_KEY ?? 'EMPR';

const JIRA_ENABLED = JIRA_BASE_URL.length > 0 && JIRA_API_TOKEN.length > 0;

const authHeader =
  'Basic ' + Buffer.from(`${JIRA_USER_EMAIL}:${JIRA_API_TOKEN}`).toString('base64');

// ── Low-level fetch wrapper ────────────────────
async function jiraRequest(
  method: string,
  path: string,
  body?: unknown
): Promise<unknown> {
  const res = await fetch(`${JIRA_BASE_URL}/rest/api/3${path}`, {
    method,
    headers: {
      Authorization: authHeader,
      'Content-Type': 'application/json',
      Accept: 'application/json',
    },
    ...(body ? { body: JSON.stringify(body) } : {}),
  });

  if (!res.ok) {
    const text = await res.text();
    throw new Error(`Jira ${method} ${path} → ${res.status}: ${text}`);
  }
  return res.json();
}

// ── Graceful wrapper ──────────────────────────
async function callJira<T>(fn: () => Promise<T>, fallback: T): Promise<T> {
  if (!JIRA_ENABLED) {
    console.warn('[JIRA] JIRA_BASE_URL or JIRA_API_TOKEN not set — skipping');
    return fallback;
  }
  try {
    return await fn();
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : String(err);
    console.warn(`[JIRA] Unavailable — skipping (${msg})`);
    return fallback;
  }
}

// ── Map severity to Jira priority ─────────────
function toPriority(severity: string): string {
  const map: Record<string, string> = {
    critical: 'Highest',
    high: 'High',
    medium: 'Medium',
    low: 'Low',
  };
  return map[severity] ?? 'Medium';
}

// ── Create issue from a code Finding ──────────
export async function createIssueFromFinding(finding: Finding): Promise<string> {
  return callJira(async () => {
    const payload = {
      fields: {
        project: { key: JIRA_PROJECT_KEY },
        summary: `[${finding.severity.toUpperCase()}] ${finding.type}: ${finding.description.slice(0, 120)}`,
        description: {
          type: 'doc',
          version: 1,
          content: [
            {
              type: 'paragraph',
              content: [
                {
                  type: 'text',
                  text: `File: ${finding.file}:${finding.line}\nRule: ${finding.rule ?? 'N/A'}\nLayer: ${finding.layer}\nModule: ${finding.module}\n\n${finding.description}`,
                },
              ],
            },
            ...(finding.codeSnippet
              ? [
                  {
                    type: 'codeBlock',
                    content: [{ type: 'text', text: finding.codeSnippet }],
                  },
                ]
              : []),
          ],
        },
        issuetype: { name: 'Bug' },
        priority: { name: toPriority(finding.severity) },
        labels: [finding.layer, `severity:${finding.severity}`, 'auto-detected'],
      },
    };

    const data = (await jiraRequest('POST', '/issue', payload)) as { key: string };
    console.log(`[JIRA] Created ${data.key}`);
    return data.key;
  }, 'SKIPPED');
}

// ── Create issue from a failed test ───────────
export async function createIssueFromTestFailure(result: TestResult): Promise<string> {
  return callJira(async () => {
    const steps = result.steps
      .map(
        (s, i) =>
          `${i + 1}. [${s.status.toUpperCase()}] ${s.action}${s.error ? ` → ${s.error}` : ''}`
      )
      .join('\n');

    const payload = {
      fields: {
        project: { key: JIRA_PROJECT_KEY },
        summary: `[E2E FAILURE] ${result.module}: ${result.scenario.slice(0, 100)}`,
        description: {
          type: 'doc',
          version: 1,
          content: [
            {
              type: 'paragraph',
              content: [
                {
                  type: 'text',
                  text: `Module: ${result.module}\nScenario: ${result.scenario}\nError: ${result.error ?? 'N/A'}\nDuration: ${result.duration}ms\nScreenshot: ${result.screenshot ?? 'N/A'}\n\nSteps:\n${steps}`,
                },
              ],
            },
          ],
        },
        issuetype: { name: 'Bug' },
        priority: { name: 'High' },
        labels: ['regression', 'e2e', 'auto-detected', result.module],
      },
    };

    const data = (await jiraRequest('POST', '/issue', payload)) as { key: string };
    console.log(`[JIRA] Created ${data.key}`);
    return data.key;
  }, 'SKIPPED');
}

// ── Transition issue status ────────────────────
export async function transitionIssue(issueKey: string, targetStatus: string): Promise<void> {
  await callJira(async () => {
    const data = (await jiraRequest('GET', `/issue/${issueKey}/transitions`)) as {
      transitions: { id: string; name: string }[];
    };
    const transition = data.transitions.find(
      (t) => t.name.toLowerCase() === targetStatus.toLowerCase()
    );
    if (!transition) {
      console.warn(`[JIRA] Transition "${targetStatus}" not found for ${issueKey}`);
      return;
    }
    await jiraRequest('POST', `/issue/${issueKey}/transitions`, {
      transition: { id: transition.id },
    });
    console.log(`[JIRA] ${issueKey} → ${targetStatus}`);
  }, undefined);
}

// ── Add comment to issue ──────────────────────
export async function addComment(issueKey: string, comment: string): Promise<void> {
  await callJira(async () => {
    await jiraRequest('POST', `/issue/${issueKey}/comment`, {
      body: {
        type: 'doc',
        version: 1,
        content: [
          { type: 'paragraph', content: [{ type: 'text', text: comment }] },
        ],
      },
    });
  }, undefined);
}

// ── Check if similar issue exists (dedup) ─────
export async function findDuplicateIssue(
  description: string,
  file: string
): Promise<string | null> {
  return callJira(async () => {
    const keyword = `${description.slice(0, 40)} ${file}`.replace(/['"\\]/g, ' ').slice(0, 100);
    const jql = `project = ${JIRA_PROJECT_KEY} AND summary ~ "${keyword}" AND statusCategory != Done ORDER BY created DESC`;
    const data = (await jiraRequest(
      'GET',
      `/search?jql=${encodeURIComponent(jql)}&maxResults=1&fields=key,summary`
    )) as { issues: { key: string }[] };
    return data.issues[0]?.key ?? null;
  }, null);
}

// ─────────────────────────────────────────────
//  emprendy.ai — Task Queue Utilities
// ─────────────────────────────────────────────
import * as fs from 'fs';
import * as path from 'path';
import { Task } from './types';

const TASKS_DIR = path.resolve(process.cwd(), 'tasks');

export function getAllTasks(): Task[] {
  if (!fs.existsSync(TASKS_DIR)) return [];
  return fs
    .readdirSync(TASKS_DIR)
    .filter((f) => f.endsWith('.json'))
    .map((f) => {
      try {
        return JSON.parse(fs.readFileSync(path.join(TASKS_DIR, f), 'utf-8')) as Task;
      } catch {
        return null;
      }
    })
    .filter((t): t is Task => t !== null)
    .sort((a, b) => a.id.localeCompare(b.id));
}

export function getPendingTasks(layer?: 'frontend' | 'backend'): Task[] {
  return getAllTasks().filter(
    (t) => t.status === 'pending' && (!layer || t.finding.layer === layer)
  );
}

export function updateTask(task: Task): void {
  const filePath = path.join(TASKS_DIR, `${task.id}.json`);
  task.updatedAt = new Date().toISOString();
  fs.writeFileSync(filePath, JSON.stringify(task, null, 2));
}

export function printTaskSummary(): void {
  const tasks = getAllTasks();
  const byStatus = tasks.reduce<Record<string, number>>((acc, t) => {
    acc[t.status] = (acc[t.status] ?? 0) + 1;
    return acc;
  }, {});
  console.log('\n📋 Task Queue Summary:');
  console.log(`  pending:     ${byStatus['pending'] ?? 0}`);
  console.log(`  in-progress: ${byStatus['in-progress'] ?? 0}`);
  console.log(`  done:        ${byStatus['done'] ?? 0}`);
  console.log(`  failed:      ${byStatus['failed'] ?? 0}`);
  console.log(`  skipped:     ${byStatus['skipped'] ?? 0}`);
  console.log(`  TOTAL:       ${tasks.length}`);
}

// ─────────────────────────────────────────────
//  emprendy.ai — Task Manager
//  Converts Inspector findings into local tasks
// ─────────────────────────────────────────────
import * as fs from 'fs';
import * as path from 'path';
import { Finding, Task } from '../shared/types';
import { notifySlack } from '../shared/bus';

const TASKS_DIR = path.resolve(process.cwd(), 'tasks');
const REPORT = path.resolve(process.cwd(), 'reports/inspector-report.json');

function loadExistingTasks(): Map<string, Task> {
  const map = new Map<string, Task>();
  if (!fs.existsSync(TASKS_DIR)) return map;
  for (const file of fs.readdirSync(TASKS_DIR)) {
    if (!file.endsWith('.json')) continue;
    try {
      const task: Task = JSON.parse(fs.readFileSync(path.join(TASKS_DIR, file), 'utf-8'));
      map.set(task.finding.id, task);
    } catch {}
  }
  return map;
}

function taskFilePath(id: string): string {
  return path.join(TASKS_DIR, `${id}.json`);
}

function writeTask(task: Task): void {
  fs.writeFileSync(taskFilePath(task.id), JSON.stringify(task, null, 2));
}

async function main() {
  console.log('📋 [TASK MANAGER] Processing inspector findings...\n');

  if (!fs.existsSync(REPORT)) {
    console.error('[TASK MANAGER] reports/inspector-report.json not found. Run inspector first.');
    process.exit(1);
  }

  fs.mkdirSync(TASKS_DIR, { recursive: true });

  // MAX_TASKS: cap to avoid creating thousands of tasks at once
  const MAX_TASKS = parseInt(process.env.MAX_TASKS ?? '30', 10);

  const findings: Finding[] = JSON.parse(fs.readFileSync(REPORT, 'utf-8'));

  const severityOrder: Record<string, number> = { critical: 0, high: 1, medium: 2, low: 3 };

  const actionable = findings
    .filter(
      (f) =>
        ['critical', 'high', 'medium'].includes(f.severity) &&
        !f.description.startsWith('FALSE_POSITIVE') &&
        f.file &&
        !f.file.endsWith('package.json') && // skip audit-only findings
        f.file.match(/\.(ts|tsx|js|jsx)$/)  // only fixable source files
    )
    .sort((a, b) => (severityOrder[a.severity] ?? 9) - (severityOrder[b.severity] ?? 9))
    .slice(0, MAX_TASKS);

  const existing = loadExistingTasks();
  let created = 0;
  let skipped = 0;

  for (let i = 0; i < actionable.length; i++) {
    const finding = actionable[i];

    // Skip if task already exists and is not failed (avoid re-creating solved tasks)
    const existing_task = existing.get(finding.id);
    if (existing_task && existing_task.status !== 'failed') {
      skipped++;
      continue;
    }

    const id = `TASK-${String(i + 1).padStart(4, '0')}`;
    const task: Task = {
      id,
      status: 'pending',
      finding,
      attempts: 0,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    writeTask(task);
    console.log(`  ✅ ${id} [${finding.severity}] ${finding.layer} — ${path.basename(finding.file)}:${finding.line}`);
    created++;
  }

  const pending = actionable.length - skipped;
  console.log(`\n📊 Tasks: ${created} created | ${skipped} already exist | ${pending} pending`);
  console.log(`📁 Tasks saved to: ${TASKS_DIR}`);

  if (created > 0) {
    await notifySlack(
      `📋 *Task Manager* — ${created} new tasks created from Inspector findings.\nRun \`fe-fixer\` or \`be-fixer\` to apply fixes.`,
      'info'
    );
  }
}

main().catch((err) => {
  console.error('[TASK MANAGER] Fatal:', err);
  process.exit(1);
});

// ─────────────────────────────────────────────
//  emprendy.ai — Agent 6: VALIDATOR
//  Verificación post-fix y cierre de loop
// ─────────────────────────────────────────────
import { execSync } from 'child_process';
import * as fs from 'fs';
import Anthropic from '@anthropic-ai/sdk';
import { JiraIssue } from '../shared/types';
import { consume, notifySlack } from '../shared/bus';
import { transitionIssue, addComment } from '../shared/jira-mcp';

const client = new Anthropic();

// ─── Re-correr los tests del módulo afectado ──
async function reRunTests(issue: JiraIssue): Promise<{ passed: boolean; output: string }> {
  const moduleMap: Record<string, string> = {
    store: 'tests/e2e/store.spec.ts',
    restaurant: 'tests/e2e/restaurant.spec.ts',
    service: 'tests/e2e/service.spec.ts',
    dashboard: 'tests/e2e/dashboard.spec.ts',
    auth: 'tests/e2e/dashboard.spec.ts',
    api: 'tests/e2e/',
    db: 'tests/e2e/',
  };

  const testFile = moduleMap[issue.component] ?? 'tests/e2e/';

  try {
    const output = execSync(`npx playwright test ${testFile} --reporter=line --timeout=30000`, {
      encoding: 'utf-8',
      stdio: 'pipe',
    });
    return { passed: true, output };
  } catch (err: any) {
    return { passed: false, output: err.stdout ?? String(err) };
  }
}

// ─── Analizar resultado con Claude ────────────
async function analyzeResult(
  issue: JiraIssue,
  testOutput: string,
  passed: boolean
): Promise<string> {
  const response = await client.messages.create({
    model: 'claude-opus-4-5',
    max_tokens: 500,
    system: `Eres un QA lead analizando si un fix resolvió el issue de emprendy.ai.
Sé conciso. Responde en español. Máximo 3 oraciones.`,

    messages: [
      {
        role: 'user',
        content: `Issue: ${issue.key} — ${issue.summary}
Fix aplicado en: ${issue.affectedFile}
Tests: ${passed ? '✅ PASARON' : '❌ FALLARON'}

Output del test:
${testOutput.slice(0, 2000)}

¿El fix parece haber resuelto el problema?`,
      },
    ],
  });

  return response.content
    .filter((b) => b.type === 'text')
    .map((b) => (b as any).text)
    .join('')
    .trim();
}

// ─── Main ─────────────────────────────────────
async function main() {
  console.log('✅ [VALIDATOR] Starting post-fix validation...\n');

  // Leer issues que tienen un PR/fix aplicado
  const issuesFile = 'reports/fixed-issues.json';
  if (!fs.existsSync(issuesFile)) {
    console.log('[VALIDATOR] No fixed-issues.json found. Nothing to validate.');
    return;
  }

  const issues: JiraIssue[] = JSON.parse(fs.readFileSync(issuesFile, 'utf-8'));
  const toValidate = issues.filter((i) => i.status === 'In Review' && i.fixBranch);

  console.log(`[VALIDATOR] ${toValidate.length} issues to validate`);

  const summary = { closed: 0, reopened: 0, errors: 0 };

  for (const issue of toValidate) {
    console.log(`\n[VALIDATOR] Validating ${issue.key}: ${issue.summary}`);

    try {
      const { passed, output } = await reRunTests(issue);
      const analysis = await analyzeResult(issue, output, passed);

      if (passed) {
        // ✅ Cerrar issue en Jira
        await transitionIssue(issue.key, 'Done');
        await addComment(
          issue.key,
          `✅ *Validator Agent* verificó el fix.\n\nTodos los tests del módulo *${issue.component}* pasan correctamente.\n\n*Análisis:* ${analysis}\n\nIssue cerrado automáticamente.`
        );
        console.log(`[VALIDATOR] ✅ ${issue.key} — CLOSED`);
        summary.closed++;
      } else {
        // ❌ Reabrir issue
        await transitionIssue(issue.key, 'Open');
        await addComment(
          issue.key,
          `❌ *Validator Agent* detectó que el fix NO resolvió el problema.\n\nTests fallando en módulo *${issue.component}*.\n\n*Análisis:* ${analysis}\n\nIssue reabierto. El fix automático fue insuficiente — requiere revisión manual.\n\nOutput:\n{code}\n${output.slice(0, 1000)}\n{code}`
        );
        console.log(`[VALIDATOR] ❌ ${issue.key} — REOPENED`);
        summary.reopened++;
      }
    } catch (err) {
      console.error(`[VALIDATOR] Error validating ${issue.key}:`, err);
      await addComment(
        issue.key,
        `⚠️ *Validator Agent* falló al ejecutar validación.\nError: ${err}`
      ).catch(() => {});
      summary.errors++;
    }
  }

  // Resumen final
  const msg = `Validator completó: *${summary.closed} cerrados* ✅ | *${summary.reopened} reabiertos* ❌ | *${summary.errors} errores* ⚠️`;
  console.log(`\n📊 ${msg}`);

  if (summary.closed > 0 || summary.reopened > 0) {
    await notifySlack(msg, summary.reopened > 0 ? 'high' : 'success');
  }

  console.log('\n✅ [VALIDATOR] Done.');
}

main().catch((err) => {
  console.error('[VALIDATOR] Fatal:', err);
  process.exit(1);
});

import { NextResponse } from 'next/server';

export async function GET(req: Request) {
  const url = new URL(req.url);
  const error = url.searchParams.get('error');
  const errorDescription = url.searchParams.get('error_description');
  const errorUri = url.searchParams.get('error_uri');

  console.log('OAuth Error Details:', {
    error,
    errorDescription,
    errorUri,
    fullUrl: req.url,
  });

  // Redirect back to register page with error message
  const redirectUrl = new URL('/registrarse', req.url);
  if (error) {
    redirectUrl.searchParams.set('error', `oauth_error: ${error}`);
    if (errorDescription) {
      redirectUrl.searchParams.set('error_description', errorDescription);
    }
  }

  return NextResponse.redirect(redirectUrl);
}

import { NextResponse } from 'next/server';

export async function GET(req: Request) {
  try {
    const url = new URL(req.url);
    const code = url.searchParams.get('code');
    const state = url.searchParams.get('state');
    const error = url.searchParams.get('error');

    // Handle OAuth errors
    if (error) {
      console.error('OAuth error:', error);
      return NextResponse.redirect(new URL('/registrarse?error=oauth_cancelled', req.url));
    }

    if (!code) {
      return NextResponse.redirect(new URL('/registrarse?error=no_authorization_code', req.url));
    }

    // Get Google client credentials
    const clientId = process.env.NEXT_PUBLIC_GOOGLE_CLIENT_ID;
    const clientSecret = process.env.GOOGLE_CLIENT_SECRET;
    const redirectUri = `${new URL(req.url).origin}/api/auth/google/callback`;

    if (!clientId || !clientSecret) {
      console.error('Google OAuth credentials not configured');
      return NextResponse.redirect(new URL('/registrarse?error=oauth_not_configured', req.url));
    }

    // Exchange authorization code for access token
    const tokenResponse = await fetch('https://oauth2.googleapis.com/token', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: new URLSearchParams({
        code,
        client_id: clientId,
        client_secret: clientSecret,
        redirect_uri: redirectUri,
        grant_type: 'authorization_code',
      }),
    });

    if (!tokenResponse.ok) {
      const tokenError = await tokenResponse.text();
      console.error('Token exchange failed:', tokenError);
      return NextResponse.redirect(new URL('/registrarse?error=token_exchange_failed', req.url));
    }

    const tokenData = await tokenResponse.json();
    const accessToken = tokenData.access_token;

    // Get user profile from Google
    const profileResponse = await fetch(
      `https://www.googleapis.com/oauth2/v2/userinfo?access_token=${accessToken}`
    );

    if (!profileResponse.ok) {
      console.error('Failed to fetch Google profile');
      return NextResponse.redirect(new URL('/registrarse?error=profile_fetch_failed', req.url));
    }

    const profile = await profileResponse.json();

    // Register or login user with your backend
    const base = process.env.NEXT_PUBLIC_API_URL;
    if (!base) {
      return NextResponse.redirect(new URL('/registrarse?error=backend_not_configured', req.url));
    }

    // Try to register/login with Google profile
    const authUrl = `${base.replace(/\/$/, '')}/auth/google`;

    console.log('🔍 Sending to backend:', {
      googleId: profile.id,
      email: profile.email,
      name: profile.name,
      picture: profile.picture || null,
      accessToken: accessToken,
    });

    const authResponse = await fetch(authUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Accept: 'application/json',
      },
      body: JSON.stringify({
        googleId: profile.id,
        email: profile.email,
        name: profile.name,
        picture: profile.picture || null,
        accessToken: accessToken,
      }),
    });

    const authData = await authResponse.json().catch((parseError) => {
      console.error('❌ Failed to parse backend response:', parseError);
      return {};
    });

    if (!authResponse.ok) {
      console.error('Backend auth failed with status:', authResponse.status);
      console.error('Backend auth error details:', authData);
      return NextResponse.redirect(
        new URL(`/registrarse?error=backend_auth_failed&status=${authResponse.status}`, req.url)
      );
    }

    // Set auth cookie and redirect to success page
    const token = authData?.access_token || authData?.accessToken || authData?.token;
    const userData = authData?.user;

    // Debug the extracted values
    console.log('🔍 Extracted token:', token);
    console.log('🔍 Extracted userData:', userData);

    // Parse state to get redirect URL and determine final destination based on user store
    let baseRedirectTo = '/dashboard/insights'; // Default redirect from state
    try {
      if (state) {
        const stateData = JSON.parse(decodeURIComponent(state));
        baseRedirectTo = stateData.redirectTo || baseRedirectTo;
      }
    } catch (e) {
      console.warn('Failed to parse state parameter:', e);
    }

    // Determine final redirect based on whether user has a store
    let finalRedirectTo;
    if (userData && (userData.storeId || userData.restaurantId || userData.serviceProviderId)) {
      // User has a store, redirect to insights dashboard
      finalRedirectTo = '/dashboard/insights';
    } else {
      // User doesn't have a store, redirect to store creation
      finalRedirectTo = '/dashboard/store/new';
    }

    // For production, we'll create a success page that handles localStorage
    // For now, let's use query parameters to pass the data
    // Always use app.emprendy.ai domain for redirects
    const appDomain =
      process.env.NEXT_PUBLIC_APP_URL ||
      (process.env.NODE_ENV === 'production' ? 'https://app.emprendy.ai' : new URL(req.url).origin);
    const redirectUrl = new URL('/auth/success', appDomain);
    redirectUrl.searchParams.set('token', token || '');
    redirectUrl.searchParams.set('user', JSON.stringify(userData || {}));
    redirectUrl.searchParams.set('redirectTo', finalRedirectTo);

    const response = NextResponse.redirect(redirectUrl);

    if (token) {
      response.cookies.set('auth_token', token, {
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production',
        sameSite: 'lax',
        path: '/',
        maxAge: 60 * 60 * 24 * 7, // 7 days
      });
    }

    return response;
  } catch (error) {
    console.error('Google OAuth callback error:', error);
    return NextResponse.redirect(new URL('/registrarse?error=unexpected_error', req.url));
  }
}

import { NextResponse } from 'next/server';

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { email, password } = body;

    // Validate input
    if (!email || !password) {
      return NextResponse.json({ error: 'Email and password are required' }, { status: 400 });
    }

    // Get backend URL
    const backendUrl = process.env.NEXT_PUBLIC_API_URL;
    if (!backendUrl) {
      return NextResponse.json({ error: 'Backend not configured' }, { status: 500 });
    }

    // Call your backend login endpoint
    const response = await fetch(`${backendUrl.replace(/\/$/, '')}/auth/login`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ email, password }),
    });

    const data = await response.json();
    console.log('🚀 ~ POST ~ data:', data);

    if (!response.ok) {
      console.error('Backend login failed:', data);
      return NextResponse.json(
        { error: data.message || 'Invalid credentials' },
        { status: response.status }
      );
    }

    // Get the token from your backend response
    const token = data.accessToken;

    // Create response and set httpOnly cookie
    const nextResponse = NextResponse.json({
      success: true,
      user: data,
      message: 'Login successful',
    });

    if (token) {
      nextResponse.cookies.set('auth_token', token, {
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production',
        sameSite: 'lax',
        path: '/',
        maxAge: 60 * 60 * 24 * 7, // 7 days
      });
    }

    return nextResponse;
  } catch (error) {
    console.error('Login API error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

