          'Bebidas',
          'Postres',
        ]
      );
    } else if (category === 'services') {
      const specialtiesMap: { [key: string]: string[] } = {
        Terapia: [
          'Psicología',
          'Terapia Familiar',
          'Terapia de Pareja',
