      // Check order status every 10 seconds for up to 2 minutes
      const orderStatusInterval = setInterval(async () => {
        if (refetch) {
          await refetch();
        }
      }, 10000);

      // Clear interval after 2 minutes
      const orderTimeout = setTimeout(
        () => {
          clearInterval(orderStatusInterval);
