              ) : (
                <div className="px-4 py-8 text-center">
                  <Tag className="w-10 h-10 text-gray-600 mx-auto mb-3" />
                  <p className="text-gray-400 text-sm font-medium">No se encontraron categorías</p>
                  <p className="text-gray-500 text-xs mt-1">Intenta con otro término de búsqueda</p>
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      {/* Empty State */}
      {selectedCategories.length === 0 && (
        <div className="text-center py-6 bg-gray-800 rounded-xl border-2 border-dashed border-gray-600">
          <Tag className="w-8 h-8 text-gray-600 mx-auto mb-2" />
          <p className="text-sm text-gray-400 font-medium">
            {categories.length === 0
              ? 'No hay categorías disponibles'
              : 'Selecciona al menos una categoría'}
          </p>
          <p className="text-xs text-gray-500 mt-1">
            Las categorías ayudan a los clientes a encontrar tu producto
          </p>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState } from 'react';
import { Plus, X, Palette } from 'lucide-react';
import { ProductColor } from '@/app/utils/types/Product';

interface ColorPickerProps {
  colors: ProductColor[];
  onChange: (colors: ProductColor[]) => void;
}

export function ColorPicker({ colors, onChange }: ColorPickerProps) {
  const [newColor, setNewColor] = useState({ name: '', hex: '#000000' });
  const [showForm, setShowForm] = useState(false);

  const addColor = () => {
    if (!newColor.name.trim()) return;

    // Prevent duplicate color names (case-insensitive)
    const exists = colors.some(
      (c) => c.name.trim().toLowerCase() === newColor.name.trim().toLowerCase()
    );
    if (exists) {
      alert('Este color ya existe.');
      return;
    }

    const color: ProductColor = {
      id: `color-${Date.now()}`,
      name: newColor.name,
      hex: newColor.hex,
    };

    onChange([...colors, color]);
    setNewColor({ name: '', hex: '#000000' });
    setShowForm(false);
  };

  const removeColor = (index: number) => {
    onChange(colors.filter((_, i) => i !== index));
  };

  const updateColor = (index: number, field: 'name' | 'hex', value: string) => {
    const updatedColors = colors.map((color, i) =>
      i === index ? { ...color, [field]: value } : color
    );
    onChange(updatedColors);
  };

  return (
    <div className="space-y-4 pt-2">
      <div className="flex items-center justify-between">
        <h5 className="text-sm font-semibold text-gray-200">Colores</h5>
        <button
          type="button"
          onClick={() => setShowForm(!showForm)}
          className="flex items-center text-sm text-blue-400 hover:text-blue-300"
        >
          <Plus className="w-4 h-4 mr-1" />
          Agregar Color
        </button>
      </div>

      {/* Add Color Form */}
      {showForm && (
        <div className="border border-gray-700 rounded-lg p-4 bg-gray-800">
          <div className="flex items-end space-x-3">
            <div className="flex-1">
              <label className="block text-xs font-medium text-gray-300 mb-1">
                Nombre del Color
              </label>
              <input
                type="text"
                value={newColor.name}
                onChange={(e) => setNewColor({ ...newColor, name: e.target.value })}
                className="w-full px-3 py-2 bg-gray-800 border border-gray-600 rounded-md text-white placeholder-gray-400 focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                placeholder="ej: Rojo Ferrari"
              />
            </div>
            <div>
              <label className="block text-xs font-medium text-gray-300 mb-1">Color</label>
              <div className="flex items-center space-x-2">
                <input
                  type="color"
                  value={newColor.hex}
                  onChange={(e) => setNewColor({ ...newColor, hex: e.target.value })}
                  className="w-10 h-10 border border-gray-600 rounded cursor-pointer bg-gray-800"
                />
                <input
                  type="text"
                  value={newColor.hex}
                  onChange={(e) => setNewColor({ ...newColor, hex: e.target.value })}
                  className="w-20 px-2 py-2 text-xs bg-gray-800 border border-gray-600 rounded text-white placeholder-gray-400"
                  placeholder="#000000"
                />
              </div>
            </div>
            <div className="flex space-x-2">
              <button
                type="button"
                onClick={addColor}
                className="px-3 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 text-sm"
              >
                Agregar
              </button>
              <button
                type="button"
                onClick={() => setShowForm(false)}
                className="px-3 py-2 bg-gray-600 text-gray-200 rounded-md hover:bg-gray-500 text-sm"
              >
                Cancelar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Colors List */}
      {colors.length > 0 && (
        <div className="space-y-2">
          {colors.map((color, index) => (
            <div
              key={color.id}
              className="flex items-center space-x-3 p-3 border border-gray-700 rounded-lg bg-gray-800"
            >
              <div
                className="w-8 h-8 rounded-full border-2 border-gray-500 flex-shrink-0"
                style={{ backgroundColor: color.hex }}
              />
              <div className="flex-1 grid grid-cols-2 gap-3">
                <input
                  type="text"
                  value={color.name}
                  onChange={(e) => updateColor(index, 'name', e.target.value)}
                  className="px-2 py-1 bg-gray-800 border border-gray-600 rounded text-sm text-white placeholder-gray-400 focus:ring-1 focus:ring-blue-500"
                  placeholder="Nombre del color"
                />
                <input
                  type="text"
                  value={color.hex}
                  onChange={(e) => updateColor(index, 'hex', e.target.value)}
                  className="px-2 py-1 bg-gray-800 border border-gray-600 rounded text-sm text-white placeholder-gray-400 focus:ring-1 focus:ring-blue-500"
                  placeholder="#000000"
                />
              </div>
              <button
                type="button"
                onClick={() => removeColor(index)}
                className="p-1 text-red-400 hover:text-red-300"
              >
                <X className="w-4 h-4" />
              </button>
            </div>
          ))}
        </div>
      )}

      {colors.length === 0 && !showForm && (
        <div className="text-center py-8 text-gray-400">
          <Palette className="w-8 h-8 mx-auto mb-2 text-gray-600" />
          <p className="text-sm">No hay colores configurados</p>
          <p className="text-xs">Haz clic en Agregar Color para empezar</p>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState } from 'react';
import { Plus, X, Settings, Palette, Ruler } from 'lucide-react';
import { ColorPicker } from './ColorPicker';
import { SizeSelector } from './SizeSelector';
import { ProductColor, ProductSize } from '@/app/utils/types/Product';

interface CustomVariant {
  id: string;
  type: string;
  name: string;
  value: string;
}

interface CustomVariantSelectorProps {
  variants: CustomVariant[];
  onChange: (variants: CustomVariant[]) => void;
  colors?: ProductColor[];
  onChangeColors?: (colors: ProductColor[]) => void;
  sizes?: ProductSize[];
  onChangeSizes?: (sizes: ProductSize[]) => void;
}

export function CustomVariantSelector({
  variants,
  onChange,
  colors = [],
  onChangeColors,
  sizes = [],
  onChangeSizes,
}: CustomVariantSelectorProps) {
  const [isAdding, setIsAdding] = useState(false);
  const [newVariant, setNewVariant] = useState({
    type: '',
    name: '',
    value: '',
  });

  const handleAddVariant = () => {
    if (!newVariant.type.trim() || !newVariant.name.trim()) return;

    // Prevent duplicate custom variants by type+name (case-insensitive)
    const isDuplicate = variants.some(
      (v) =>
        v.type.trim().toLowerCase() === newVariant.type.trim().toLowerCase() &&
        v.name.trim().toLowerCase() === newVariant.name.trim().toLowerCase()
    );
    if (isDuplicate) {
      alert('Esta variante personalizada ya existe.');
      return;
    }

    const variant: CustomVariant = {
      id: `custom-${Date.now()}-${Math.random()}`,
      type: newVariant.type.trim(),
      name: newVariant.name.trim(),
      value: newVariant.value.trim() || newVariant.name.trim(),
    };

    onChange([...variants, variant]);
    setNewVariant({ type: '', name: '', value: '' });
    setIsAdding(false);
  };

  const handleRemoveVariant = (id: string) => {
    onChange(variants.filter((v) => v.id !== id));
  };

  const handleUpdateVariant = (
    id: string,
    field: keyof Omit<CustomVariant, 'id'>,
    value: string
  ) => {
    onChange(variants.map((v) => (v.id === id ? { ...v, [field]: value } : v)));
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h5 className="text-md font-medium text-gray-300 mb-4 flex items-center">
          <Settings className="w-4 h-4 mr-2" />
          Variantes Personalizadas
        </h5>
        <button
          type="button"
          onClick={() => setIsAdding(true)}
          className="flex items-center text-sm text-blue-400 hover:text-blue-300"
        >
          <Plus className="w-4 h-4 mr-1" />
          Agregar Variante
        </button>
      </div>

      {/* Existing variants grouped by type */}
      <div className="space-y-3">
        {(() => {
          if (!variants || variants.length === 0) return null;
          const groups: Record<string, { typeLabel: string; items: CustomVariant[] }> = {};
          variants.forEach((v) => {
            const key = (v.type || 'Otros').trim().toLowerCase() || 'otros';
            if (!groups[key]) groups[key] = { typeLabel: v.type || key, items: [] };
            groups[key].items.push(v);
          });

          return Object.keys(groups).map((k) => {
            const group = groups[k];
            const title =
              group.typeLabel && group.typeLabel.trim()
                ? group.typeLabel.charAt(0).toUpperCase() + group.typeLabel.slice(1)
                : k.charAt(0).toUpperCase() + k.slice(1);

            return (
              <div key={k} className="space-y-2">
                <h6 className="text-sm font-semibold text-gray-200">{title}</h6>
                <div className="space-y-2">
                  {group.items.map((variant) => (
                    <div
                      key={variant.id}
                      className="flex items-center space-x-3 p-3 border border-gray-700 rounded-lg bg-gray-800"
                    >
                      <div className="flex-1 grid grid-cols-3 gap-3">
                        <input
                          type="text"
                          value={variant.type}
                          onChange={(e) => handleUpdateVariant(variant.id, 'type', e.target.value)}
                          placeholder="Tipo (ej: Material)"
                          className="px-2 py-1 border border-gray-600 bg-gray-800 text-white rounded text-sm focus:ring-1 focus:ring-blue-500 focus:border-blue-500 placeholder-gray-400"
                        />
                        <input
                          type="text"
                          value={variant.name}
                          onChange={(e) => handleUpdateVariant(variant.id, 'name', e.target.value)}
                          placeholder="Nombre (ej: Algodón)"
                          className="px-2 py-1 border border-gray-600 bg-gray-800 text-white rounded text-sm focus:ring-1 focus:ring-blue-500 focus:border-blue-500 placeholder-gray-400"
                        />
                        <input
                          type="text"
                          value={variant.value}
                          onChange={(e) => handleUpdateVariant(variant.id, 'value', e.target.value)}
                          placeholder="Valor (opcional)"
                          className="px-2 py-1 border border-gray-600 bg-gray-800 text-white rounded text-sm focus:ring-1 focus:ring-blue-500 focus:border-blue-500 placeholder-gray-400"
                        />
                      </div>
                      <button
                        type="button"
                        onClick={() => handleRemoveVariant(variant.id)}
                        className="p-1 text-red-400 hover:text-red-300 hover:bg-red-900 rounded transition-colors"
                      >
                        <X className="w-4 h-4" />
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            );
          });
        })()}
        {onChangeColors && colors && colors.length > 0 && (
          <div>
            <ColorPicker colors={colors} onChange={onChangeColors} />
          </div>
        )}
        {onChangeSizes && sizes && sizes.length > 0 && (
          <div>
            <SizeSelector sizes={sizes} onChange={onChangeSizes} />
          </div>
        )}
      </div>

      {/* Add new variant form */}
      {isAdding && (
        <div className="p-4 border-2 border-dashed border-gray-600 rounded-lg bg-gray-800">
          <div className="space-y-3">
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-1">
                  Tipo de Variante *
                </label>
                <input
                  type="text"
                  value={newVariant.type}
                  onChange={(e) => setNewVariant((prev) => ({ ...prev, type: e.target.value }))}
                  placeholder="ej: Material, Acabado, Estilo"
                  className="w-full px-3 py-2 border border-gray-600 bg-gray-800 text-white rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500 placeholder-gray-400"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-1">Nombre *</label>
                <input
                  type="text"
                  value={newVariant.name}
                  onChange={(e) => setNewVariant((prev) => ({ ...prev, name: e.target.value }))}
                  placeholder="ej: Algodón, Mate, Clásico"
                  className="w-full px-3 py-2 border border-gray-600 bg-gray-800 text-white rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500 placeholder-gray-400"
                />
              </div>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-1">
                Valor (opcional)
              </label>
              <input
                type="text"
                value={newVariant.value}
                onChange={(e) => setNewVariant((prev) => ({ ...prev, value: e.target.value }))}
                placeholder="Valor adicional o descripción"
                className="w-full px-3 py-2 border border-gray-600 bg-gray-800 text-white rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500 placeholder-gray-400"
              />
            </div>
            <div className="flex justify-end space-x-2">
              <button
                type="button"
                onClick={() => {
                  setIsAdding(false);
                  setNewVariant({ type: '', name: '', value: '' });
                }}
                className="px-3 py-2 border border-gray-600 rounded-md text-sm text-gray-300 bg-gray-800 hover:bg-gray-700 transition-colors"
              >
                Cancelar
              </button>
              <button
                type="button"
                onClick={handleAddVariant}
                disabled={!newVariant.type.trim() || !newVariant.name.trim()}
                className="px-3 py-2 bg-blue-600 text-white rounded-md text-sm hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                Agregar
              </button>
            </div>
          </div>
        </div>
      )}

      {variants.length === 0 && !isAdding && (
        <div className="text-center py-8 text-gray-400">
          <Settings className="w-8 h-8 mx-auto mb-2 opacity-50" />
          <p className="text-sm">No hay variantes personalizadas</p>
          <p className="text-xs text-gray-500 mt-1">
            Agrega variantes como material, acabado, estilo, etc.
          </p>
        </div>
      )}

      {variants.length > 0 && (
        <div className="mt-4 p-3 bg-blue-900 border border-blue-800 rounded-lg">
          <p className="text-sm text-blue-300">
            💡 <strong>Tip:</strong> Las variantes personalizadas te permiten añadir características
            únicas de tu producto como material, acabado, estilo, marca, etc.
          </p>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState, useCallback } from 'react';
import { Upload, X, Move, Image as ImageIcon, Eye, ZoomIn, Grid, List } from 'lucide-react';
import Image from 'next/image';
import { ProductImage } from '../../utils/types/Product';

interface ImageUploaderProps {
  images: ProductImage[];
  onChange: (images: ProductImage[]) => void;
  maxImages?: number;
}

export function ImageUploader({ images, onChange, maxImages = 10 }: ImageUploaderProps) {
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [previewImage, setPreviewImage] = useState<ProductImage | null>(null);
  const [hoveredImage, setHoveredImage] = useState<ProductImage | null>(null);
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const inputId = useState(() => `file-input-${Math.random().toString(36).slice(2)}`)[0];

  const handleFileUpload = useCallback(
    async (files: FileList) => {
      if (images.length + files.length > maxImages) {
        alert(`Máximo ${maxImages} imágenes permitidas`);
        return;
      }

      setIsUploading(true);
      const newImages: ProductImage[] = [];

      for (let i = 0; i < files.length; i++) {
        const file = files[i];
        if (!file.type.startsWith('image/')) continue;

        // Create a temporary URL for preview
        const url = URL.createObjectURL(file);
        newImages.push({
          id: `temp-${Date.now()}-${i}`,
          url,
          alt: file.name,
          order: images.length + newImages.length,
        });
      }

      onChange([...images, ...newImages]);
      setIsUploading(false);
    },
    [images, onChange, maxImages]
  );

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault();
      const files = e.dataTransfer.files;
      if (files.length > 0) {
        handleFileUpload(files);
      }
    },
    [handleFileUpload]
  );

  const handleFileChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files) {
        handleFileUpload(e.target.files);
      }
    },
    [handleFileUpload]
  );

  const removeImage = useCallback(
    (index: number) => {
      const newImages = images.filter((_, i) => i !== index);
      onChange(newImages.map((img, i) => ({ ...img, order: i })));
    },
    [images, onChange]
  );

  const moveImage = useCallback(
    (fromIndex: number, toIndex: number) => {
      const newImages = [...images];
      const [movedItem] = newImages.splice(fromIndex, 1);
      newImages.splice(toIndex, 0, movedItem);
      onChange(newImages.map((img, i) => ({ ...img, order: i })));
    },
    [images, onChange]
  );

  const handleDragStart = (index: number) => {
    setDraggedIndex(index);
  };

  const handleDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    if (draggedIndex !== null && draggedIndex !== index) {
      moveImage(draggedIndex, index);
      setDraggedIndex(index);
    }
  };

  const handleDragEnd = () => {
    setDraggedIndex(null);
  };

  return (
    <div className="space-y-4">
      {/* Upload Area */}
      <div
        onDrop={handleDrop}
        onDragOver={(e) => e.preventDefault()}
        className="border-2 border-dashed border-gray-600 bg-gray-800 rounded-lg p-6 text-center hover:border-fourth-500 hover:bg-gray-700 transition-colors"
      >
        <input
          type="file"
          multiple={maxImages > 1}
          accept="image/*"
          onChange={handleFileChange}
          className="hidden"
          id={inputId}
          disabled={isUploading || images.length >= maxImages}
        />

        <label htmlFor={inputId} className="cursor-pointer flex flex-col items-center space-y-2">
          {isUploading ? (
            <div className="w-8 h-8 border-2 border-fourth-500 border-t-transparent rounded-full animate-spin" />
          ) : (
            <Upload className="w-8 h-8 text-gray-400" />
          )}
          <div>
            <p className="text-sm font-medium text-white">
              {isUploading ? 'Subiendo...' : 'Arrastra imágenes aquí o haz clic para seleccionar'}
            </p>
            <p className="text-xs text-gray-400">
              PNG, JPG, GIF hasta 10MB. Máximo {maxImages} imágenes.
            </p>
          </div>
        </label>
      </div>

      {/* Image Grid */}
      {images.length > 0 && (
        <div className="space-y-4">
          {/* View Mode Toggle */}
          <div className="flex items-center justify-between">
            <p className="text-sm font-medium text-gray-300">
              {images.length} imagen{images.length !== 1 ? 'es' : ''} subida
              {images.length !== 1 ? 's' : ''}
            </p>
            <div className="flex items-center space-x-2">
              <button
                onClick={() => setViewMode('grid')}
                className={`p-2 rounded-lg transition-colors ${
                  viewMode === 'grid'
                    ? 'bg-fourth-base text-black'
                    : 'text-gray-500 hover:text-gray-300 hover:bg-gray-700'
                }`}
                title="Vista de cuadrícula"
              >
                <Grid className="w-4 h-4" />
              </button>
              <button
                onClick={() => setViewMode('list')}
                className={`p-2 rounded-lg transition-colors ${
                  viewMode === 'list'
                    ? 'bg-fourth-base text-black'
                    : 'text-gray-500 hover:text-gray-300 hover:bg-gray-700'
                }`}
                title="Vista de lista"
              >
                <List className="w-4 h-4" />
              </button>
            </div>
          </div>

          {/* Grid View */}
          {viewMode === 'grid' && (
            <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
              {images.map((image, index) => (
                <div
                  key={image.id}
                  className="bg-gray-800 border border-gray-700 rounded-lg p-3 shadow-sm hover:shadow-md transition-shadow"
                >
                  {/* Main Image */}
                  <div
                    draggable
                    onDragStart={() => handleDragStart(index)}
                    onDragOver={(e) => handleDragOver(e, index)}
                    onDragEnd={handleDragEnd}
                    className="relative aspect-square bg-gray-700 rounded-lg overflow-hidden cursor-move mb-3"
                  >
                    <Image
                      src={
                        image.url.startsWith('blob:')
                          ? image.url
                          : `https://emprendyup-images.s3.us-east-1.amazonaws.com/${image.url}`
                      }
                      alt={image.alt || `Producto imagen ${index + 1}`}
                      fill
                      className="object-cover"
                    />

                    {/* Order indicator */}
                    <div className="absolute top-2 left-2 bg-fourth-500 text-white text-xs rounded-full w-6 h-6 flex items-center justify-center">
                      {index + 1}
                    </div>
                  </div>

                  {/* Image Info */}
                  <div className="mb-3">
                    <p className="text-sm font-medium text-white truncate">
                      {image.alt || `Imagen ${index + 1}`}
                    </p>
                    <p className="text-xs text-gray-400">Posición: {index + 1}</p>
                  </div>

                  {/* Action Buttons */}
                  <div className="flex items-center justify-between space-x-2">
                    <button
                      onClick={() => setPreviewImage(image)}
                      className="flex-1 px-3 py-2 bg-fourth-base text-white text-xs rounded-md hover:bg-blue-700 transition-colors flex items-center justify-center"
                      title="Vista previa completa"
                    >
                      <Eye className="w-3 h-3 mr-1" />
                      Ver
                    </button>
                    <button
                      onClick={() => removeImage(index)}
                      className="px-3 py-2 bg-red-600 text-white text-xs rounded-md hover:bg-red-700 transition-colors"
                      title="Eliminar imagen"
                    >
                      <X className="w-3 h-3" />
                    </button>
                    <div
                      className="px-3 py-2 bg-gray-600 text-white text-xs rounded-md cursor-move flex items-center justify-center"
                      title="Arrastrar para reordenar"
                    >
                      <Move className="w-3 h-3" />
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}

          {/* List View */}
          {viewMode === 'list' && (
            <div className="space-y-3">
              {images.map((image, index) => (
                <div
                  key={image.id}
                  draggable
                  onDragStart={() => handleDragStart(index)}
                  onDragOver={(e) => handleDragOver(e, index)}
                  onDragEnd={handleDragEnd}
                  className="flex items-center space-x-4 p-3 bg-gray-800 border border-gray-700 rounded-lg hover:bg-gray-700 transition-colors cursor-move"
                >
                  {/* Thumbnail */}
                  <div className="relative w-16 h-16 bg-gray-700 rounded-lg overflow-hidden flex-shrink-0">
                    <Image
                      src={
                        image.url.startsWith('blob:')
                          ? image.url
                          : `https://emprendyup-images.s3.us-east-1.amazonaws.com/${image.url}`
                      }
                      alt={image.alt || `Producto imagen ${index + 1}`}
                      fill
                      className="object-cover"
                    />
                  </div>

                  {/* Info */}
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-white truncate">
                      {image.alt || `Imagen ${index + 1}`}
                    </p>
                    <p className="text-xs text-gray-400">Posición: {index + 1}</p>
                  </div>

                  {/* Actions */}
                  <div className="flex items-center space-x-2">
                    <button
                      onClick={() => setPreviewImage(image)}
                      className="p-2 text-black hover:bg-fourth-base rounded-lg transition-colors"
                      title="Vista previa"
                    >
                      <Eye className="w-4 h-4" />
                    </button>
                    <button
                      onClick={() => removeImage(index)}
                      className="p-2 text-red-400 hover:bg-red-900 rounded-lg transition-colors"
                      title="Eliminar"
                    >
                      <X className="w-4 h-4" />
                    </button>
                    <div className="p-2 text-gray-400" title="Arrastrar para reordenar">
                      <Move className="w-4 h-4" />
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Preview Modal */}
      {previewImage && (
        <div className="fixed inset-0 bg-black bg-opacity-75 flex items-center justify-center z-50 p-4">
          <div className="relative max-w-4xl max-h-full bg-gray-800 border border-gray-700 rounded-lg overflow-hidden">
            {/* Modal Header */}
            <div className="flex items-center justify-between p-4 border-b border-gray-700">
              <h3 className="text-lg font-semibold text-white">Vista Previa de Imagen</h3>
              <button
                onClick={() => setPreviewImage(null)}
                className="p-2 hover:bg-gray-700 rounded-full transition-colors"
              >
                <X className="w-5 h-5 text-gray-400" />
              </button>
            </div>

            {/* Modal Content */}
            <div className="p-4 bg-gray-800">
              <div className="relative max-w-3xl max-h-96 mx-auto">
                <Image
                  src={
                    previewImage.url.startsWith('blob:')
                      ? previewImage.url
                      : `https://emprendyup-images.s3.us-east-1.amazonaws.com/${previewImage.url}`
                  }
                  alt={previewImage.alt || 'Preview'}
                  width={800}
                  height={600}
                  className="object-contain w-full h-full rounded-lg"
                />
              </div>

              {/* Image Info */}
              <div className="mt-4 text-center text-sm text-gray-400">
                <p className="font-medium text-white">
                  {previewImage.alt ||
                    `Imagen ${images.findIndex((img) => img.id === previewImage.id) + 1}`}
                </p>
                <p>Orden: {previewImage.order + 1}</p>
              </div>

              {/* Actions */}
              <div className="flex justify-center space-x-3 mt-4">
                <button
                  onClick={() => {
                    const currentIndex = images.findIndex((img) => img.id === previewImage.id);
                    if (currentIndex > 0) {
                      const prevImage = images[currentIndex - 1];
                      setPreviewImage(prevImage);
                    }
                  }}
                  disabled={images.findIndex((img) => img.id === previewImage.id) === 0}
                  className="px-4 py-2 bg-gray-600 text-white rounded-lg hover:bg-gray-500 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                >
                  ← Anterior
                </button>
                <button
                  onClick={() => {
                    const currentIndex = images.findIndex((img) => img.id === previewImage.id);
                    removeImage(currentIndex);
                    setPreviewImage(null);
                  }}
                  className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors"
                >
                  Eliminar
                </button>
                <button
                  onClick={() => {
                    const currentIndex = images.findIndex((img) => img.id === previewImage.id);
                    if (currentIndex < images.length - 1) {
                      const nextImage = images[currentIndex + 1];
                      setPreviewImage(nextImage);
                    }
                  }}
                  disabled={
                    images.findIndex((img) => img.id === previewImage.id) === images.length - 1
                  }
                  className="px-4 py-2 bg-gray-600 text-white rounded-lg hover:bg-gray-500 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                >
                  Siguiente →
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

