'use client';
import { gql, useQuery } from '@apollo/client';
import { useState } from 'react';
import Link from 'next/link';
import Image from 'next/image';
import { FiHeart, FiEye, FiBookmark, FiChevronLeft, FiChevronRight } from '../assets/icons/vander';
import { Product } from '../utils/types';

const PAGINATED_PRODUCTS_QUERY = gql`
  query GetPaginatedProducts($page: Int, $pageSize: Int) {
    paginatedProducts(pagination: { page: $page, pageSize: $pageSize }) {
      items {
        id
        name
        title
        description
        price
        currency
        storeId
        available
        createdAt
        updatedAt
        images {
          id
          url
          order
        }
        colors {
          id
          color
          colorHex
        }
        sizes {
          id
          size
        }
        comments {
          id
          rating
          comment
          createdAt
        }
      }
      total
      page
      pageSize
    }
  }
`;

export default function ProductListClient({
  page = 1,
  pageSize = 50,
  gridClass = 'grid grid-cols-1 md:grid-cols-2 gap-6',
}) {
  const [currentPage, setCurrentPage] = useState(page);
  const { data, loading, error } = useQuery(PAGINATED_PRODUCTS_QUERY, {
    variables: { page: currentPage, pageSize },
    // Use pageSize from props or default value
  });

  if (loading) return <div className="text-center py-10">Cargando productos...</div>;
  if (error) return <div className="text-center py-10 text-red-500">Error: {error.message}</div>;

  const products = data?.paginatedProducts?.items || [];
  const total = data?.paginatedProducts?.total || 0;
  // const currentPage = data?.paginatedProducts?.page || 1;
  const pageSizeVal = data?.paginatedProducts?.pageSize || pageSize;
  const totalPages = Math.ceil(total / pageSizeVal);

  const handleAddToFavorites = (item: Product) => {
    console.log(`Add to favorites: ${item.title}`);
    // Save to localStorage
    try {
      const favorites = JSON.parse(localStorage.getItem('favorites') || '[]');
      // Avoid duplicates by id
      if (!favorites.some((fav: Product) => fav.id === item.id)) {
        favorites.push(item);
        localStorage.setItem('favorites', JSON.stringify(favorites));
      }
    } catch (e) {
      console.error('Error saving to favorites:', e);
    }
  };

  // Function to get the image URL
  const getImageUrl = (item: Product) => {
    const imageKey = item?.images?.[0]?.url;
    const imageUrl = imageKey
      ? `https://emprendyup-images.s3.us-east-1.amazonaws.com/${imageKey}`
      : '/assets/default-product.jpg';
    return imageUrl;
  };

  return (
    <>
      <div className={gridClass}>
        {products.map((item: Product) => (
          <div className="group relative duration-500 w-full mx-auto" key={item.id}>
            <div className="flex flex-col items-center">
              <div
                className="relative overflow-hidden w-full shadow dark:shadow-gray-800 group-hover:shadow-lg group-hover:dark:shadow-gray-800 rounded-md duration-500"
                style={{ height: '320px' }}
              >
                <Image
                  className="w-full h-full object-cover rounded-md group-hover:scale-110 duration-500"
                  src={getImageUrl(item)}
                  width={320}
                  height={320}
                  alt={item.title || 'Placeholder Image'}
                  loading="lazy"
                />
                <ul className="list-none absolute top-[10px] end-4 opacity-0 group-hover:opacity-100 duration-500 space-y-1">
                  <li>
                    <button
                      className="size-10 inline-flex items-center justify-center tracking-wide align-middle duration-500 text-center rounded-full bg-white text-slate-900 hover:bg-slate-900 hover:text-white shadow"
                      onClick={() => handleAddToFavorites(item)}
                    >
                      <FiHeart className="size-4" />
                    </button>
                  </li>
                  <li className="mt-1 ms-0">
                    <Link
                      href={`/producto/${item.id}`}
                      className="size-10 inline-flex items-center justify-center tracking-wide align-middle duration-500 text-center rounded-full bg-white text-slate-900 hover:bg-slate-900 hover:text-white shadow"
                    >
                      <FiEye className="size-4" />
                    </Link>
                  </li>
                  <li className="mt-1 ms-0">
                    <Link
                      href="#"
                      className="size-10 inline-flex items-center justify-center tracking-wide align-middle duration-500 text-center rounded-full bg-white text-slate-900 hover:bg-slate-900 hover:text-white shadow"
                    >
                      <FiBookmark className="size-4" />
                    </Link>
                  </li>
                </ul>
              </div>
              <div className="w-full mt-4 text-center">
                <Link
                  href={`/producto/${item.id}`}
                  className="hover:text-fourth-base text-lg font-medium block"
                >
                  {item.title}
                </Link>
                <p className="text-slate-400 mt-2">{item.description}</p>
                <p className="mt-2 font-semibold">
                  {item.price} {item.currency}
                </p>
                <div className="mt-4">
                  <Link
                    href="/shop-cart"
                    className="py-2 px-5 inline-block font-semibold tracking-wide align-middle duration-500 text-base text-center bg-slate-900 dark:bg-slate-800 text-white rounded-md shadow dark:shadow-gray-700"
                  >
                    Añadir al carrito
                  </Link>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
      {/* Pagination outside grid */}
      <div className="grid md:grid-cols-12 grid-cols-1 mt-6">
        <div className="md:col-span-12 text-center">
          <nav aria-label="Page navigation example">
            <ul className="inline-flex items-center -space-x-px">
              <li>
                <button
                  disabled={currentPage === 1}
                  onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
                  className="size-[40px] inline-flex justify-center items-center text-slate-400 bg-white dark:bg-slate-900 rounded-s-3xl hover:text-white border border-gray-100 dark:border-gray-800 hover:border-fourth-base dark:hover:border-fourth-base hover:bg-fourth-base dark:hover:bg-fourth-base"
                >
                  <FiChevronLeft className="size-5 rtl:rotate-180 rtl:-mt-1" />
                </button>
              </li>
              {[...Array(totalPages)].map((_, i) => (
                <li key={i}>
                  <button
                    onClick={() => setCurrentPage(i + 1)}
                    className={`size-[40px] inline-flex justify-center items-center border border-gray-100 dark:border-gray-800 ${currentPage === i + 1 ? 'bg-fourth-base text-white z-10 border-fourth-base' : 'text-slate-400 bg-white dark:bg-slate-900 hover:text-white hover:border-fourth-base hover:bg-fourth-base dark:hover:border-fourth-base dark:hover:bg-fourth-base'}`}
                  >
                    {i + 1}
                  </button>
                </li>
              ))}
              <li>
                <button
                  disabled={currentPage === totalPages}
                  onClick={() => setCurrentPage((p) => Math.min(totalPages, p + 1))}
                  className="size-[40px] inline-flex justify-center items-center text-slate-400 bg-white dark:bg-slate-900 rounded-e-3xl hover:text-white border border-gray-100 dark:border-gray-800 hover:border-fourth-base dark:hover:border-fourth-base hover:bg-fourth-base dark:hover:bg-fourth-base"
                >
                  <FiChevronRight className="size-5 rtl:rotate-180 rtl:-mt-1" />
                </button>
              </li>
            </ul>
          </nav>
        </div>
      </div>
    </>
  );
}

'use client';
import React, { useState, useEffect, useRef } from 'react';
import FileUpload from './FileUpload';
import Image from 'next/image';
import { useSessionStore } from '@/lib/store/dashboard';
import AdressAutocomplete from './AdressAutocomplete';
import { setOptions, importLibrary } from '@googlemaps/js-api-loader';

interface RestaurantSummaryProps {
  open: boolean;
  onClose: () => void;
  data: any;
  onConfirm: (values: any) => void;
}

export default function RestaurantSummary({
  open,
  onClose,
  data,
  onConfirm,
}: RestaurantSummaryProps) {
  const [formData, setFormData] = useState<any>(data || {});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const user = useSessionStore();

  const resolveImageUrl = (value?: string) => {
    if (!value) return '';
    if (
      value.startsWith('http') ||
      value.startsWith('https') ||
      value.startsWith('blob:') ||
      value.startsWith('data:')
    ) {
      return value;
    }
    return `https://emprendyup-images.s3.us-east-1.amazonaws.com/${value}`;
  };

  useEffect(() => {
    if (data) {
      setFormData({
        ...data,
        whatsappNumber: data.whatsappNumber || data.phone || '',
        email: data.email || user.user?.email || '',
      });
    }
  }, [data, user.user?.email]);

  // Google Maps refs and init
  const mapContainerRef = useRef<HTMLDivElement | null>(null);
  const mapRef = useRef<google.maps.Map | null>(null);
  const markerRef = useRef<google.maps.marker.AdvancedMarkerElement | null>(null);

  const initGoogleMaps = () => {
    const apiKey = process.env.NEXT_PUBLIC_GOOGLE_MAPS_API_KEY;
    if (!apiKey) {
      // eslint-disable-next-line no-console
      console.warn('NEXT_PUBLIC_GOOGLE_MAPS_API_KEY no está configurada');
      return;
    }
    try {
      setOptions({ key: apiKey });
    } catch (e) {
      // noop
    }
  };

  useEffect(() => {
    initGoogleMaps();
  }, []);

  const setMapRef = (node: HTMLDivElement | null) => {
    if (!node) return;
    mapContainerRef.current = node;

    if (!mapRef.current) {
      importLibrary('maps')
        .then((maps: any) => {
          mapRef.current = new maps.Map(node, {
            center: {
              lat: typeof formData.lat === 'number' ? formData.lat : 4.60971,
              lng: typeof formData.lng === 'number' ? formData.lng : -74.08175,
            },
            zoom: 14,
            mapId: process.env.NEXT_PUBLIC_GOOGLE_MAP_ID,
          });
          // If initial coordinates are present, add marker
          (async () => {
            try {
              if (typeof formData.lat === 'number' && typeof formData.lng === 'number') {
                const markerLib = (await importLibrary('marker')) as google.maps.MarkerLibrary;
                if (!markerRef.current) {
                  markerRef.current = new markerLib.AdvancedMarkerElement({
                    map: mapRef.current,
                    position: { lat: formData.lat, lng: formData.lng },
                  });
                }
              }
            } catch (e) {
              // ignore marker init errors
            }
          })();
        })
        .catch((err: any) => {
          // eslint-disable-next-line no-console
          console.error('Error loading Google Maps:', err);
        });
    }
  };

  if (!open) return null;

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData((prev: any) => ({ ...prev, [name]: value }));
  };

  const handleImageUpload = (field: string) => (url: string) => {
    setFormData((prev: any) => ({ ...prev, [field]: url }));
  };

  const handleRemoveImage = (field: string) => () => {
    setFormData((prev: any) => ({ ...prev, [field]: '' }));
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      await onConfirm(formData);
    } catch (error) {
      console.error('Error al crear restaurante:', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleOverlayClick = (e: React.MouseEvent) => {
    if (e.target === e.currentTarget) {
      onClose();
    }
  };

  const inputClassName =
    'w-full border border-gray-600 rounded-lg px-3 py-2 bg-gray-800 text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500';

  const ImageUploadSection = ({ field, label }: { field: string; label: string }) => (
    <div className="space-y-2">
      <label className="text-sm font-medium text-gray-300 block mb-2">{label}</label>
      {!formData[field] ? (
        <FileUpload onFile={handleImageUpload(field)} accept="image/*" storeId={formData.storeId} />
      ) : (
        <div className="flex flex-col items-center gap-2">
          <div className="relative inline-block">
            {(() => {
              const resolved = resolveImageUrl(formData[field]);
              const isBlob = resolved.startsWith('blob:') || resolved.startsWith('data:');
              return (
                <Image
                  src={resolved}
                  alt={`${label} preview`}
                  width={80}
                  height={80}
                  className="h-20 w-20 object-contain rounded-lg border border-gray-600"
                  unoptimized={isBlob}
                />
              );
            })()}
            <button
              type="button"
              onClick={handleRemoveImage(field)}
              className="absolute -top-2 -right-2 w-6 h-6 bg-red-600 hover:bg-red-700 text-white rounded-full text-xs flex items-center justify-center transition-colors"
              disabled={isSubmitting}
            >
              ✕
            </button>
          </div>
        </div>
      )}
    </div>
  );

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/50"
      onClick={handleOverlayClick}
    >
      <div className="bg-gray-900 text-white rounded-xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto p-6 m-4 border border-gray-700">
        {/* Header */}
        <div className="flex justify-between items-center border-b border-gray-700 pb-3 mb-6">
          <h2 className="text-xl font-bold text-white">🍽️ Revisar datos del restaurante</h2>
          <button
            onClick={onClose}
            className="text-gray-400 hover:text-white text-xl font-bold w-8 h-8 flex items-center justify-center rounded-full hover:bg-gray-800 transition-colors"
            disabled={isSubmitting}
          >
            ✕
          </button>
        </div>

        <div className="space-y-6">
          {/* Información básica */}
          <div className="space-y-3">
            <h3 className="text-lg font-semibold text-white border-b border-gray-700 pb-1">
              Información básica
            </h3>
            <div>
              <label className="text-sm font-medium text-gray-300 mb-1 block">
                Nombre del restaurante
              </label>
              <input
                type="text"
                name="name"
