                  if (mapRef.current) {
                    mapRef.current.setCenter({ lat, lng });
                    mapRef.current.setZoom(16);
                    try {
                      const markerLib = (await importLibrary(
                        'marker'
                      )) as google.maps.MarkerLibrary;
                      if (!markerRef.current) {
                        markerRef.current = new markerLib.AdvancedMarkerElement({
                          map: mapRef.current,
                          position: { lat, lng },
                        });
                      } else if ((markerRef.current as any).position) {
                        // Update position
                        (markerRef.current as any).position = { lat, lng };
                      }
                    } catch (err) {
                      // eslint-disable-next-line no-console
                      console.warn('Marker library not available or error creating marker', err);
