                Agregar Imagen de Servicio
              </h2>
              <button
                onClick={() => {
                  setShowCreateModal(false);
                  setImageUrl('');
                }}
                className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-200"
              >
                <X className="h-6 w-6" />
              </button>
            </div>

            <form onSubmit={handleCreateImage} className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                  Imagen *
                </label>
                {imageUrl || imageFile ? (
                  <div className="relative">
                    <Image
                      src={imageFile ? URL.createObjectURL(imageFile) : resolveImageUrl(imageUrl)}
                      alt="Preview"
                      width={400}
                      height={200}
                      className="w-full h-48 object-cover rounded-lg"
                      unoptimized
                    />
                    <button
                      type="button"
                      onClick={() => {
                        setImageUrl('');
                        setImageFile(null);
                      }}
                      className="absolute top-2 right-2 p-2 bg-red-500 text-white rounded-full hover:bg-red-600"
                    >
                      <Trash2 className="h-4 w-4" />
                    </button>
                  </div>
                ) : (
                  <div>
                    <input
                      type="file"
                      accept="image/*"
                      onChange={(e) => {
                        const file = e.target.files?.[0];
                        if (file) {
                          setImageFile(file);
                        }
                      }}
                      className="block w-full text-sm text-gray-500 dark:text-gray-400
                        file:mr-4 file:py-2 file:px-4
                        file:rounded-lg file:border-0
                        file:text-sm file:font-semibold
                        file:bg-fourth-base file:text-white
                        hover:file:opacity-90
                        file:cursor-pointer cursor-pointer"
                    />
                  </div>
                )}
              </div>

              <div className="sticky bottom-0 bg-white dark:bg-gray-800 pt-4 flex gap-3">
                <button
                  type="button"
                  onClick={() => {
                    setShowCreateModal(false);
                    setImageUrl('');
                  }}
                  className="flex-1 px-4 py-2 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700"
                >
                  Cancelar
                </button>
                <button
                  type="submit"
                  disabled={uploading || (!imageUrl && !imageFile)}
                  className="flex-1 px-4 py-2 bg-fourth-base text-white rounded-lg hover:opacity-90 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {uploading ? 'Agregando...' : 'Agregar Imagen'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';
import React, { useState, useEffect } from 'react';
import FileUpload from './FileUpload';
import Image from 'next/image';
import { useSessionStore } from '@/lib/store/dashboard';

interface ServicesSummaryProps {
  open: boolean;
  onClose: () => void;
  data: any;
  onConfirm: (values: any) => void;
}

export default function ServicesSummary({ open, onClose, data, onConfirm }: ServicesSummaryProps) {
  const [formData, setFormData] = useState<any>(data || {});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const user = useSessionStore();

  const resolveImageUrl = (value?: string) => {
    if (!value) return '';
    if (
      value.startsWith('http') ||
      value.startsWith('https') ||
      value.startsWith('blob:') ||
      value.startsWith('data:')
    ) {
      return value;
    }
    return `https://emprendyup-images.s3.us-east-1.amazonaws.com/${value}`;
  };

  useEffect(() => {
    if (data) {
      setFormData({
        ...data,
        whatsappNumber: data.whatsappNumber || data.phone || '',
        email: data.email || user.user?.email || '',
      });
    }
  }, [data, user.user?.email]);

  if (!open) return null;

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData((prev: any) => ({ ...prev, [name]: value }));
  };

  const handleImageUpload = (field: string) => (url: string) => {
    setFormData((prev: any) => ({ ...prev, [field]: url }));
  };

  const handleRemoveImage = (field: string) => () => {
    setFormData((prev: any) => ({ ...prev, [field]: '' }));
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      await onConfirm(formData);
    } catch (error) {
      console.error('Error al crear empresa de servicios:', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleOverlayClick = (e: React.MouseEvent) => {
    if (e.target === e.currentTarget) {
      onClose();
    }
  };

  const inputClassName =
    'w-full border border-gray-600 rounded-lg px-3 py-2 bg-gray-800 text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500';

  const ImageUploadSection = ({ field, label }: { field: string; label: string }) => (
    <div className="space-y-2">
      <label className="text-sm font-medium text-gray-300 block mb-2">{label}</label>
      {!formData[field] ? (
