'use client';

import { useState, useEffect } from 'react';
import PostForm from './PostForm';
import RichTextEditor from './RichTextEditor';
import DOMPurify from 'dompurify';
import { BlogPost } from '@/lib/blog/blog.api';

interface PostEditorProps {
  initialData?: BlogPost;
}

export default function PostEditor({ initialData }: PostEditorProps) {
  const [content, setContent] = useState(initialData?.content || '');
  const [activeTab, setActiveTab] = useState<'edit' | 'preview'>('edit');
  const [saving, setSaving] = useState(false);
  // image upload handled at form level when needed
  // editing flag not used directly here
  // Autosave en localStorage
  useEffect(() => {
    const draftKey = initialData?.id ? `draft:${initialData.id}` : 'draft:new';
    const saved = localStorage.getItem(draftKey);
    if (!initialData && saved) {
      setContent(saved);
      alert('Borrador restaurado');
    }
    const interval = setInterval(() => {
      localStorage.setItem(draftKey, content);
    }, 5000);
    return () => clearInterval(interval);
  }, [content, initialData]);

  return (
    <div className="space-y-6">
      <PostForm initialData={initialData} />
    </div>
  );
}

'use client';

import { useEffect, useState, useRef } from 'react';
import { gql, useMutation, useQuery } from '@apollo/client';
import { useRouter } from 'next/navigation';
import { blogApi, BlogPost } from '@/lib/blog/blog.api';
import { generateSlug } from '@/lib/blog/slug';
import { BlogPostSchema } from '@/lib/blog/validation';
import RichTextEditor, { RichTextEditorRef } from './RichTextEditor';
import useDebounce from '../../../lib/hooks/useDebounce';
import { X, Save, Send, ArrowLeft, Plus } from 'lucide-react';
import { getUserFromLocalStorage } from '@/lib/utils/localAuth';
import FileUpload from '../FileUpload';

interface PostFormProps {
  initialData?: Partial<BlogPost>;
}

export default function PostForm({ initialData }: PostFormProps) {
  const [formData, setFormData] = useState({
    title: '',
    excerpt: '',
    slug: '',
    content: '',
    coverImageUrl: '',
    blogCategoryId: '',
    tagIds: [] as string[],
    relatedPostIds: [] as string[],
  });
  const [message, setMessage] = useState<string | null>(null);
  const [messageType, setMessageType] = useState<'success' | 'error' | 'info'>('info');
  const [isSaving, setIsSaving] = useState(false);
  const [contentHtml, setContentHtml] = useState<string>(initialData?.content || '');
  const [relatedQuery, setRelatedQuery] = useState('');
  const [relatedSuggestions, setRelatedSuggestions] = useState<BlogPost[]>([]);
  const [selectedRelatedPosts, setSelectedRelatedPosts] = useState<BlogPost[]>([]);
  const debouncedRelated = useDebounce(relatedQuery, 300);
  const router = useRouter();
  const isEdit = Boolean(initialData?.id);
  const user = getUserFromLocalStorage();

  const GET_ALL_POSTS = gql`
    query ListPostsPaginated($categoryId: String, $page: Int, $pageSize: Int) {
      listPostsPaginated(categoryId: $categoryId, page: $page, pageSize: $pageSize) {
        items {
          id
          title
          slug
          excerpt
          content
          status
          createdAt
          updatedAt
          publishedAt
          creator {
            id
            name
            email
          }
          blogCategory {
            id
            name
            slug
          }
          tags {
            tag {
              id
              name
              slug
            }
          }
          relatedPosts {
            id
            title
            slug
          }
          coverImageUrl
        }
        total
        page
        pageSize
        totalPages
        hasNextPage
        hasPrevPage
      }
    }
  `;

  const CREATE_POST = gql`
    mutation CreatePost($input: CreatePostInput!) {
      createPost(input: $input) {
        id
        title
        excerpt
        content
        coverImageUrl
        blogCategoryId
        status
        createdAt
        tags {
          tag {
            id
          }
        }
        relatedPosts {
          id
          title
          slug
        }
        slug
        creator {
          id
          name
          email
        }
        __typename
      }
    }
  `;

  const UPDATE_POST = gql`
    mutation UpdatePost($input: UpdatePostInput!) {
      updatePost(input: $input) {
        id
        title
        slug
        excerpt
        content
        coverImageUrl
        blogCategoryId
        status
        updatedAt
        tags {
          tag {
            id
          }
        }
        relatedPosts {
          id
          title
          slug
        }
      }
    }
  `;

  const [createPostMutation] = useMutation(CREATE_POST);
  const [updatePostMutation] = useMutation(UPDATE_POST);

  // Query to get all posts for related posts selection
  const { data: allPostsData } = useQuery(GET_ALL_POSTS, {
    fetchPolicy: 'cache-and-network',
  });

  // Auto-generate slug when leaving title field
  const handleTitleBlur = () => {
    if (!formData.slug && formData.title) {
      const slug = generateSlug(formData.title!);
      setFormData((prev) => ({ ...prev, slug }));
      // Pre-validate uniqueness
      (async () => {
        try {
          const existing = await blogApi.getPostBySlug(slug);
          if (existing && existing.id !== initialData?.id) {
            setMessage('El slug ya existe. Modifícalo para que sea único.');
            setMessageType('error');
          }
        } catch (err) {
          // Not found => OK
        }
      })();
    }
  };
  useEffect(() => {
    if (initialData) {
      setFormData({
        title: initialData.title || '',
        excerpt: initialData.excerpt || '',
        slug: initialData.slug || '',
        content: initialData.content || '',
        coverImageUrl: initialData.coverImageUrl || '',
        blogCategoryId: initialData.blogCategory?.id || '',
        tagIds: initialData.tags?.map((t) => t.tag.id) || [],
        relatedPostIds: (initialData as any).relatedPosts?.map((p: any) => p.id || p) || [],
      });

      // Cargar información completa de posts relacionados para edición
      if ((initialData as any).relatedPosts?.length > 0) {
        const relatedPosts = (initialData as any).relatedPosts.filter((p: any) => p.id && p.title);
        setSelectedRelatedPosts(relatedPosts);
      }
    }
  }, [initialData]);

  const handleChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>
  ) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  // Enhanced Rich Text Editor wrapper
  const rteRef = useRef<RichTextEditorRef | null>(null);

  const handleEditorChange = (html: string) => {
    setContentHtml(html);
  };

  // Related posts suggestions - filtrar localmente desde allPosts
  useEffect(() => {
    if (!debouncedRelated || debouncedRelated.length < 2) {
      setRelatedSuggestions([]);
      return;
    }

    const allPosts: BlogPost[] = allPostsData?.posts || [];
    const searchTerm = debouncedRelated.toLowerCase();
    const filtered = allPosts.filter(
      (post: BlogPost) =>
        post.id !== initialData?.id &&
        !formData.relatedPostIds?.includes(post.id!) &&
        (post.title?.toLowerCase().includes(searchTerm) ||
          post.excerpt?.toLowerCase().includes(searchTerm))
    );
    setRelatedSuggestions(filtered.slice(0, 10)); // Limitar a 10 resultados
  }, [debouncedRelated, initialData?.id, formData.relatedPostIds, allPostsData]);

  const handleSubmit = async (status: 'DRAFT' | 'PUBLISHED') => {
    try {
      setIsSaving(true);
      setMessage(null);

      if (!formData.title.trim()) {
        setMessage('Título requerido');
        setMessageType('error');
        setIsSaving(false);
        return;
      }

      // Validation with zod
      const parsed = BlogPostSchema.parse({
        ...formData,
        creatorId: user?.id,
        content: contentHtml || formData.content,
        status,
      });

      let saved: BlogPost;
      if (isEdit && initialData?.id) {
        const res = await updatePostMutation({
          variables: { input: { id: initialData.id, ...parsed } },
        });
        saved = res?.data?.updatePost;
        setMessage('Artículo actualizado correctamente');
      } else {
        const res = await createPostMutation({ variables: { input: parsed } });
        saved = res?.data?.createPost;
        setMessage(
          status === 'DRAFT' ? 'Borrador guardado correctamente' : 'Artículo publicado exitosamente'
        );
      }

      setMessageType('success');
      router.push(`/dashboard/blog`);
    } catch (err: any) {
      console.error(err);
      setMessage(err.message || 'Error al guardar. Intenta nuevamente.');
      setMessageType('error');
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-900 text-gray-200">
      <div className="max-w-4xl mx-auto p-6">
        {/* Header */}
        <div className="flex items-center justify-between mb-8">
          <div className="flex items-center gap-4">
            <button
              onClick={() => router.push('/dashboard/blog')}
              className="p-2 hover:bg-gray-800 rounded-lg transition-colors"
            >
              <ArrowLeft className="w-5 h-5" />
            </button>
            <div>
              <h1 className="text-2xl font-bold">
                {isEdit ? 'Editar artículo' : 'Nuevo artículo'}
              </h1>
              <p className="text-gray-400 text-sm mt-1">
                {isEdit ? 'Modifica tu contenido' : 'Crea contenido increíble'}
              </p>
            </div>
          </div>
        </div>

        {/* Message Alert */}
        {message && (
          <div
            className={`mb-6 p-4 rounded-xl border ${
              messageType === 'error'
                ? 'bg-red-500/10 border-red-500/20 text-red-400'
                : messageType === 'success'
                  ? 'bg-green-500/10 border-green-500/20 text-green-400'
                  : 'bg-blue-500/10 border-blue-500/20 text-blue-400'
            }`}
          >
            <p className="font-medium">{message}</p>
          </div>
        )}

        <div className="space-y-8">
          {/* Title */}
          <div className="space-y-2">
            <label className="block text-sm font-semibold text-gray-300">Título del artículo</label>
            <input
              type="text"
              name="title"
              value={formData.title || ''}
              onChange={handleChange}
              onBlur={handleTitleBlur}
              placeholder="Escribe un título atractivo..."
              className="w-full px-4 py-3 bg-gray-800 border border-gray-600 rounded-xl text-gray-200 placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all"
              required
            />
          </div>

          {/* Slug */}
          <div className="space-y-2">
            <label className="block text-sm font-semibold text-gray-300">URL slug</label>
            <div className="flex items-center">
              <span className="px-3 py-3 bg-gray-800 border border-r-0 border-gray-600 rounded-l-xl text-gray-400 text-sm">
                /blog/
              </span>
              <input
                type="text"
                name="slug"
                value={formData.slug || ''}
                onChange={handleChange}
                placeholder="url-del-articulo"
                className="flex-1 px-4 py-3 bg-gray-800 border border-gray-600 rounded-r-xl text-gray-200 placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all"
              />
            </div>
          </div>

          {/* Excerpt */}
          <div className="space-y-2">
            <label className="block text-sm font-semibold text-gray-300">
              Resumen del artículo
            </label>
            <textarea
              name="excerpt"
              value={formData.excerpt || ''}
              onChange={handleChange}
              placeholder="Escribe un breve resumen del artículo..."
              rows={3}
              className="w-full px-4 py-3 bg-gray-800 border border-gray-600 rounded-xl text-gray-200 placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all resize-none"
            />
            <p className="text-xs text-gray-500">
              Un resumen atractivo que aparecerá en las vistas previas
            </p>
          </div>

          {/* Category and Tags */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {/* Category */}
            <div className="space-y-2">
              <label className="block text-sm font-semibold text-gray-300">Categoría</label>
              <input
                type="text"
                name="blogCategoryId"
                value={formData.blogCategoryId || ''}
                onChange={(e) =>
                  setFormData((prev) => ({ ...prev, blogCategoryId: e.target.value }))
                }
                placeholder="Escribe la categoría (puede ser nueva)"
                className="w-full px-4 py-3 bg-gray-800 border border-gray-600 rounded-xl text-gray-200 placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all"
              />
            </div>

            {/* Tags */}
            <div className="space-y-2">
              <label className="block text-sm font-semibold text-gray-300">Etiquetas</label>
              <input
                type="text"
                name="tags"
                value={(formData.tagIds || []).join(', ')}
                onChange={(e) =>
                  setFormData((prev) => ({
                    ...prev,
                    tagIds: e.target.value
                      .split(',')
                      .map((s) => s.trim())
                      .filter(Boolean),
                  }))
                }
                placeholder="marketing, ecommerce, startups"
                className="w-full px-4 py-3 bg-gray-800 border border-gray-600 rounded-xl text-gray-200 placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all"
              />
              <p className="text-xs text-gray-500">Separa las etiquetas con comas</p>
            </div>
          </div>

          {/* Related posts */}
          <div className="space-y-2">
            <label className="block text-sm font-semibold text-gray-300">
              Artículos relacionados
            </label>
            <div className="relative">
              <input
                type="text"
                value={relatedQuery}
                onChange={(e) => setRelatedQuery(e.target.value)}
                placeholder="Buscar artículos para relacionar..."
                className="w-full px-4 py-3 bg-gray-800 border border-gray-600 rounded-xl text-gray-200 placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all"
              />

              {relatedSuggestions.length > 0 && (
                <div className="absolute top-full left-0 right-0 mt-2 bg-gray-800 border border-gray-600 rounded-xl shadow-xl z-10">
                  {relatedSuggestions.map((post) => (
                    <div
                      key={post.id}
                      className="flex items-center justify-between p-3 hover:bg-gray-700 transition-colors first:rounded-t-xl last:rounded-b-xl"
                    >
                      <span className="text-gray-200">{post.title}</span>
                      <button
                        type="button"
                        onClick={() => {
                          const newPost = post;
                          setFormData((prev) => ({
                            ...prev,
                            relatedPostIds: Array.from(
                              new Set([...(prev.relatedPostIds || []), post.id!])
                            ),
                          }));
                          setSelectedRelatedPosts((prev) => [...prev, newPost]);
                          setRelatedQuery('');
                        }}
                        className="flex items-center gap-1 px-3 py-1 bg-blue-600 hover:bg-blue-700 text-white rounded-lg text-sm transition-colors"
                      >
                        <Plus className="w-3 h-3" />
                        Añadir
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {selectedRelatedPosts && selectedRelatedPosts.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-3">
                {selectedRelatedPosts.map((post) => (
                  <span
                    key={post.id}
                    className="flex items-center gap-2 px-3 py-1 bg-gray-700 text-gray-300 rounded-full text-sm"
                  >
                    {post.title}
                    <button
                      onClick={() => {
                        setFormData((prev) => ({
                          ...prev,
                          relatedPostIds: prev.relatedPostIds?.filter(
                            (postId) => postId !== post.id
                          ),
                        }));
                        setSelectedRelatedPosts((prev) => prev.filter((p) => p.id !== post.id));
                      }}
                      className="text-gray-400 hover:text-red-400 transition-colors"
                    >
                      <X className="w-3 h-3" />
                    </button>
                  </span>
                ))}
              </div>
            )}
          </div>

          {/* Content (RichTextEditor) */}
          <div className="space-y-2">
            <label className="block text-sm font-semibold text-gray-300">
              Contenido del artículo
            </label>
            <div className="md:flex md:gap-4">
              <div className="md:flex-1">
                <RichTextEditor
                  ref={rteRef}
                  value={contentHtml}
                  onChange={(html) => {
                    handleEditorChange(html);
                  }}
                  onKeyDown={() => {}}
                  onSubmit={() => {}}
                  autoFocus={false}
                  placeholder="Escribe el contenido del artículo..."
                  maxHeight="700px"
                />
              </div>
            </div>
          </div>
          <div className="flex items-center gap-4">
            {/* Cover Image */}
            <div className="space-y-2">
              <label className="block text-sm font-semibold text-gray-300">Imagen de portada</label>
              <FileUpload
                onFile={(url) => setFormData((prev) => ({ ...prev, coverImageUrl: url }))}
                initialImage={formData.coverImageUrl}
              />
            </div>
          </div>

          {/* Action Buttons */}
          <div className="flex items-center justify-between pt-6 border-t border-gray-700">
            <button
              type="button"
              onClick={() => router.push('/dashboard/blog')}
              className="px-6 py-2 text-gray-400 hover:text-gray-300 transition-colors"
            >
              Cancelar
            </button>

            <div className="flex items-center gap-3">
              <button
                type="button"
                disabled={isSaving}
                onClick={() => handleSubmit('DRAFT')}
                className="flex items-center gap-2 px-6 py-3 bg-gray-700 hover:bg-gray-600 text-gray-200 rounded-xl font-medium transition-all disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <Save className="w-4 h-4" />
                {isSaving ? 'Guardando...' : 'Guardar borrador'}
              </button>

              <button
                type="button"
                disabled={isSaving}
                onClick={() => handleSubmit('PUBLISHED')}
                className="flex items-center gap-2 px-6 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-medium transition-all disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <Send className="w-4 h-4" />
                {isSaving ? 'Publicando...' : isEdit ? 'Actualizar' : 'Publicar'}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

'use client';
import React, {
  useRef,
  useEffect,
  useState,
  KeyboardEvent,
  forwardRef,
  useImperativeHandle,
  useCallback,
} from 'react';
import './RichTextEditor.scss';
import classNames from 'classnames';
import {
  Bold as IconRTEBold,
  Italic as IconRTEItalic,
  Underline as IconRTEUnderline,
  Strikethrough as IconRTECrossed,
  List as IconRTEUL,
  ListOrdered as IconRTEOL,
  Link as IconRTELink,
} from 'lucide-react';

import DOMPurify from 'dompurify';
import { mentionUtils } from '@/lib/blog/mentionUtils';

export interface RichTextEditorRef {
  insertText: (text: string) => void;
  focus: () => void;
  submit: () => void;
  KAI: (text: string) => void;
  getEditor: () => HTMLDivElement | null;
  setValue: (html: string) => void;
  getValue: () => string;
  setSelection: (selection: Selection) => void;
  getSelection: () => Selection | Range;
  posFromIndex: (index: number) => number;
  replaceMention: (startPos: number, length: number, mentionHtml: string) => void;
  getCursorPosition: () => number;
  getAllMentions: () => string[];
}

interface RichTextEditorProps {
  value: string;
  onChange: (value: string, plainText: string, mentions?: string[]) => void;
  onKeyDown: (e: React.KeyboardEvent<HTMLDivElement>) => void;
  onSubmit: () => void;
  placeholder?: string;
  className?: string;
  autoFocus?: boolean;
  maxHeight?: string;
  toolbar?: boolean;
  getEditor?: (editor: HTMLDivElement | null) => void;
  setValue?: (html: string) => void;
  isUserSearchOpen?: boolean;
  onMentionDetected?: (mentions: any[]) => void;
}

let isUpdating = false;

const RichTextEditor = forwardRef<RichTextEditorRef, RichTextEditorProps>(
  (
    {
      value,
      onChange,
      onKeyDown,
      onSubmit,
      placeholder = 'Write your message...',
      className = '',
      autoFocus = false,
      maxHeight = '250px',
      toolbar = true,
      getEditor,
      isUserSearchOpen = false,
      onMentionDetected,
    },
    ref
  ) => {
    const editorRef = useRef<HTMLDivElement>(null);
    const [showPlaceholder, setShowPlaceholder] = useState(!value);
    const operationInProgressRef = useRef(false);
    const lastKnownSelectionRef = useRef<Range | null>(null);

    const purifyConfig = {
      ALLOWED_TAGS: [
        'b',
        'i',
        'em',
        'strong',
        'u',
        'a',
        'ul',
        'ol',
        'li',
        'p',
        'br',
        'strike',
        'del',
        'div',
      ],
      ALLOWED_ATTR: ['href', 'target', 'rel', 'style', 'class', 'data-mention'],
      ADD_ATTR: ['target', 'rel', 'data-mention'],
      KEEP_CONTENT: true,
    };

    const [activeFormats, setActiveFormats] = useState({
      bold: false,
      italic: false,
      underline: false,
      strikeThrough: false,
      ul: false,
      ol: false,
    });

    /**
     * Enhanced formatMentions function using our utility
     */
    const formatMentions = useCallback((content: string, skipAutoFormat: boolean = false) => {
      if (skipAutoFormat) {
        return content;
      }
      return mentionUtils.formatMentionsToHtml(content);
    }, []);

    const checkFormatting = useCallback(() => {
      const selection = window.getSelection();
      if (!selection || !selection.rangeCount) return;

      const range = selection.getRangeAt(0);
      let container = range.commonAncestorContainer;

      if (container.nodeType === Node.TEXT_NODE) {
        container = container.parentNode as Node;
      }

      let currentNode = container as HTMLElement;
      const formats = {
        bold: false,
        italic: false,
        underline: false,
        strikeThrough: false,
        ul: false,
        ol: false,
      };

      while (currentNode && currentNode !== editorRef.current) {
        const nodeName = currentNode.nodeName.toLowerCase();

        if (
          nodeName === 'b' ||
          nodeName === 'strong' ||
          (currentNode.style && currentNode.style.fontWeight === 'bold') ||
          (currentNode.style && parseInt(currentNode.style.fontWeight, 10) >= 700)
        ) {
          formats.bold = true;
        }

        if (
          nodeName === 'i' ||
          nodeName === 'em' ||
          (currentNode.style && currentNode.style.fontStyle === 'italic')
        ) {
          formats.italic = true;
        }

        if (
          nodeName === 'u' ||
          (currentNode.style && currentNode.style.textDecoration === 'underline')
        ) {
          formats.underline = true;
        }

        if (
          nodeName === 's' ||
          nodeName === 'strike' ||
          nodeName === 'del' ||
          (currentNode.style &&
            (currentNode.style.textDecoration === 'line-through' ||
              currentNode.style.textDecoration.includes('line-through')))
        ) {
          formats.strikeThrough = true;
        }

        if (nodeName === 'ul') {
          formats.ul = true;
        }
        if (nodeName === 'ol') {
          formats.ol = true;
        }

        currentNode = currentNode.parentNode as HTMLElement;
      }

      setActiveFormats(formats);
    }, []);

    const handleAutoGrow = () => {
      if (editorRef.current) {
        // Get the minimum height from CSS (80px as defined in SCSS)
        const minHeightPx = 80;

        // Store the current height before changing it
        const currentHeight = editorRef.current.offsetHeight;

        // Temporarily set height to auto to measure scroll height
        const originalHeight = editorRef.current.style.height;
        editorRef.current.style.height = 'auto';
        const scrollHeight = editorRef.current.scrollHeight;

        // Reset to original height immediately to prevent flicker
        editorRef.current.style.height = originalHeight;

        const maxHeightPx = parseInt(maxHeight.replace('px', ''), 10);

        // Calculate the new height, ensuring it never goes below minimum
        const newHeight = Math.max(Math.min(scrollHeight, maxHeightPx), minHeightPx);

        // Only update if the height actually needs to change
        if (newHeight !== currentHeight) {
          editorRef.current.style.height = `${newHeight}px`;
          editorRef.current.style.overflowY = scrollHeight > maxHeightPx ? 'auto' : 'hidden';
        }
      }
    };

    const insertAtCursor = (html: string) => {
      if (!editorRef.current) return;

      const selection = window.getSelection();
      if (!selection || !selection.rangeCount) return;

      const range = selection.getRangeAt(0);
      if (!editorRef.current.contains(range.commonAncestorContainer)) {
        editorRef.current.focus();
        const newRange = document.createRange();
        newRange.setStart(editorRef.current, 0);
        newRange.setEnd(editorRef.current, 0);
        selection.removeAllRanges();
        selection.addRange(newRange);
      }

      operationInProgressRef.current = true;
      document.execCommand('insertHTML', false, html);

      setTimeout(() => {
        const rawHtmlContent = editorRef?.current?.innerHTML || '';
        const sanitizedHtml = DOMPurify.sanitize(rawHtmlContent, purifyConfig);
        const plainText = editorRef?.current?.textContent || '';
        const formattedHtml = formatMentions(sanitizedHtml, isUserSearchOpen);
        const mentions = mentionUtils.extractUserIdsFromHtml(formattedHtml);
        onChange(formattedHtml, plainText, mentions);
        operationInProgressRef.current = false;
        handleAutoGrow();
      }, 10);
    };

    const withOperation = (callback: () => void) => {
      operationInProgressRef.current = true;
      callback();
      setTimeout(() => {
        operationInProgressRef.current = false;
      }, 10);
    };

    /**
     * Enhanced replaceMentionInEditor using our utility
     */
    const replaceMentionInEditor = (startPos: number, length: number, mentionHtml: string) => {
      if (!editorRef.current) return;

      try {
        const currentHtml = editorRef.current.innerHTML;
        const newHtml = mentionUtils.replaceMentionAtPosition(
          currentHtml,
          startPos,
          length,
          mentionHtml.match(/data-mention="([^"]*)"?/)?.[1] || '',
          mentionHtml.match(/>@([^<]*)</)?.[1] || ''
        );

        editorRef.current.innerHTML = newHtml;
        editorRef.current.focus();

        setTimeout(() => {
          updateContent();
        }, 10);
      } catch (error) {
        console.error('Error replacing mention:', error);
        insertAtCursor(mentionHtml + ' ');
      }
    };

    // Enhanced ref methods
    useImperativeHandle(ref, () => ({
      insertText: (text: string) => {
        editorRef.current?.focus();

        if (lastKnownSelectionRef.current) {
          const selection = window.getSelection();
          if (selection) {
            try {
              selection.removeAllRanges();
              selection.addRange(lastKnownSelectionRef.current);
            } catch (e) {
              console.error('Failed to restore selection:', e);
            }
          }
        }

        const safeText = DOMPurify.sanitize(text, purifyConfig);
        insertAtCursor(safeText);
      },
      focus: () => {
        editorRef.current?.focus();
      },
      submit: () => {
        setTimeout(() => {
          if (editorRef.current) {
            editorRef.current.innerHTML = '';
            setShowPlaceholder(value === '' || value === '<br>');
            editorRef.current.focus();
          }
        }, 10);
      },
      KAI: (text: string) => {
        editorRef.current?.focus();
        if (editorRef.current) {
          editorRef.current.innerHTML = '';
          const safeText = DOMPurify.sanitize(text, purifyConfig);
          insertAtCursor(safeText);
        }
      },
      getEditor: () => editorRef.current,
      setValue: (html: string) => {
        if (editorRef.current) {
          const sanitizedHtml = DOMPurify.sanitize(html, purifyConfig);
          editorRef.current.innerHTML = sanitizedHtml;
          updateContent();
        }
      },
      setSelection: (selection: Selection) => {
        if (selection.rangeCount > 0 && editorRef.current) {
          const range = selection.getRangeAt(0);
          if (editorRef.current.contains(range.commonAncestorContainer)) {
            const newSelection = window.getSelection();
            newSelection?.removeAllRanges();
            newSelection?.addRange(range);
          }
        }
      },
      getSelection: () => {
        return window.getSelection() || document.createRange();
      },
      getValue: () => {
        return editorRef.current?.innerHTML || '';
      },
      posFromIndex: (index: number) => {
        if (!editorRef.current) return 0;
        mentionUtils.setCursorPosition(editorRef.current, index);
        return index;
      },
      replaceMention: (startPos: number, length: number, mentionHtml: string) => {
        replaceMentionInEditor(startPos, length, mentionHtml);
      },
      getCursorPosition: () => {
        return mentionUtils.getCursorPosition(editorRef.current);
      },
      getAllMentions: () => {
        return mentionUtils.extractUserIdsFromHtml(editorRef.current?.innerHTML || '');
      },
    }));

    const ensureLinkStyling = () => {
      if (!editorRef.current) return;
      const links = editorRef.current.querySelectorAll('a[href]:not(.rte-link)');
      links.forEach((link) => {
        link.classList.add('rte-link');
        link.setAttribute('target', '_blank');
        link.setAttribute('rel', 'noopener noreferrer');
      });
    };

    const updateContent = () => {
      if (!editorRef.current || isUpdating) return;

      isUpdating = true;

      if (operationInProgressRef.current) {
        isUpdating = false;
        return;
      }

      try {
        const rawHtmlContent = editorRef.current.innerHTML;
        const mentionsFormattedValue = formatMentions(rawHtmlContent, isUserSearchOpen);
        const sanitizedHtml = DOMPurify.sanitize(mentionsFormattedValue, purifyConfig);

        // Extract mentions for callback
        const mentions = mentionUtils.extractUserIdsFromHtml(sanitizedHtml);
        const allMentions = mentionUtils.extractAllMentions(editorRef.current.textContent || '');

        // Call mention detected callback
        if (onMentionDetected) {
          onMentionDetected(allMentions);
        }

        if (sanitizedHtml !== rawHtmlContent) {
          const selection = window.getSelection();
          let selectionSaved = false;
          let startContainer: Node | null = null;
          let startOffset = 0;
          let endContainer: Node | null = null;
          let endOffset = 0;

          if (selection && selection.rangeCount > 0) {
            const range = selection.getRangeAt(0);
            if (editorRef.current.contains(range.startContainer)) {
              startContainer = range.startContainer;
              startOffset = range.startOffset;
              endContainer = range.endContainer;
              endOffset = range.endOffset;
              selectionSaved = true;
            }
          }

          editorRef.current.innerHTML = sanitizedHtml;

          if (selectionSaved && selection && startContainer && endContainer) {
            try {
              const hadFocus = document.activeElement === editorRef.current;
              const newRange = document.createRange();
              newRange.setStart(startContainer, startOffset);
              newRange.setEnd(endContainer, endOffset);
              selection.removeAllRanges();
              selection.addRange(newRange);

              if (hadFocus) {
                editorRef.current.focus();
                setTimeout(() => {
                  if (editorRef.current) {
                    editorRef.current.focus();
                    try {
                      selection.removeAllRanges();
                      selection.addRange(newRange);
                    } catch (e) {
                      console.error('Failed to restore selection after timeout:', e);
                    }
                  }
                }, 0);
              }
            } catch (e) {
              console.error('Failed to restore selection:', e);
              editorRef.current.focus();
            }
          }
        }

        ensureLinkStyling();

        const isEmpty =
          editorRef.current.innerHTML === '' || editorRef.current.innerHTML === '<br>';
        setShowPlaceholder(isEmpty);

        const plainText = editorRef.current.textContent || '';
        onChange(sanitizedHtml, plainText, mentions);

        handleAutoGrow();
      } finally {
        isUpdating = false;
      }
    };

    // Rest of your component methods (execCommand, handleBold, etc.)...
    const execCommand = (command: string, value: string = '') => {
      withOperation(() => {
        editorRef.current?.focus();
        document.execCommand(command, false, value);

        const rawHtmlContent = editorRef?.current?.innerHTML || '';
        const sanitizedHtml = DOMPurify.sanitize(rawHtmlContent, purifyConfig);
        const plainText = editorRef?.current?.textContent || '';
        const mentions = mentionUtils.extractUserIdsFromHtml(sanitizedHtml);
        onChange(sanitizedHtml, plainText, mentions);
        updateContent();
      });
    };

    const handleBold = () => execCommand('bold');
    const handleItalic = () => execCommand('italic');
    const handleUnderline = () => execCommand('underline');
    const handleStrikethrough = () => execCommand('strikeThrough');
    const handleOrderedList = () => execCommand('insertOrderedList');
    const handleUnorderedList = () => execCommand('insertUnorderedList');

    const handleLink = () => {
      const selection = window.getSelection();
      const hasSelection = selection && selection.toString().trim() !== '';
      const url = prompt('Enter URL:', 'https://');
      if (!url) return;

      let formattedUrl = url;
      if (!/^https?:\/\//i.test(url)) {
        formattedUrl = 'https://' + url;
      }

      withOperation(() => {
        if (hasSelection) {
          execCommand('createLink', formattedUrl);
          if (selection && selection.rangeCount) {
            const range = selection.getRangeAt(0);
            const linkNode = range.commonAncestorContainer.parentElement;
            if (linkNode && linkNode.tagName === 'A') {
              linkNode.className = 'rte-link';
              linkNode.setAttribute('target', '_blank');
              linkNode.setAttribute('rel', 'noopener noreferrer');
            }
          }
        } else {
          const linkText = new URL(formattedUrl).hostname;
          const linkHtml = `<a href="${formattedUrl}" class="rte-link" target="_blank" rel="noopener noreferrer">${linkText}</a>`;
          insertAtCursor(linkHtml);
        }
      });
    };

    const handlePaste = (e: React.ClipboardEvent<HTMLDivElement>) => {
      e.preventDefault();

      let pastedText = '';
      if (e.clipboardData) {
        pastedText = e.clipboardData.getData('text/plain');
      }

      withOperation(() => {
        const isEmoji = /^\p{Emoji}+$/u.test(pastedText);

        if (isEmoji) {
          insertAtCursor(pastedText);
          return;
        }

        if (/^https?:\/\/\S+$/.test(pastedText.trim())) {
          const url = pastedText.trim();
          try {
            const linkText = new URL(url).hostname;
            const linkHtml = `<a href="${url}" class="rte-link" target="_blank" rel="noopener noreferrer">${linkText}</a>`;
            insertAtCursor(linkHtml);
          } catch (e) {
            insertAtCursor(pastedText);
          }
        } else {
          insertAtCursor(pastedText);
        }
      });
    };

    const handleKeyDown = (e: KeyboardEvent<HTMLDivElement>) => {
      e.stopPropagation();
      if (onKeyDown) {
        onKeyDown(e);
      }

      // Let the parent component handle Shift+Enter submission
      // Remove duplicate handling to prevent double submission
    };

    const handleFocus = () => {
      setShowPlaceholder(false);
    };

    const handleBlur = (e: React.FocusEvent<HTMLDivElement>) => {
      const selection = window.getSelection();
      if (selection && selection.rangeCount > 0) {
        lastKnownSelectionRef.current = selection.getRangeAt(0).cloneRange() || null;
      }

      if (editorRef.current) {
        const isEmpty =
          editorRef.current.innerHTML === '' || editorRef.current.innerHTML === '<br>';
        setShowPlaceholder(isEmpty);
      }
    };

    // Initialize editor
    useEffect(() => {
      if (editorRef.current) {
        if (value) {
          const mentionFormattedValue = formatMentions(value, false);
          const sanitizedValue = DOMPurify.sanitize(mentionFormattedValue, purifyConfig);
          editorRef.current.innerHTML = sanitizedValue;
          if (sanitizedValue !== value) {
            const mentions = mentionUtils.extractUserIdsFromHtml(sanitizedValue);
            onChange(sanitizedValue, editorRef.current.textContent || '', mentions);
          }
        }

        handleAutoGrow();

        const observer = new MutationObserver(() => {
          if (!operationInProgressRef.current) {
            ensureLinkStyling();
          }
        });

        observer.observe(editorRef.current, {
          childList: true,
          subtree: true,
          characterData: true,
        });

        return () => observer.disconnect();
      }
    }, []);

    useEffect(() => {
      if (autoFocus && editorRef.current) {
        editorRef.current.focus();
      }
    }, [autoFocus]);

    useEffect(() => {
      if (getEditor && editorRef.current) {
        getEditor(editorRef.current);
      }
    }, [getEditor]);

    useEffect(() => {
      const handleSelectionChange = () => {
        if (document.activeElement === editorRef.current) {
          checkFormatting();
        }
      };

      document.addEventListener('selectionchange', handleSelectionChange);

      const handleFocusEvent = () => {
        checkFormatting();
      };

      if (editorRef.current) {
        editorRef.current.addEventListener('focus', handleFocusEvent);
      }

      return () => {
        document.removeEventListener('selectionchange', handleSelectionChange);
        if (editorRef.current) {
          editorRef.current.removeEventListener('focus', handleFocusEvent);
        }
      };
    }, [checkFormatting]);

    return (
      <div className={`rich-text-editor ${className}`}>
        {toolbar && (
          <div className="rich-text-toolbar">
            <div className="rich-text-toolbar-group">
              <button
                type="button"
                className={`toolbar-button ${activeFormats.bold ? 'active' : ''}`}
                onClick={handleBold}
                title="Bold"
              >
                <IconRTEBold />
              </button>
              <button
                type="button"
                className={`toolbar-button ${activeFormats.italic ? 'active' : ''}`}
                onClick={handleItalic}
                title="Italic"
              >
                <IconRTEItalic />
              </button>
              <button
                type="button"
                className={`toolbar-button ${activeFormats.underline ? 'active' : ''}`}
                onClick={handleUnderline}
                title="Underline"
              >
                <IconRTEUnderline />
              </button>
              <button
                type="button"
                className={`toolbar-button ${activeFormats.strikeThrough ? 'active' : ''}`}
                onClick={handleStrikethrough}
                title="Strikethrough"
              >
                <IconRTECrossed />
              </button>
            </div>
            <div className="rich-text-toolbar-group">
              <button
                type="button"
                className={`toolbar-button ${activeFormats.ul ? 'active' : ''}`}
                onClick={handleUnorderedList}
                title="Unordered List"
              >
                <IconRTEUL />
              </button>
              <button
                type="button"
                className={`toolbar-button ${activeFormats.ol ? 'active' : ''}`}
                onClick={handleOrderedList}
                title="Ordered List"
              >
                <IconRTEOL />
              </button>
            </div>

            <button type="button" className="toolbar-button" onClick={handleLink} title="Add URL">
              <IconRTELink />
            </button>
          </div>
        )}

        <div
          className={classNames('rich-text-content', { 'show-placeholder': showPlaceholder })}
          ref={editorRef}
          contentEditable={true}
          onInput={updateContent}
          onPaste={handlePaste}
          onKeyDown={handleKeyDown}
          onFocus={handleFocus}
          onBlur={handleBlur}
          data-placeholder={placeholder}
          style={{
            minHeight: '80px',
            maxHeight: maxHeight,
            overflow: 'hidden',
          }}
        />
      </div>
    );
  }
);

