        </div>
      </div>

      {/* Tabla */}
      {/* Tabla Desktop / Cards Mobile */}
      {/* Desktop Table */}
      <div className="hidden md:block bg-slate-800 border border-slate-700 rounded-xl overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
