            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {[
                { name: 'code', label: 'Código *', placeholder: 'VERANO2024' },
                { name: 'name', label: 'Nombre *', placeholder: 'Descuento de verano' },
