                  </label>
                  <input
                    type="number"
                    value={newMenuItem.price}
                    onChange={(e) =>
                      setNewMenuItem((p: any) => ({
                        ...p,
                        price: parseFloat(e.target.value || '0'),
                      }))
                    }
                    className={inputClassName}
                    placeholder="0.00"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
