                      >
                        Eliminar
                      </button>
                    </div>
                  ) : (
                    <FileUpload
                      onFile={(url) => setNewMenuItem((p: any) => ({ ...p, imageUrl: url }))}
                      accept="image/*"
                    />
                  )}
                </div>
                <div className="flex items-center gap-3">
                  <label className="flex items-center cursor-pointer">
                    <input
