    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>
  ) => {
    const { name, value } = e.target;
    setFormData((prev: any) => ({ ...prev, [name]: value }));
  };

  const handleSave = async () => {
    setSaveStatus('saving');
    try {
      const {
        id,
        brandingId,
        businessConfigId,
        createdAt,
        updatedAt,
        slug,
        __typename,
        ...inputData
      } = formData;

      await updateService({
        variables: {
          id: serviceId,
          data: inputData,
        },
      });

