                aria-label={`Restaurar categoría ${category.name}`}
              >
                <RotateCcw className="h-4 w-4" />
              </button>
            )}

            {/* Botón crear subcategoría (solo hasta nivel 2) */}
            {canCreateSubcategory && (
              <button
                onClick={() => onCreateSubcategory(category)}
                className="text-gray-400 hover:text-blue-600 dark:hover:text-blue-400 transition-colors"
                aria-label={`Crear subcategoría de ${category.name}`}
              >
                <Plus className="h-4 w-4" />
              </button>
            )}

            <button
              onClick={() => onHardDelete(category)}
              className="text-gray-400 hover:text-red-600 dark:hover:text-red-400 transition-colors"
              aria-label={`Eliminar permanentemente categoría ${category.name}`}
            >
              <Trash2 className="h-4 w-4" />
            </button>
          </div>
        </td>
      </tr>

      {/* Renderizar hijos si está expandido y hay hijos */}
      {isExpanded && category.children && category.children.length > 0 && (
        <>
          {category.children.map((child) => (
            <CategoryRow
              key={child.id}
              category={child}
              onEdit={onEdit}
              onSoftDelete={onSoftDelete}
              onHardDelete={onHardDelete}
              onRestore={onRestore}
              onCreateSubcategory={onCreateSubcategory}
              onDragStart={onDragStart}
              onDragOver={onDragOver}
              onDragLeave={onDragLeave}
              onDrop={onDrop}
              onDragEnd={onDragEnd}
              isExpanded={isExpanded}
              onToggleExpand={onToggleExpand}
              depth={depth + 1}
            />
          ))}
        </>
      )}
    </>
  );
};

export default function CategoriesPage() {
  const [statusFilter, setStatusFilter] = useState<'all' | 'active' | 'deleted'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingCategory, setEditingCategory] = useState<Category | null>(null);
  const [preselectedParent, setPreselectedParent] = useState<Category | null>(null);
  const [deleteModal, setDeleteModal] = useState<{
    isOpen: boolean;
    category: Category | null;
    isHardDelete: boolean;
  }>({ isOpen: false, category: null, isHardDelete: false });
  const userData = JSON.parse(localStorage.getItem('user') || '{}');

  const [draggedItem, setDraggedItem] = useState<Category | null>(null);
  const [draggedOverItem, setDraggedOverItem] = useState<Category | null>(null);
  const [expandedIds, setExpandedIds] = useState<Set<string>>(new Set());

  const toggleExpand = (id: string) => {
    setExpandedIds((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const {
    data: categoriesData,
    loading,
    error,
    refetch,
  } = useQuery(GET_CATEGORIES_BY_STORE, {
    variables: { storeId: userData?.storeId },
    skip: !userData?.storeId,
    errorPolicy: 'all',
  });

  const [softDeleteCategory] = useMutation(SOFT_DELETE_CATEGORY);
  const [deleteCategory] = useMutation(DELETE_CATEGORY);
  const [updateCategory] = useMutation(UPDATE_CATEGORY);
  const [reorderCategories] = useMutation(REORDER_CATEGORIES);

  const categories: Category[] = useMemo(() => {
    return categoriesData?.categories || categoriesData?.categoriesByStore || [];
  }, [categoriesData]);

  // Construir árbol de categorías jerárquico
  const buildCategoryTree = (categoriesList: Category[]): Category[] => {
    const categoryMap = new Map<string, Category>();
    const roots: Category[] = [];

    // Primero, crear un mapa de todas las categorías
    categoriesList.forEach((category) => {
      categoryMap.set(category.id, { ...category, children: [] });
    });

    // Luego, construir la jerarquía
    categoriesList.forEach((category) => {
      const node = categoryMap.get(category.id)!;
      if (category.parent?.id && categoryMap.has(category.parent.id)) {
        const parent = categoryMap.get(category.parent.id)!;
        if (!parent.children) parent.children = [];
        parent.children.push(node);
        // Ordenar hijos por order
        parent.children.sort((a, b) => a.order - b.order);
      } else {
        roots.push(node);
      }
    });

    // Ordenar raíces por order
    return roots.sort((a, b) => a.order - b.order);
  };

  // Filtered categories
  const filteredCategories = useMemo(() => {
    const filtered = categories.filter((category) => {
      const matchesSearch =
        category.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        (category.slug && category.slug.toLowerCase().includes(searchTerm.toLowerCase()));

      const matchesStatus =
        statusFilter === 'all' ||
        (statusFilter === 'active' && category.isActive) ||
        (statusFilter === 'deleted' && !category.isActive);

      return matchesSearch && matchesStatus;
    });

    return buildCategoryTree(filtered);
  }, [categories, searchTerm, statusFilter]);

  // Función recursiva para renderizar tarjetas en móvil
  const renderCategoryCards = (categoryList: Category[], depth = 0) => {
    return categoryList.map((category) => {
      const isExpanded = expandedIds.has(category.id);

      return (
        <div key={category.id} className="space-y-3">
          <CategoryCard
            category={category}
            onEdit={handleEditCategory}
            onSoftDelete={handleSoftDelete}
            onHardDelete={handleHardDelete}
            onRestore={handleRestoreCategory}
            onCreateSubcategory={handleCreateSubcategory}
            onDragStart={handleDragStart}
            onDragOver={handleDragOver}
            onDragLeave={handleDragLeave}
            onDrop={handleDrop}
            onDragEnd={handleDragEnd}
            isDraggedOver={draggedOverItem?.id === category.id}
            isExpanded={isExpanded}
            onToggleExpand={toggleExpand}
            depth={depth}
          />

          {/* Renderizar hijos si está expandido */}
          {isExpanded && category.children && category.children.length > 0 && (
            <div className="space-y-3">{renderCategoryCards(category.children, depth + 1)}</div>
          )}
        </div>
      );
    });
  };

  // Función recursiva para renderizar filas en desktop
  const renderCategoryRows = (categoryList: Category[], depth = 0) => {
    return categoryList.map((category) => (
      <CategoryRow
        key={category.id}
        category={category}
        onEdit={handleEditCategory}
        onSoftDelete={handleSoftDelete}
        onHardDelete={handleHardDelete}
        onRestore={handleRestoreCategory}
        onCreateSubcategory={handleCreateSubcategory}
        onDragStart={handleDragStart}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
        onDragEnd={handleDragEnd}
        isExpanded={expandedIds.has(category.id)}
        onToggleExpand={toggleExpand}
        depth={depth}
      />
    ));
  };

  // Handlers (se mantienen igual)
  const handleCreateCategory = () => {
    setEditingCategory(null);
    setPreselectedParent(null);
    setIsModalOpen(true);
  };

  const handleCreateSubcategory = (parentCategory: Category) => {
    // Verificar que no se exceda el límite de 3 niveles
    let current = parentCategory;
    let depth = 1; // Ya estamos en al menos nivel 1

    while (current.parent) {
      depth++;
      if (depth >= 3) {
        toast.error('No se pueden crear más de 3 niveles de subcategorías', {
          style: {
            background: '#fef3c7',
            color: '#d97706',
            border: '1px solid #fde68a',
          },
        });
        return;
      }
      current = current.parent as Category;
    }

    setEditingCategory(null);
    setPreselectedParent(parentCategory);
    setIsModalOpen(true);
  };

  const handleEditCategory = (category: Category) => {
    setEditingCategory(category);
    setPreselectedParent(null);
    setIsModalOpen(true);
  };

  const handleSoftDelete = (category: Category) => {
    setDeleteModal({
      isOpen: true,
      category,
      isHardDelete: false,
    });
  };

  const handleHardDelete = (category: Category) => {
    setDeleteModal({
      isOpen: true,
      category,
      isHardDelete: true,
    });
  };

  const handleRestoreCategory = async (category: Category) => {
    try {
      await updateCategory({
        variables: {
          id: category.id,
          input: {
            isActive: true,
          },
        },
      });
      toast.success('Categoría restaurada exitosamente');
      refetch();
    } catch (error: any) {
      const errorMessage =
        error?.graphQLErrors?.[0]?.message || error?.message || 'Error al restaurar la categoría';

      if (
        errorMessage.toLowerCase().includes('permission') ||
        errorMessage.toLowerCase().includes('unauthorized') ||
        errorMessage.toLowerCase().includes('forbidden')
      ) {
        toast.error('No tienes permisos para restaurar esta categoría', {
          style: {
            background: '#fef3c7',
            color: '#d97706',
            border: '1px solid #fde68a',
          },
        });
      } else {
        toast.error(errorMessage, {
          style: {
            background: '#fee2e2',
            color: '#dc2626',
            border: '1px solid #fca5a5',
          },
        });
      }
    }
  };

  // Drag and Drop handlers
  const handleDragStart = (e: React.DragEvent, category: Category) => {
    setDraggedItem(category);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent, category: Category) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
    setDraggedOverItem(category);
  };

  const handleDragLeave = () => {
    setDraggedOverItem(null);
  };

  const handleDrop = async (e: React.DragEvent, dropTarget: Category) => {
    e.preventDefault();
    if (draggedItem?.parent || dropTarget?.parent) {
      toast.error('Solo se pueden reordenar las categorías de primer nivel', {
        style: {
          background: '#fef3c7',
          color: '#d97706',
          border: '1px solid #fde68a',
        },
      });
      setDraggedItem(null);
      setDraggedOverItem(null);
      return;
    }

    if (!draggedItem || draggedItem.id === dropTarget.id) {
      setDraggedItem(null);
      setDraggedOverItem(null);
      return;
    }

    // Only allow reordering within the same store and same status (active/inactive)
    if (
      draggedItem.store?.id !== dropTarget.store?.id ||
      draggedItem.isActive !== dropTarget.isActive
    ) {
      toast.error('Solo puedes reordenar categorías dentro de la misma tienda y estado', {
        style: {
          background: '#fef3c7',
          color: '#d97706',
          border: '1px solid #fde68a',
        },
      });
      setDraggedItem(null);
      setDraggedOverItem(null);
      return;
    }

    try {
      // Get all categories for the same store and status, sorted by current order
      // Reorder only among categories that belong to the same store, same active state,
      // and the same parent (so subcategories reorder within their parent).
      const draggedParentId = draggedItem.parent?.id || null;
      const sameStoreCategories = filteredCategories
        .filter((cat) => {
          const parentId = cat.parent?.id || null;
          return (
            cat.store?.id === draggedItem.store?.id &&
            cat.isActive === draggedItem.isActive &&
            parentId === draggedParentId
          );
        })
        .sort((a, b) => a.order - b.order);

      // Find positions
      const draggedIndex = sameStoreCategories.findIndex((cat) => cat.id === draggedItem.id);
      const targetIndex = sameStoreCategories.findIndex((cat) => cat.id === dropTarget.id);

      if (draggedIndex === -1 || targetIndex === -1) return;

      // Create new array with reordered items
      const reorderedCategories = [...sameStoreCategories];
      const [removed] = reorderedCategories.splice(draggedIndex, 1);
      reorderedCategories.splice(targetIndex, 0, removed);

      // Create the category orders array for the mutation
      const categoryOrders = reorderedCategories.map((category, index) => ({
        id: category.id,
        order: index + 1,
      }));

      // Execute the reorder mutation
      await reorderCategories({
        variables: {
          storeId: draggedItem.store?.id || userData?.storeId,
          categoryOrders,
        },
      });

      toast.success('Categorías reordenadas exitosamente');
      refetch();
    } catch (error: any) {
      const errorMessage =
        error?.graphQLErrors?.[0]?.message || error?.message || 'Error al reordenar categorías';
      toast.error(errorMessage, {
        style: {
          background: '#fee2e2',
          color: '#dc2626',
          border: '1px solid #fca5a5',
        },
      });
    } finally {
      setDraggedItem(null);
      setDraggedOverItem(null);
    }
  };

  const handleDragEnd = () => {
    setDraggedItem(null);
    setDraggedOverItem(null);
  };

  const confirmDelete = async () => {
    if (!deleteModal.category) return;

    try {
      if (deleteModal.isHardDelete) {
        await deleteCategory({
          variables: { id: deleteModal.category.id },
        });
        toast.success('Categoría eliminada permanentemente');
      } else {
        await softDeleteCategory({
          variables: { id: deleteModal.category.id },
        });
        toast.success('Categoría archivada exitosamente');
      }

      refetch();
      setDeleteModal({ isOpen: false, category: null, isHardDelete: false });
    } catch (error: any) {
      const errorMessage =
        error?.graphQLErrors?.[0]?.message || error?.message || 'Error al procesar la operación';

      // Handle specific error messages
      if (errorMessage.includes('Cannot delete category with active subcategories')) {
        toast.error(
          `No se puede eliminar la categoría "${deleteModal.category.name}" porque tiene subcategorías activas. Elimina las subcategorías primero.`,
          {
            style: {
              background: '#fee2e2',
              color: '#dc2626',
              border: '1px solid #fca5a5',
            },
          }
        );
      } else if (
        errorMessage.toLowerCase().includes('productos asociados') ||
        errorMessage.toLowerCase().includes('has products') ||
        (errorMessage.toLowerCase().includes('cannot delete') &&
          errorMessage.toLowerCase().includes('products'))
      ) {
        toast.error(
          `No se puede eliminar la categoría "${deleteModal.category.name}" porque tiene productos asociados. Reasigna o elimina los productos primero.`,
          {
            style: {
              background: '#fef3c7',
              color: '#d97706',
              border: '1px solid #fde68a',
            },
          }
        );
      } else if (
        errorMessage.toLowerCase().includes('constraint') ||
        errorMessage.toLowerCase().includes('foreign key')
      ) {
        toast.error(
          `No se puede eliminar la categoría "${deleteModal.category.name}" debido a restricciones de integridad. Verifica que no tenga elementos dependientes.`,
          {
            style: {
              background: '#fee2e2',
              color: '#dc2626',
              border: '1px solid #fca5a5',
            },
          }
        );
      } else {
        toast.error(errorMessage, {
          style: {
            background: '#fee2e2',
            color: '#dc2626',
            border: '1px solid #fca5a5',
          },
        });
      }
    }
  };

  const handleModalSuccess = () => {
    refetch();
  };

  // Loading state
  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 dark:bg-gray-900 p-4 sm:p-6 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
          <p className="text-gray-600 dark:text-gray-400">Cargando categorías...</p>
        </div>
      </div>
    );
  }

  // Error state
  if (error) {
    return (
      <div className="min-h-screen bg-gray-50 dark:bg-gray-900 p-4 sm:p-6 flex items-center justify-center">
        <div className="text-center">
          <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg p-6">
            <AlertCircle className="h-12 w-12 text-red-500 mx-auto mb-4" />
            <h3 className="text-lg font-semibold text-red-800 dark:text-red-400 mb-2">
              Error al cargar categorías
            </h3>
            <p className="text-red-600 dark:text-red-400 mb-4">{error.message}</p>
            <button
              onClick={() => refetch()}
              className="bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700 transition-colors"
            >
              Reintentar
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 p-4 sm:p-6">
      <div className="max-w-7xl mx-auto space-y-6 sm:space-y-8">
        {/* Header */}
        <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4">
          <div>
            <h1 className="text-2xl sm:text-3xl font-bold text-gray-900 dark:text-white">
              Categorías
            </h1>
            <p className="text-gray-600 dark:text-gray-400 mt-1">
              Gestiona las categorías de productos (máximo 3 niveles)
            </p>
          </div>
          <button
            onClick={handleCreateCategory}
            className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors w-fit"
          >
            <Plus className="h-4 w-4" />
            Nueva Categoría
          </button>
        </div>

        {/* Filters */}
        <div className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 p-4">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {/* Search */}
            <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 h-4 w-4" />
              <input
                type="text"
                placeholder="Buscar por nombre o slug..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                aria-label="Buscar categorías"
              />
            </div>

            {/* Status Filter */}
            <select
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value as 'all' | 'active' | 'deleted')}
              className="px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
              aria-label="Filtrar por estado"
            >
              <option value="all">Todos los estados</option>
              <option value="active">Activos</option>
              <option value="deleted">Archivados</option>
            </select>
          </div>
        </div>

        {/* Categories Display - Table on desktop, Cards on mobile */}
        {filteredCategories.length === 0 ? (
          <div className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 p-12 text-center">
            <Tag className="mx-auto h-12 w-12 text-gray-400 mb-4" />
            <h3 className="text-lg font-medium text-gray-900 dark:text-white mb-2">
              {categories.length === 0 ? 'No hay categorías' : 'No se encontraron categorías'}
            </h3>
            <p className="text-gray-500 dark:text-gray-400 mb-4">
              {categories.length === 0
                ? 'Comienza creando tu primera categoría de productos.'
                : 'Prueba ajustando los filtros de búsqueda.'}
            </p>
            {categories.length === 0 && (
              <button
                onClick={handleCreateCategory}
                className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg inline-flex items-center gap-2 transition-colors"
              >
                <Plus className="h-4 w-4" />
                Crear primera categoría
              </button>
            )}
          </div>
        ) : (
          <>
            {/* Desktop Table View - Hidden on mobile */}
            <div className="hidden md:block bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 overflow-hidden shadow-sm">
              <div className="px-6 py-4 border-b border-gray-200 dark:border-gray-700">
                <h2 className="text-xl font-semibold text-gray-900 dark:text-white">
                  Categorías ({categories.length})
                </h2>
              </div>

              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead className="bg-gray-50 dark:bg-gray-900/50">
                    <tr>
                      <th className="px-6 py-4 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                        Imagen
                      </th>
                      <th className="px-6 py-4 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                        Nombre
                      </th>
                      <th className="px-6 py-4 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                        Descripción
                      </th>
                      <th className="px-6 py-4 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                        Estado
                      </th>
                      <th className="px-6 py-4 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                        Creado
                      </th>
                      <th className="px-6 py-4 text-left text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                        Acciones
                      </th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
                    {renderCategoryRows(filteredCategories)}
                  </tbody>
                </table>
              </div>
            </div>

            {/* Mobile Card View - Visible only on mobile */}
            <div className="md:hidden space-y-4">
              <div className="px-4">
                <h2 className="text-xl font-semibold text-gray-900 dark:text-white">
                  Categorías ({categories.length})
                </h2>
              </div>
              {renderCategoryCards(filteredCategories)}
            </div>
          </>
        )}

        {/* Modals */}
        <CategoryFormModal
          isOpen={isModalOpen}
          onClose={() => setIsModalOpen(false)}
          category={editingCategory || undefined}
          storeId={userData?.storeId}
          onSuccess={handleModalSuccess}
          availableCategories={categories}
          preselectedParent={preselectedParent}
        />

        <DeleteConfirmationModal
          isOpen={deleteModal.isOpen}
          onClose={() => setDeleteModal({ isOpen: false, category: null, isHardDelete: false })}
          onConfirm={confirmDelete}
          categoryName={deleteModal.category?.name || ''}
          isHardDelete={deleteModal.isHardDelete}
        />
      </div>
    </div>
  );
}

'use client';

import { gql, useMutation, useQuery } from '@apollo/client';
import {
  Plus,
  Search,
  Edit,
  Trash2,
  Archive,
  RotateCcw,
  GripVertical,
  Tag,
  Calendar,
  Eye,
  EyeOff,
  AlertCircle,
  ChevronDown,
  ChevronRight,
  MoreVertical,
} from 'lucide-react';
import { useMemo, useState, useEffect, JSX } from 'react';
import toast from 'react-hot-toast';
import FileUpload from '@/app/components/FileUpload';
import Image from 'next/image';

const GET_ALL_CATEGORIES = gql`
  query GetAllCategories {
    categories {
      id
      name
      slug
      description
      image
      isActive
      order
      createdAt
      updatedAt
      store {
        id
        name
      }
      parent {
        id
        name
        slug
      }
      children {
        id
        name
        slug
        description
        image
        isActive
        order
        createdAt
        updatedAt
        parent {
          id
          name
        }
        children {
          id
          name
          slug
          parent {
            id
            name
          }
          image
          isActive
          order
          createdAt
        }
      }
    }
  }
`;

const CREATE_CATEGORY = gql`
  mutation CreateCategory($input: CreateCategoryInput!) {
    createCategory(input: $input) {
      id
      name
      slug
      description
      image
      parentId
      storeId
      isActive
      order
      createdAt
      updatedAt
      store {
        id
        name
      }
      parent {
        id
        name
        slug
      }
    }
  }
`;

const UPDATE_CATEGORY = gql`
  mutation UpdateCategory($id: ID!, $input: UpdateCategoryInput!) {
    updateCategory(id: $id, input: $input) {
      id
      name
      slug
      description
      image
      isActive
      order
      updatedAt
      parent {
        id
        name
        slug
      }
      store {
        id
        name
      }
    }
  }
`;

const SOFT_DELETE_CATEGORY = gql`
  mutation SoftDeleteCategory($id: ID!) {
    softDeleteCategory(id: $id) {
      id
      name
      isActive
      updatedAt
    }
  }
`;

const DELETE_CATEGORY = gql`
  mutation DeleteCategory($id: ID!) {
    deleteCategory(id: $id)
  }
`;

const REORDER_CATEGORIES = gql`
  mutation ReorderCategories($categoryOrders: [CategoryOrderInput!]!) {
    reorderCategories(categoryOrders: $categoryOrders) {
      id
      order
    }
  }
`;

const GET_ALL_STORES_FOR_ADMIN_MIN = gql`
  query GetAllStoresForAdminMin {
    getAllStoresForAdmin {
      id
      storeId
      name
      isActive
    }
  }
`;

// Types
interface Category {
  id: string;
  name: string;
  slug: string;
  description?: string;
  image?: string;
  isActive: boolean;
  order: number;
  createdAt: string;
  updatedAt: string;
  store?: {
    id: string;
    name: string;
  };
  parent?: {
    id: string;
    name: string;
    slug: string;
  };
  children?: Category[];
}

interface Store {
  id: string;
  name: string;
}

interface AdminStoreRow {
  id: string;
  storeId?: string;
  name: string;
  isActive?: boolean;
}

const CategoryFormModal = ({
  isOpen,
  onClose,
  category,
  onSuccess,
  availableCategories = [],
  preselectedParent = null,
}: {
  isOpen: boolean;
  onClose: () => void;
  category?: Category;
  onSuccess: () => void;
  availableCategories?: Category[];
  preselectedParent?: Category | null;
}) => {
  const [formData, setFormData] = useState({
    name: category?.name || '',
    description: category?.description || '',
    slug: category?.slug || '',
    parentId: category?.parent?.id || '',
    storeId: category?.store?.id || '',
    image: category?.image || '',
  });
  const [errors, setErrors] = useState<{ [key: string]: string }>({});
  const [isLoading, setIsLoading] = useState(false);

  // Function to generate slug from name
  const generateSlug = (name: string) => {
    return name
      .toLowerCase()
      .trim()
      .replace(/[áàäâ]/g, 'a')
      .replace(/[éèëê]/g, 'e')
      .replace(/[íìïî]/g, 'i')
      .replace(/[óòöô]/g, 'o')
      .replace(/[úùüû]/g, 'u')
      .replace(/ñ/g, 'n')
      .replace(/ç/g, 'c')
      .replace(/[^a-z0-9\s-]/g, '') // Remove special characters
      .replace(/\s+/g, '-') // Replace spaces with hyphens
      .replace(/-+/g, '-') // Replace multiple hyphens with single
      .replace(/^-|-$/g, ''); // Remove leading/trailing hyphens
  };

  const [createCategory] = useMutation(CREATE_CATEGORY);
  const [updateCategory] = useMutation(UPDATE_CATEGORY);

  // Update form data when category or preselectedParent prop changes
  useEffect(() => {
    if (category) {
      setFormData({
        name: category.name || '',
        description: category.description || '',
        slug: category.slug || generateSlug(category.name || ''),
        parentId: category.parent?.id || '',
        storeId: category.store?.id || '',
        image: category.image || '',
      });
    } else {
      setFormData({
        name: '',
        description: '',
        slug: '',
        parentId: preselectedParent?.id || '',
        storeId: preselectedParent?.store?.id || '',
        image: '',
      });
    }
    setErrors({});
  }, [category, preselectedParent]);

  useEffect(() => {
    if (!isOpen) {
      setFormData({
        name: '',
        description: '',
        slug: '',
        parentId: '',
        storeId: '',
        image: '',
      });
      setErrors({});
      setIsLoading(false);
    }
  }, [isOpen]);

  const validateForm = () => {
    const newErrors: { [key: string]: string } = {};

    if (!formData.name.trim()) {
      newErrors.name = 'El nombre es requerido';
    } else if (formData.name.length < 2) {
      newErrors.name = 'El nombre debe tener al menos 2 caracteres';
    } else if (formData.name.length > 80) {
      newErrors.name = 'El nombre no puede exceder 80 caracteres';
    }

    if (!formData.storeId && !category && !preselectedParent) {
      newErrors.storeId = 'La tienda es requerida';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validateForm()) return;

    setIsLoading(true);
    try {
      // Determinar storeId - prioridad: formData > preselectedParent > category
      const storeId = formData.storeId || preselectedParent?.store?.id || category?.store?.id;

      if (!storeId) {
        toast.error('No se pudo determinar la tienda para la categoría');
        return;
      }

      // Sanitize input
      const inputPayload: any = {
        name: formData.name.trim(),
        description: formData.description.trim(),
        slug: formData.slug.trim(),
        storeId: storeId,
      };

      // Solo agregar parentId si existe y no es una cadena vacía
      if (formData.parentId && formData.parentId.trim()) {
        inputPayload.parentId = formData.parentId;
      }

      console.log('Enviando datos:', inputPayload); // Para debug

      if (category) {
        // Update existing category
        // The GraphQL UpdateCategoryInput does not accept `storeId`, remove it
        const updatePayload = { ...inputPayload };
        delete updatePayload.storeId;

        await updateCategory({
          variables: {
            id: category.id,
            input: updatePayload,
          },
        });
        toast.success('Categoría actualizada exitosamente');
      } else {
        // Create new category
        await createCategory({
          variables: {
            input: inputPayload,
          },
        });

        if (formData.parentId) {
          toast.success('Subcategoría creada exitosamente');
        } else {
          toast.success('Categoría creada exitosamente');
        }
      }

      onSuccess();
      onClose();
    } catch (error: any) {
      console.error('Error al guardar categoría:', error);
      const errorMessage =
        error?.graphQLErrors?.[0]?.message || error?.message || 'Error al guardar la categoría';

      if (
        errorMessage.toLowerCase().includes('duplicate') ||
        errorMessage.toLowerCase().includes('unique') ||
        errorMessage.toLowerCase().includes('already exists')
      ) {
        toast.error(
          `Ya existe una categoría con el nombre "${formData.name}". Por favor usa un nombre diferente.`,
          {
            style: {
              background: '#fef3c7',
              color: '#d97706',
              border: '1px solid #fde68a',
            },
          }
        );
      } else if (errorMessage.toLowerCase().includes('slug')) {
        toast.error('El slug de la categoría ya está en uso. Por favor usa uno diferente.', {
          style: {
            background: '#fef3c7',
            color: '#d97706',
            border: '1px solid #fde68a',
          },
        });
      } else if (
        errorMessage.toLowerCase().includes('validation') ||
        errorMessage.toLowerCase().includes('invalid')
      ) {
        toast.error('Los datos ingresados no son válidos. Por favor revisa la información.', {
          style: {
            background: '#fee2e2',
            color: '#dc2626',
            border: '1px solid #fca5a5',
          },
        });
      } else {
        toast.error(errorMessage, {
          style: {
            background: '#fee2e2',
            color: '#dc2626',
            border: '1px solid #fca5a5',
          },
        });
      }
    } finally {
      setIsLoading(false);
    }
  };

  // Get unique stores from available categories
  const stores = useMemo(() => {
    const storeMap = new Map();
    availableCategories.forEach((cat) => {
      if (cat.store) {
        storeMap.set(cat.store.id, cat.store);
      }
    });
    return Array.from(storeMap.values());
  }, [availableCategories]);

  const creatingMainCategory = !category && !preselectedParent;

  // For the creation form we want to show ALL stores (including those without categories).
  const {
    data: allStoresData,
    loading: allStoresLoading,
    error: allStoresError,
  } = useQuery(GET_ALL_STORES_FOR_ADMIN_MIN, {
    skip: !isOpen || !creatingMainCategory,
    fetchPolicy: 'network-only',
  });

  const allStores: Store[] = useMemo(() => {
    const rows: AdminStoreRow[] = allStoresData?.getAllStoresForAdmin || [];
    if (!rows.length) return [];

    const dedup = new Map<string, Store>();
    for (const r of rows) {
      if (!r?.id) continue;
      dedup.set(r.id, { id: r.id, name: r.name });
    }

    return Array.from(dedup.values()).sort((a, b) => a.name.localeCompare(b.name));
  }, [allStoresData]);

  const modalStores: Store[] = useMemo(() => {
    if (!creatingMainCategory) return stores;

    // Merge the stores derived from categories with the full store list.
    // This prevents showing only category-backed stores while still rendering fast.
    const merged = new Map<string, Store>();
    for (const s of stores) merged.set(s.id, s);
    for (const s of allStores) merged.set(s.id, s);
    return Array.from(merged.values()).sort((a, b) => a.name.localeCompare(b.name));
  }, [creatingMainCategory, stores, allStores]);

  const noStoresAvailable = creatingMainCategory && !allStoresLoading && modalStores.length === 0;

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 overflow-y-auto">
      <div className="flex min-h-full items-center justify-center p-4">
        <div className="fixed inset-0 bg-black bg-opacity-25" onClick={onClose} />

        <div className="relative bg-white dark:bg-gray-800 rounded-lg shadow-xl w-full max-w-md p-6">
          <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-4">
            {category
              ? 'Editar Categoría'
              : preselectedParent
                ? `Nueva Subcategoría de "${preselectedParent.name}"`
                : 'Nueva Categoría'}
          </h3>

          {/* Banner informativo para subcategorías */}
          {!category && preselectedParent && (
            <div className="mb-4 p-3 bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800 rounded-lg">
              <div className="flex items-center gap-2">
                <Tag className="h-4 w-4 text-blue-600 dark:text-blue-400" />
                <div>
                  <p className="text-sm font-medium text-blue-800 dark:text-blue-300">
                    Creando subcategoría
                  </p>
                  <p className="text-xs text-blue-700 dark:text-blue-400">
                    Esta será una subcategoría de &quot;{preselectedParent.name}&quot; en la tienda
                    &quot;{preselectedParent.store?.name}&quot;
                  </p>
                </div>
              </div>
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-4">
            {/* Mostrar tienda para subcategorías (solo lectura) */}
            {!category && preselectedParent && (
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                  Tienda
                </label>
                <div className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-gray-50 dark:bg-gray-600 text-gray-700 dark:text-gray-300">
                  {preselectedParent.store?.name || 'No especificada'}
                </div>
                <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">
                  La subcategoría hereda la tienda de la categoría padre
                </p>
              </div>
            )}

            {/* Seleccionar tienda solo para categorías principales nuevas */}
            {!category && !preselectedParent && (
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                  Tienda *
                </label>
                {allStoresError && (
                  <div className="mb-3 p-3 rounded-lg bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 text-sm">
                    Error cargando tiendas. Revisa tu sesión/permisos y refresca la página.
                  </div>
                )}
                {noStoresAvailable && (
                  <div className="mb-3 p-3 rounded-lg bg-yellow-50 dark:bg-yellow-900/20 border border-yellow-200 dark:border-yellow-800 text-sm">
                    No hay tiendas disponibles para asignar. Por favor crea una tienda antes de
                    crear categorías.
                  </div>
                )}
                <select
                  value={formData.storeId}
                  onChange={(e) => setFormData({ ...formData, storeId: e.target.value })}
                  className={`w-full px-3 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 ${
                    errors.storeId
                      ? 'border-red-500 bg-red-50 dark:bg-red-900/20'
                      : 'border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700'
                  } text-gray-900 dark:text-white`}
                  disabled={isLoading}
                >
                  <option value="">
                    {allStoresLoading ? 'Cargando tiendas...' : 'Seleccionar tienda'}
                  </option>
                  {modalStores.map((store) => (
                    <option key={store.id} value={store.id}>
                      {store.name}
                    </option>
                  ))}
                </select>
                {errors.storeId && <p className="text-red-500 text-sm mt-1">{errors.storeId}</p>}
              </div>
            )}

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                Nombre *
              </label>
              <input
                type="text"
                value={formData.name}
                onChange={(e) => {
                  const newName = e.target.value;
                  setFormData({
                    ...formData,
                    name: newName,
                    slug: generateSlug(newName),
                  });
                }}
                className={`w-full px-3 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 ${
                  errors.name
                    ? 'border-red-500 bg-red-50 dark:bg-red-900/20'
                    : 'border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700'
                } text-gray-900 dark:text-white`}
                placeholder="Nombre de la categoría"
                aria-label="Nombre de la categoría"
                disabled={isLoading}
              />
              {errors.name && <p className="text-red-500 text-sm mt-1">{errors.name}</p>}
            </div>

            {/* Show generated slug */}
            {formData.slug && (
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                  Slug generado
                </label>
                <div className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-gray-50 dark:bg-gray-600 text-gray-700 dark:text-gray-300 text-sm">
                  /{formData.slug}
                </div>
                <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">
                  Este slug se genera automáticamente desde el nombre
                </p>
              </div>
            )}

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                Descripción
              </label>
              <textarea
                value={formData.description}
                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                rows={3}
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                placeholder="Descripción opcional"
                aria-label="Descripción de la categoría"
                disabled={isLoading}
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                Imagen de la categoría
              </label>
              <FileUpload
                onFile={(url) => setFormData({ ...formData, image: url })}
                accept="image/*"
                storeId={formData.storeId}
                initialImage={formData.image}
              />
            </div>

            <div className="flex justify-end gap-3 pt-4">
              <button
                type="button"
                onClick={onClose}
                className="px-4 py-2 text-gray-700 dark:text-gray-300 bg-gray-100 dark:bg-gray-700 rounded-lg hover:bg-gray-200 dark:hover:bg-gray-600 transition-colors"
                disabled={isLoading}
              >
                Cancelar
              </button>
              <button
                type="submit"
                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50"
                disabled={isLoading || noStoresAvailable}
              >
                {isLoading ? 'Guardando...' : category ? 'Actualizar' : 'Crear'}
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

// Delete Confirmation Modal (se mantiene igual)
const DeleteConfirmationModal = ({
  isOpen,
  onClose,
  onConfirm,
  categoryName,
  isHardDelete,
}: {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: () => void;
  categoryName: string;
  isHardDelete: boolean;
}) => {
  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 overflow-y-auto">
      <div className="flex min-h-full items-center justify-center p-4">
        <div className="fixed inset-0 bg-black bg-opacity-25" onClick={onClose} />

        <div className="relative bg-white dark:bg-gray-800 rounded-lg shadow-xl w-full max-w-md p-6">
          <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-4">
            {isHardDelete ? 'Eliminar Permanentemente' : 'Archivar Categoría'}
          </h3>

          <p className="text-gray-600 dark:text-gray-400 mb-6">
            {isHardDelete ? (
              <>
                ¿Estás seguro de que quieres eliminar permanentemente la categoría{' '}
                <strong>&quot;{categoryName}&quot;</strong>? Esta acción no se puede deshacer.
              </>
            ) : (
              <>
                ¿Estás seguro de que quieres archivar la categoría{' '}
                <strong>&quot;{categoryName}&quot;</strong>? Se mantendrá en el sistema pero no
                estará visible.
              </>
            )}
          </p>

          <div className="flex justify-end gap-3">
            <button
              onClick={onClose}
              className="px-4 py-2 text-gray-700 dark:text-gray-300 bg-gray-100 dark:bg-gray-700 rounded-lg hover:bg-gray-200 dark:hover:bg-gray-600 transition-colors"
            >
              Cancelar
            </button>
            <button
              onClick={onConfirm}
              className={`px-4 py-2 text-white rounded-lg transition-colors ${
                isHardDelete ? 'bg-red-600 hover:bg-red-700' : 'bg-orange-600 hover:bg-orange-700'
              }`}
            >
              {isHardDelete ? 'Eliminar Permanentemente' : 'Archivar'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

const CategoryCard = ({
  category,
  onEdit,
  onSoftDelete,
  onHardDelete,
  onRestore,
  onCreateSubcategory,
  isExpanded,
  onToggleExpand,
  depth = 0,
  isMobile = false,
}: {
  category: Category;
  onEdit: (category: Category) => void;
  onSoftDelete: (category: Category) => void;
  onHardDelete: (category: Category) => void;
  onRestore: (category: Category) => void;
  onCreateSubcategory: (category: Category) => void;
  isExpanded?: boolean;
  onToggleExpand?: (id: string) => void;
  depth?: number;
  isMobile?: boolean;
}) => {
  const formatDate = (dateString: string) =>
    new Date(dateString).toLocaleDateString('es-ES', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });

  const canCreateSubcategory = category.isActive && depth < 2;

  // En móvil, si es subcategoría (depth > 0), mostrar como lista simple
  if (isMobile && depth > 0) {
    return (
      <div
        className={`border-b border-gray-200 dark:border-gray-700 ${depth === 1 ? 'pl-6' : 'pl-10'}`}
      >
        <div className="flex items-center justify-between py-3 px-4 hover:bg-gray-50 dark:hover:bg-gray-750 transition-colors">
          {/* Información de la subcategoría */}
          <div className="flex items-center gap-3 flex-1 min-w-0">
            {/* Botón expandir/colapsar si tiene hijos */}
            {category.children && category.children.length > 0 && (
              <button
                onClick={() => onToggleExpand?.(category.id)}
                className="p-1 hover:bg-gray-200 dark:hover:bg-gray-600 rounded transition-colors flex-shrink-0"
                aria-label={isExpanded ? 'Colapsar' : 'Expandir'}
              >
                {isExpanded ? (
                  <ChevronDown className="h-3.5 w-3.5 text-gray-500" />
                ) : (
                  <ChevronRight className="h-3.5 w-3.5 text-gray-500" />
                )}
              </button>
            )}

            {/* Nombre y estado */}
            <div className="flex items-center gap-2 flex-1 min-w-0">
              <h4 className="text-sm font-medium text-gray-900 dark:text-white truncate">
                {category.name}
              </h4>

              <span
                className={`inline-flex items-center p-1 rounded-full flex-shrink-0 ${
                  category.isActive
                    ? 'text-green-600 dark:text-green-400'
                    : 'text-red-600 dark:text-red-400'
                }`}
              >
                {category.isActive ? <Eye className="w-3 h-3" /> : <EyeOff className="w-3 h-3" />}
              </span>
            </div>
          </div>

          {/* Acciones compactas */}
          <div className="flex items-center gap-1 flex-shrink-0 ml-3">
            <button
              onClick={() => onEdit(category)}
              disabled={!category.isActive}
              className="p-2 text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200 hover:bg-gray-100 dark:hover:bg-gray-700 rounded transition-colors disabled:opacity-30"
              aria-label="Editar"
            >
              <Edit className="h-4 w-4" />
            </button>

            {category.isActive ? (
              <button
                onClick={() => onSoftDelete(category)}
                className="p-2 text-orange-500 hover:text-orange-700 hover:bg-orange-50 rounded transition-colors"
                aria-label="Archivar"
              >
                <Archive className="h-4 w-4" />
              </button>
            ) : (
              <button
                onClick={() => onRestore(category)}
                className="p-2 text-green-500 hover:text-green-700 hover:bg-green-50 rounded transition-colors"
                aria-label="Restaurar"
              >
                <RotateCcw className="h-4 w-4" />
              </button>
            )}

            <button
              onClick={() => onHardDelete(category)}
              className="p-2 text-red-500 hover:text-red-700 hover:bg-red-50 rounded transition-colors"
              aria-label="Eliminar permanentemente"
            >
              <Trash2 className="h-4 w-4" />
            </button>

            {canCreateSubcategory && (
              <button
                onClick={() => onCreateSubcategory(category)}
                className="p-2 text-blue-500 hover:text-blue-700 hover:bg-blue-50 rounded transition-colors"
                aria-label="Crear subcategoría"
              >
                <Plus className="h-4 w-4" />
              </button>
            )}
          </div>
        </div>
      </div>
    );
  }

  // Vista normal de card (para categorías principales o en desktop)
  return (
    <div className={`space-y-3 ${depth > 0 ? 'pl-4' : ''}`}>
      <div className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 p-4 shadow-sm">
        {/* Header con nombre y estado */}
        <div className="flex items-start justify-between mb-3">
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-2 mb-1">
              <GripVertical className="h-4 w-4 text-gray-400 flex-shrink-0" />

              {depth > 0 && (
                <span className="text-xs text-blue-600 dark:text-blue-400 bg-blue-100 dark:bg-blue-900/30 px-2 py-0.5 rounded flex-shrink-0">
                  Nivel {depth + 1}
                </span>
              )}

              {category.children && category.children.length > 0 && (
                <button
                  onClick={() => onToggleExpand?.(category.id)}
                  className="p-1 hover:bg-gray-100 dark:hover:bg-gray-700 rounded transition-colors flex-shrink-0"
                  aria-label={isExpanded ? 'Colapsar' : 'Expandir'}
                >
                  {isExpanded ? (
                    <ChevronDown className="h-3 w-3 text-gray-500" />
                  ) : (
                    <ChevronRight className="h-3 w-3 text-gray-500" />
                  )}
                </button>
