                    'Plan Actual'
                  ) : mode === 'dashboard' && currentPlan ? (
                    'Cambiar Plan'
                  ) : (
                    'Empieza gratis'
                  )}
                </button>

                {/* Description as list below button */}
                <div className="mt-6 text-left space-y-2">
                  {plan.description.split(',').map((item, i) => (
                    <div key={i} className="flex items-start gap-2">
