'use client';

import { useEffect, useMemo, useRef, useState } from 'react';
import Link from 'next/link';
import { useParams, useRouter } from 'next/navigation';
import { gql, useQuery } from '@apollo/client';
import toast from 'react-hot-toast';
import { ArrowLeft, Search, ShoppingCart, CheckCircle2 } from 'lucide-react';

import { fairsApi, Fair, FairsApiError } from '@/lib/api/fairs';
import { useFairCartStore } from '@/lib/store/fairCart';
import { formatMoney, toNumber } from '@/lib/utils/money';

const GET_PRODUCTS_BY_STORE_FOR_FAIR = gql`
  query ProductsByStore($storeId: String!, $page: Int!, $pageSize: Int!) {
    productsByStore(storeId: $storeId, page: $page, pageSize: $pageSize) {
      items {
        id
        name
        price
        currency
        stock
        inStock
        available
        imageUrl
      }
      total
      page
      pageSize
    }
  }
`;

const PAYMENT_METHODS: Array<{ value: string; label: string }> = [
  { value: 'CASH', label: 'Efectivo' },
  { value: 'NEQUI', label: 'Nequi' },
  { value: 'DAVIPLATA', label: 'Daviplata' },
  { value: 'PSE', label: 'PSE' },
  { value: 'CREDIT_CARD', label: 'Tarjeta crédito' },
  { value: 'DEBIT_CARD', label: 'Tarjeta débito' },
  { value: 'TRANSFER', label: 'Transferencia' },
  { value: 'OTHER', label: 'Otro' },
];

function isFairActive(fair?: Fair | null): boolean {
  if (!fair) return false;
  const raw = (fair.status || '').toUpperCase();
  if (fair.isActive === true) return true;
  if (raw.includes('ACTIVE') || raw.includes('RUNNING')) return true;
  if (raw.includes('CLOSED')) return false;
  if (fair.closedAt) return false;
  const now = Date.now();
  const start = fair.startsAt ? new Date(fair.startsAt).getTime() : 0;
  const end = fair.endsAt ? new Date(fair.endsAt).getTime() : 0;
  return start <= now && now <= end;
}

function friendlySaleError(err: unknown): string {
  const msg = (err as any)?.message || '';
  const lower = String(msg).toLowerCase();
  if (lower.includes('insufficient stock')) {
    return 'Stock insuficiente para uno o más productos.';
  }
  if (
    lower.includes('fair is not active') ||
    lower.includes('not active') ||
    lower.includes('not running')
  ) {
    return 'La feria no está activa. No se puede registrar la venta.';
  }
  return msg || 'No se pudo registrar la venta.';
}

export default function FairSellPage() {
  const router = useRouter();
  const params = useParams<{ fairId: string }>();
  const fairId = params.fairId;

  const {
    byFairId,
    ensureFair,
    increment,
    decrement,
    setQuantity,
    clearFair,
    setPaymentMethod,
    setCustomerName,
    setCustomerContact,
  } = useFairCartStore();

  const per = byFairId[fairId];

  const [fair, setFair] = useState<Fair | null>(null);
  const [loadingFair, setLoadingFair] = useState(true);
  const [search, setSearch] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [lastSuccess, setLastSuccess] = useState<any>(null);

  const userStoreId = useMemo(() => {
    try {
      const raw = localStorage.getItem('user');
      if (!raw) return null;
      const parsed = JSON.parse(raw);
      const resolved = parsed?.storeId ?? parsed?.store?.id ?? parsed?.store?.storeId;
      if (!resolved) return null;
      return String(resolved);
    } catch {
      return null;
    }
  }, []);

  useEffect(() => {
    ensureFair(fairId);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [fairId]);

  useEffect(() => {
    let mounted = true;
    (async () => {
      setLoadingFair(true);
      try {
        const f = await fairsApi.getFairById(fairId);
        if (mounted) setFair(f);
      } catch (e: any) {
        toast.error(e?.message || 'No se pudo cargar la feria');
      } finally {
        if (mounted) setLoadingFair(false);
      }
    })();
    return () => {
      mounted = false;
    };
  }, [fairId]);

  const storeId = fair?.storeId;
  // Prefer the fair's storeId for correctness; fallback to logged-in user's storeId.
  const effectiveStoreId = storeId || userStoreId || '';
  const active = useMemo(() => isFairActive(fair), [fair]);

  // Backend typically enforces a max pageSize; keep it safe and paginate.
  const pageSize = 200;
  const autoPagingRef = useRef<{ storeId: string; calls: number }>({ storeId: '', calls: 0 });
  const {
    data,
    loading: loadingProducts,
    error: productsError,
    fetchMore,
    networkStatus,
  } = useQuery(GET_PRODUCTS_BY_STORE_FOR_FAIR, {
    variables: { storeId: effectiveStoreId, page: 1, pageSize },
    skip: !effectiveStoreId,
    notifyOnNetworkStatusChange: true,
    fetchPolicy: 'network-only',
  });

  const isFetchingMore = networkStatus === 3;

  useEffect(() => {
    if (!productsError) return;
    toast.error(productsError.message || 'No se pudieron cargar los productos');
  }, [productsError]);

  useEffect(() => {
    // Reset pagination guard when store changes
    if (autoPagingRef.current.storeId !== effectiveStoreId) {
      autoPagingRef.current = { storeId: effectiveStoreId, calls: 0 };
    }

    if (!effectiveStoreId) return;
    if (loadingProducts || isFetchingMore) return;

    const total = toNumber(data?.productsByStore?.total);
    const currentItems = (data?.productsByStore?.items || []) as any[];
    const currentPage = toNumber(data?.productsByStore?.page) || 1;
    const currentPageSize = toNumber(data?.productsByStore?.pageSize) || pageSize;

    if (!total) return;
    if (!Array.isArray(currentItems)) return;
    if (currentItems.length >= total) return;

    // Safety guard to avoid infinite loops if backend behaves unexpectedly.
    const estimatedPages = Math.ceil(total / Math.max(1, currentPageSize));
    const maxCalls = Math.min(estimatedPages + 5, 300);
    if (autoPagingRef.current.calls >= maxCalls) return;
    autoPagingRef.current.calls += 1;

    void fetchMore({
      variables: {
        storeId: effectiveStoreId,
        page: currentPage + 1,
        pageSize: currentPageSize,
      },
      updateQuery: (prev, { fetchMoreResult }) => {
        const prevItems = (prev as any)?.productsByStore?.items || [];
        const moreItems = (fetchMoreResult as any)?.productsByStore?.items || [];
        if (!Array.isArray(moreItems) || moreItems.length === 0) return prev;

        const byId = new Map<string, any>();
        [...prevItems, ...moreItems].forEach((p: any) => {
          if (p?.id) byId.set(String(p.id), p);
        });

        return {
          ...(prev as any),
          productsByStore: {
            ...(fetchMoreResult as any).productsByStore,
            items: Array.from(byId.values()),
            total:
              (fetchMoreResult as any)?.productsByStore?.total ??
              (prev as any)?.productsByStore?.total,
          },
        };
      },
    });
  }, [data, effectiveStoreId, fetchMore, isFetchingMore, loadingProducts]);

  const products = (data?.productsByStore?.items || []) as Array<any>;
  const filtered = useMemo(() => {
    const q = search.trim().toLowerCase();
    if (!q) return products;
    return products.filter((p) => {
      const name = String(p?.name || p?.title || '').toLowerCase();
      return name.includes(q);
    });
  }, [products, search]);

  const currency = (products[0]?.currency as string) || 'COP';
  const quantities = per?.quantities || {};

  const total = useMemo(() => {
    let sum = 0;
    for (const p of products) {
      const qty = quantities[p.id] || 0;
      if (!qty) continue;
      sum += toNumber(p.price) * qty;
    }
    return sum;
  }, [products, quantities]);

  const selectedItems = useMemo(() => {
    return Object.entries(quantities)
      .filter(([, q]) => q > 0)
      .map(([productId, quantity]) => ({ productId, quantity }));
  }, [quantities]);

  async function submitSale() {
    if (!active) {
      toast.error('La feria no está activa.');
      return;
    }
    if (selectedItems.length === 0) {
      toast.error('Agrega al menos un producto.');
      return;
    }

    setSubmitting(true);
    try {
      const res = await fairsApi.createSale(fairId, {
        paymentMethod: per?.paymentMethod || 'CASH',
        items: selectedItems,
        customerName: per?.customerName || undefined,
        customerContact: per?.customerContact || undefined,
      });

      setLastSuccess({ sale: res, total, items: selectedItems });
      toast.success('Venta registrada');

      // Clear only quantities; keep payment method + customer fields
      clearFair(fairId);
      setPaymentMethod(fairId, per?.paymentMethod || 'CASH');
      setCustomerName(fairId, per?.customerName || '');
      setCustomerContact(fairId, per?.customerContact || '');
    } catch (e: any) {
      toast.error(friendlySaleError(e));
    } finally {
      setSubmitting(false);
    }
  }

  if (loadingFair) {
    return (
      <div className="p-4 md:p-6 max-w-5xl mx-auto">
        <div className="rounded-2xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-4">
          Cargando feria...
        </div>
      </div>
    );
  }

  return (
    <div className="p-4 md:p-6 max-w-5xl mx-auto">
      <div className="flex items-center justify-between gap-3">
        <div className="flex items-center gap-3 min-w-0">
          <button
            type="button"
            onClick={() => router.back()}
            className="inline-flex items-center justify-center rounded-lg p-2 bg-gray-100 dark:bg-gray-800 text-gray-900 dark:text-white"
          >
            <ArrowLeft className="h-5 w-5" />
          </button>
          <div className="min-w-0">
            <h1 className="text-xl md:text-2xl font-semibold text-gray-900 dark:text-white truncate">
              Vender en: {fair?.name || 'Feria'}
            </h1>
            <p className="text-sm text-gray-600 dark:text-gray-300">
              {active ? 'Activa' : 'No activa'} •
              {!effectiveStoreId
                ? ' Cargando tienda…'
                : loadingProducts
                  ? ' Cargando productos…'
                  : ` ${products.length} producto${products.length === 1 ? '' : 's'}`}
            </p>
          </div>
        </div>

        <Link
          href={`/dashboard/fairs/${fairId}`}
          className="inline-flex items-center justify-center rounded-lg px-3 py-2 text-sm font-medium bg-gray-100 dark:bg-gray-800 text-gray-900 dark:text-white"
        >
          Detalle
        </Link>
      </div>

      {/* Confirmation */}
      {lastSuccess && (
        <div className="mt-4 rounded-2xl border border-emerald-200 dark:border-emerald-900 bg-emerald-50/70 dark:bg-emerald-900/20 p-4">
          <div className="flex items-start gap-3">
            <CheckCircle2 className="h-6 w-6 text-emerald-600" />
            <div className="min-w-0">
              <p className="font-semibold text-emerald-900 dark:text-emerald-200">
                Venta registrada
              </p>
              <p className="text-sm text-emerald-900/80 dark:text-emerald-200/80">
                Total:{' '}
                <span className="font-semibold">{formatMoney(lastSuccess.total, currency)}</span>
              </p>
              <p className="text-xs text-emerald-900/70 dark:text-emerald-200/70">
                Items: {lastSuccess.items.reduce((a: number, it: any) => a + it.quantity, 0)}
              </p>
            </div>
            <button
              type="button"
              onClick={() => setLastSuccess(null)}
              className="ml-auto text-sm font-semibold text-emerald-800 dark:text-emerald-200"
            >
              Ok
            </button>
          </div>
        </div>
      )}

      {/* Controls */}
      <div className="mt-4 grid gap-3">
        <div className="rounded-2xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-4">
          <div className="flex items-center gap-2">
            <Search className="h-4 w-4 text-gray-400" />
            <input
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Buscar producto..."
              className="w-full bg-transparent outline-none text-base text-gray-900 dark:text-white"
            />
          </div>
        </div>

        <div className="grid md:grid-cols-2 gap-3">
          <div className="rounded-2xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-4">
            <label className="block text-sm font-medium text-gray-900 dark:text-white">
              Método de pago
            </label>
            <select
              value={per?.paymentMethod || 'CASH'}
              onChange={(e) => setPaymentMethod(fairId, e.target.value)}
              className="mt-2 w-full rounded-xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900 px-3 py-3 text-base text-gray-900 dark:text-white"
            >
              {PAYMENT_METHODS.map((m) => (
                <option key={m.value} value={m.value}>
                  {m.label}
                </option>
              ))}
            </select>
          </div>

          <div className="rounded-2xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-4">
            <label className="block text-sm font-medium text-gray-900 dark:text-white">
              Cliente (opcional)
            </label>
            <input
              value={per?.customerName || ''}
              onChange={(e) => setCustomerName(fairId, e.target.value)}
              placeholder="Nombre"
              className="mt-2 w-full rounded-xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900 px-3 py-3 text-base text-gray-900 dark:text-white"
            />
            <input
              value={per?.customerContact || ''}
              onChange={(e) => setCustomerContact(fairId, e.target.value)}
              placeholder="Contacto (tel/email)"
              className="mt-2 w-full rounded-xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900 px-3 py-3 text-base text-gray-900 dark:text-white"
            />
          </div>
        </div>
      </div>

      {/* Products */}
      <div className="mt-4 space-y-3">
        {!effectiveStoreId || loadingProducts ? (
          <div className="rounded-2xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-4">
            Cargando productos...
          </div>
        ) : productsError ? (
          <div className="rounded-2xl border border-red-200 dark:border-red-900 bg-red-50/70 dark:bg-red-900/20 p-4">
            <p className="font-semibold text-red-900 dark:text-red-200">
              No se pudieron cargar los productos
            </p>
            <p className="mt-1 text-sm text-red-900/80 dark:text-red-200/80">
              {productsError.message}
            </p>
          </div>
        ) : filtered.length === 0 ? (
          <div className="rounded-2xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-4">
            No hay productos para mostrar.
          </div>
        ) : (
          filtered.map((p) => {
            const qty = quantities[p.id] || 0;
            return (
              <div
                key={p.id}
                className="rounded-2xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-4"
              >
                <div className="flex items-start justify-between gap-3">
                  <div className="min-w-0">
                    <p className="font-semibold text-gray-900 dark:text-white truncate">
                      {p.name || p.title}
                    </p>
                    <p className="text-sm text-gray-600 dark:text-gray-300">
                      {formatMoney(toNumber(p.price), p.currency || currency)}
                      {typeof p.stock === 'number' ? ` • Stock: ${p.stock}` : ''}
                    </p>
                  </div>

                  <div className="flex items-center gap-2 flex-shrink-0">
                    <button
                      type="button"
                      onClick={() => decrement(fairId, p.id)}
                      className="h-11 w-11 rounded-xl bg-gray-100 dark:bg-gray-700 text-gray-900 dark:text-white text-lg font-bold"
                      aria-label="Disminuir"
                    >
                      −
                    </button>
                    <input
                      inputMode="numeric"
                      value={qty}
                      onChange={(e) => setQuantity(fairId, p.id, Number(e.target.value || 0))}
                      className="w-16 h-11 text-center rounded-xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900 text-base text-gray-900 dark:text-white"
                    />
                    <button
                      type="button"
                      onClick={() => increment(fairId, p.id)}
                      className="h-11 w-11 rounded-xl bg-fourth-base text-black text-lg font-bold"
                      aria-label="Aumentar"
                    >
                      +
                    </button>
                  </div>
                </div>
              </div>
            );
          })
        )}

        {isFetchingMore && (
          <div className="rounded-2xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-4 text-sm text-gray-600 dark:text-gray-300">
            Cargando más productos...
          </div>
        )}
      </div>

      {/* Bottom CTA */}
      <div className="sticky bottom-0 mt-6 pt-3 pb-4 bg-gradient-to-t from-white dark:from-gray-900 via-white/90 dark:via-gray-900/90 to-transparent">
        <button
          type="button"
          disabled={submitting}
          onClick={submitSale}
          className="w-full inline-flex items-center justify-center gap-3 rounded-2xl px-4 py-4 text-base font-semibold bg-fourth-base text-black disabled:opacity-60"
        >
          <ShoppingCart className="h-5 w-5" />
          {submitting ? 'Registrando…' : `Registrar venta • ${formatMoney(total, currency)}`}
        </button>
        {!active && (
          <p className="mt-2 text-xs text-red-600">Feria no activa: no se puede registrar venta.</p>
        )}
      </div>
    </div>
  );
}

'use client';

import React, { useEffect, useState } from 'react';
import { gql, useQuery } from '@apollo/client';
import { Users, ShoppingCart, DollarSign, TrendingUp, Package } from 'lucide-react';
import { useRouter } from 'next/navigation';
import KPICard from '../components/KPICard';
import LineChart from '../components/LineChart';
import BarChart from '../components/BarChart';
import { KPI, ChartData, Customer } from '@/lib/schemas/dashboard';
import { useSessionStore } from '@/lib/store/dashboard';

// Queries GraphQL
const TOTAL_PRODUCTS_QUERY = gql`
  query {
    totalProducts
  }
`;

const MONTHLY_SALES_QUERY = gql`
  query {
    monthlySales {
      totalSales
      percentageChange
    }
  }
`;
const CONVERSION_RATE_QUERY = gql`
  query ConversionRate($storeId: String) {
    conversionRate(storeId: $storeId) {
      rate
      percentageChange
    }
  }
`;

const ORDERS_BY_PERIOD = gql`
  query OrdersByPeriod($period: Period!, $storeId: String, $limit: Float) {
    ordersByPeriod(period: $period, storeId: $storeId, limit: $limit) {
      period
      count
      periodLabel
      startDate
      endDate
    }
  }
`;

const CUSTOMERS_BY_PERIOD = gql`
  query CustomersByPeriod($period: Period!, $storeId: String, $limit: Float) {
    customersByPeriod(period: $period, storeId: $storeId, limit: $limit) {
      period
      count
      periodLabel
      startDate
      endDate
    }
  }
`;

const SALES_BY_PERIOD = gql`
  query SalesByPeriod($period: Period!, $storeId: String, $limit: Float) {
    salesByPeriod(period: $period, storeId: $storeId, limit: $limit) {
      period
      totalSales
      totalOrders
      averageOrderValue
      periodLabel
      startDate
      endDate
    }
  }
`;

const ACTIVE_USERS_QUERY = gql`
  query ActiveUsers($storeId: String, $daysBack: Float) {
    activeUsers(storeId: $storeId, daysBack: $daysBack) {
      count
      percentageChange
      lastActiveDate
    }
  }
`;

const CONTACT_LEADS_BY_STORE = gql`
  query ContactLeadsByStore($storeId: ID!) {
    contactLeadsByStore(storeId: $storeId) {
      id
      firstName
      lastName
      email
      phoneNumber
      createdAt
      updatedAt
      store {
        id
        name
      }
    }
  }
`;

const mockKPIs: KPI = {
  totalCustomers: 1234,
  totalOrders: 892,
  monthlyRevenue: 45600,
  conversionRate: 3.2,
  averageOrderValue: 78.5,
};

export default function InsightsPage() {
  const router = useRouter();
  const [kpis, setKpis] = useState<KPI | null>(null);
  const [chartData, setChartData] = useState<ChartData | null>(null);
  const [user, setUser] = useState<any>(null);
  const currentStore = useSessionStore((s: any) => s.currentStore);

  // Load user data from localStorage
  useEffect(() => {
    const userData = localStorage.getItem('user');
    if (userData) {
      const parsedUser = JSON.parse(userData);
      setUser(parsedUser);
      console.log('🚀 ~ InsightsPage ~ userData from localStorage:', parsedUser);
    }
  }, []);

  // Get storeId from either the session store or user data
  const storeId = currentStore?.storeId.id || user?.storeId;

  // Queries para las KPI cards
  const {
    data: totalProductsData,
    loading: loadingProducts,
    error: errorProducts,
  } = useQuery(TOTAL_PRODUCTS_QUERY);
  const {
    data: activeUsersData,
    loading: loadingActiveUsers,
    error: errorActiveUsers,
  } = useQuery(ACTIVE_USERS_QUERY);
  const {
    data: monthlySalesData,
    loading: loadingMonthlySales,
    error: errorMonthlySales,
  } = useQuery(MONTHLY_SALES_QUERY);
  const {
    data: conversionRateData,
    loading: loadingConversionRate,
    error: errorConversionRate,
  } = useQuery(CONVERSION_RATE_QUERY, { variables: { storeId } });

  const {
    data: ordersByPeriodData,
    loading: loadingOrdersByPeriod,
    error: errorOrdersByPeriod,
  } = useQuery(ORDERS_BY_PERIOD, {
    variables: { period: 'WEEK', storeId: storeId || null, limit: 12.0 },
    skip: !storeId,
  });

  const {
    data: customersByPeriodData,
    loading: loadingCustomersByPeriod,
    error: errorCustomersByPeriod,
  } = useQuery(CUSTOMERS_BY_PERIOD, {
    variables: { period: 'MONTH', storeId: storeId || null, limit: 6.0 },
    skip: !storeId,
  });

  const {
    data: salesByPeriodData,
    loading: loadingSalesByPeriod,
    error: errorSalesByPeriod,
  } = useQuery(SALES_BY_PERIOD, {
    variables: { period: 'MONTH', storeId: storeId || null, limit: 6.0 },
    skip: !storeId,
  });

  const {
    data,
    loading: loadingLeads,
    error: errorLeads,
  } = useQuery(CONTACT_LEADS_BY_STORE, {
    variables: { storeId: storeId || '' },
    skip: !storeId,
  });

  // Log any GraphQL errors
  useEffect(() => {
    if (errorProducts) console.error('Products query error:', errorProducts);
    if (errorActiveUsers) console.error('Active users query error:', errorActiveUsers);
    if (errorMonthlySales) console.error('Monthly sales query error:', errorMonthlySales);
    if (errorConversionRate) console.error('Conversion rate query error:', errorConversionRate);
    if (errorLeads) console.error('Leads query error:', errorLeads);
  }, [errorProducts, errorActiveUsers, errorMonthlySales, errorConversionRate, errorLeads]);

  const leads: Customer[] =
    data?.contactLeadsByStore?.map((lead: any) => ({
      id: lead.id,
      name: `${lead.firstName} ${lead.lastName}`,
      email: lead.email,
      phone: lead.phoneNumber,
      status: 'lead',
      lastContactAt: lead.updatedAt || lead.createdAt,
      totalSpent: 0,
      ordersCount: 0,
      createdAt: lead.createdAt,
    })) || [];

  useEffect(() => {
    // Build KPIs and chart data from real query results when available
    const builtKPIs: KPI = {
      totalCustomers: 0,
      totalOrders: 0,
      monthlyRevenue: monthlySalesData?.monthlySales?.totalSales || mockKPIs.monthlyRevenue,
      conversionRate: conversionRateData?.conversionRate?.rate || mockKPIs.conversionRate,
      averageOrderValue:
        monthlySalesData?.monthlySales?.averageOrderValue || mockKPIs.averageOrderValue,
    } as KPI;

    setKpis(builtKPIs);

    const builtChartData: ChartData = {
      customersGrowth:
        (customersByPeriodData?.customersByPeriod || []).map((c: any) => ({
          date: c.periodLabel,
          customers: c.count,
        })) || [],
      salesByPeriod:
        (salesByPeriodData?.salesByPeriod || []).map((s: any) => ({
          date: s.periodLabel,
          totalSales: s.totalSales,
          totalOrders: s.totalOrders,
          averageOrderValue: s.averageOrderValue,
        })) || [],
      ordersByPeriod:
        (ordersByPeriodData?.ordersByPeriod && ordersByPeriodData.ordersByPeriod.length
          ? ordersByPeriodData.ordersByPeriod.map((o: any) => ({
              date: o.periodLabel,
              count: o.count,
            }))
          : (salesByPeriodData?.salesByPeriod || []).map((s: any) => ({
              date: s.periodLabel,
              count: s.totalOrders || 0,
            }))) || [],
    } as any;

    setChartData(builtChartData);
  }, [
    customersByPeriodData,
    salesByPeriodData,
    ordersByPeriodData,
    monthlySalesData,
    conversionRateData,
  ]);

  // Determinar si hay carga en alguna de las queries
  const isLoading =
    loadingProducts ||
    loadingActiveUsers ||
    loadingMonthlySales ||
    loadingConversionRate ||
    loadingLeads ||
    (typeof loadingOrdersByPeriod !== 'undefined' && loadingOrdersByPeriod) ||
    (typeof loadingCustomersByPeriod !== 'undefined' && loadingCustomersByPeriod) ||
    (typeof loadingSalesByPeriod !== 'undefined' && loadingSalesByPeriod);

  // Show loading while checking user data
  if (!user) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  // Show message if no store exists
  if (user && !storeId) {
    return (
      <div className="space-y-6">
        {/* Encabezado */}
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">Panel de Insights</h1>
          <p className="text-gray-600 dark:text-gray-400">
            Primero necesitas crear tu tienda para ver las métricas
          </p>
        </div>

        {/* Message Card */}
        <div className="bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800 rounded-lg p-6">
          <div className="flex items-center justify-between">
            <div>
              <h3 className="text-lg font-semibold text-blue-900 dark:text-blue-100 mb-2">
                ¡Bienvenido a Emprendy.ai!
              </h3>
              <p className="text-blue-700 dark:text-blue-300 mb-4">
                Para comenzar a ver tus métricas e insights, primero necesitas crear tu tienda
                online.
              </p>
              <button
                onClick={() => router.push('/dashboard/store/new')}
                className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-md transition-colors"
              >
                Crear mi tienda
              </button>
            </div>
            <div className="hidden md:block">
              <Package className="h-16 w-16 text-blue-400" />
            </div>
          </div>
        </div>

        {/* Demo KPI Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          <KPICard
            title="Total de Productos"
            value={0}
            icon={Package}
            trend={{ value: 0, isPositive: true }}
            loading={false}
          />
          <KPICard
            title="Usuarios Activos"
            value={0}
            icon={Users}
            trend={{ value: 0, isPositive: true }}
            loading={false}
          />
          <KPICard
            title="Ventas Mensuales"
            value="$0"
            icon={DollarSign}
            trend={{ value: 0, isPositive: true }}
            loading={false}
          />
          <KPICard
            title="Tasa de Conversión"
            value="0%"
            icon={TrendingUp}
            trend={{ value: 0, isPositive: true }}
            loading={false}
          />
        </div>
      </div>
    );
  }

  const getStatusBadge = (status: string) => {
    const styles = {
      lead: 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-300',
      customer: 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-300',
      vip: 'bg-purple-100 text-purple-800 dark:bg-purple-900 dark:text-purple-300',
    };

    const etiquetas: Record<string, string> = {
      lead: 'LEAD',
      customer: 'CLIENTE',
      vip: 'VIP',
    };

    return (
      <span
        className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${styles[status as keyof typeof styles]}`}
      >
        {etiquetas[status] || status.toUpperCase()}
      </span>
    );
  };

  return (
    <div className="space-y-6">
      {/* Encabezado */}
      <div>
        <h1 className="text-2xl font-bold text-gray-900 dark:text-white">Panel de Insights</h1>
        <p className="text-gray-600 dark:text-gray-400">
          Vista general del rendimiento de tu tienda y análisis de clientes
        </p>
      </div>

      {/* Tarjetas KPI actualizadas con los nuevos queries */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {/* Total de Productos */}
        <KPICard
          title="Total de Productos"
          value={totalProductsData?.totalProducts || 0}
          icon={Package}
          trend={{ value: 0, isPositive: true }} // Puedes ajustar este trend según necesites
          loading={loadingProducts}
        />

        {/* Usuarios Activos */}
        <KPICard
          title="Usuarios Activos"
          value={activeUsersData?.activeUsers?.count || 0}
          icon={Users}
          trend={{
            value: activeUsersData?.activeUsers?.percentageChange || 0,
            isPositive: (activeUsersData?.activeUsers?.percentageChange || 0) >= 0,
          }}
          loading={loadingActiveUsers}
        />

        {/* Ventas Mensuales */}
        <KPICard
          title="Ventas Mensuales"
          value={
            monthlySalesData?.monthlySales
              ? `$${monthlySalesData.monthlySales.totalSales.toLocaleString()}`
              : '$0'
          }
          icon={DollarSign}
          trend={{
            value: monthlySalesData?.monthlySales?.percentageChange || 0,
            isPositive: (monthlySalesData?.monthlySales?.percentageChange || 0) >= 0,
          }}
          loading={loadingMonthlySales}
        />

        {/* Órdenes - último periodo */}
        <KPICard
          title="Órdenes (último periodo)"
          value={(() => {
            const orders = ordersByPeriodData?.ordersByPeriod || [];
            const latest = orders.length ? orders[orders.length - 1] : null;
            return latest ? latest.count : 0;
          })()}
          icon={ShoppingCart}
          trend={{
            value: (() => {
              const orders = ordersByPeriodData?.ordersByPeriod || [];
              if (orders.length < 2) return 0;
              const latest = orders[orders.length - 1];
              const prev = orders[orders.length - 2];
              if (!prev || !prev.count) return 0;
              const diff = latest.count - prev.count;
              return Math.round((diff / Math.max(prev.count, 1)) * 100 * 10) / 10; // one decimal
            })(),
            isPositive: (() => {
              const orders = ordersByPeriodData?.ordersByPeriod || [];
              if (orders.length < 2) return true;
              const latest = orders[orders.length - 1];
              const prev = orders[orders.length - 2];
              return latest.count - (prev?.count || 0) >= 0;
            })(),
          }}
          description={(() => {
            const orders = ordersByPeriodData?.ordersByPeriod || [];
            const latest = orders.length ? orders[orders.length - 1] : null;
            return latest?.periodLabel || '';
          })()}
          loading={loadingOrdersByPeriod}
        />

        {/* Órdenes Totales (mantenida como ejemplo adicional) */}
        {/* <KPICard
          title="Órdenes Totales"
          value={kpis?.totalOrders || 0}
          icon={ShoppingCart}
          trend={{ value: 8.2, isPositive: true }}
          loading={isLoading}
        /> */}
      </div>

      {/* Gráficas */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {chartData ? (
          <>
            <LineChart
              data={chartData.customersGrowth}
              xKey="date"
              yKey="customers"
              title="Crecimiento de Clientes"
              color="#22c55e"
            />
            <BarChart
              data={chartData.ordersByPeriod || []}
              xKey="date"
              yKey="count"
              title="Órdenes por periodo"
              color="#3b82f6"
            />
          </>
        ) : (
          <>
            <div className="bg-white dark:bg-gray-800 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700 p-6">
              <div className="animate-pulse h-64 bg-gray-300 dark:bg-gray-600 rounded"></div>
            </div>
            <div className="bg-white dark:bg-gray-800 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700 p-6">
              <div className="animate-pulse h-64 bg-gray-300 dark:bg-gray-600 rounded"></div>
            </div>
          </>
        )}
      </div>

      {/* Tabla Leads estilo pro */}
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow border border-gray-200 dark:border-gray-700">
        <div className="px-6 py-4 border-b border-gray-200 dark:border-gray-700 flex items-center justify-between">
          <h3 className="text-lg font-semibold text-gray-900 dark:text-white">Leads Recientes</h3>
        </div>
        <div className="overflow-x-auto">
          {loadingLeads ? (
            <div className="p-6 text-center text-gray-500">Cargando leads...</div>
          ) : leads.length === 0 ? (
            <div className="p-6 text-center text-gray-500">No hay leads disponibles.</div>
          ) : (
            <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
              <thead className="bg-gray-50 dark:bg-gray-900">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-300 uppercase tracking-wider">
                    Cliente
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-300 uppercase tracking-wider">
                    Estado
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-300 uppercase tracking-wider">
                    Email
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-300 uppercase tracking-wider">
                    Teléfono
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-300 uppercase tracking-wider">
                    Último Contacto
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
                {leads.map((lead) => (
                  <tr key={lead.id} className="hover:bg-gray-50 dark:hover:bg-gray-700 transition">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm font-medium text-gray-900 dark:text-white">
                        {lead.name}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">{getStatusBadge(lead.status)}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500 dark:text-gray-400">
                      {lead.email}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500 dark:text-gray-400">
                      {lead.phone}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500 dark:text-gray-400">
                      {new Date(lead.lastContactAt).toLocaleDateString()}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import {
  Search,
  Filter,
  Download,
  Eye,
  ChevronLeft,
  ChevronRight,
  Package,
  Truck,
  CreditCard,
  DollarSign,
  Wallet,
} from 'lucide-react';
import { Order } from '@/lib/schemas/dashboard';
import { useDashboardUIStore } from '@/lib/store/dashboard';
import { gql, useQuery } from '@apollo/client';
import { useSessionStore } from '@/lib/store/dashboard';
import { useParams } from 'next/navigation';
import ShipmentFormModal from '@/app/components/ShipmentFormModal';
import { Shipment } from '@/app/utils/types/types';
import { GET_PAYMENTS } from '@/lib/graphql/queries';

const GET_ORDERS_BY_STORE = gql`
  query OrdersByStore($storeId: String!) {
    ordersByStore(storeId: $storeId) {
      id
      status
      total
      subtotal
      tax
      shipping
      createdAt
      userName
      items {
        id
        productName
        quantity
        price
        product {
          name
          images {
            url
          }
        }
      }
      address {
        name
        street
      }
      store {
        id
        name
        logoUrl
      }
    }
  }
`;

const PAGINATED_ORDERS = gql`
  query PaginatedOrders($pagination: PaginationInput!) {
    paginatedOrders(pagination: $pagination) {
      items {
        id
        status
        total
        subtotal
        tax
        shipping
        createdAt
        userName
        items {
          id
          productName
          quantity
          price
          product {
            name
            images {
              url
            }
          }
        }
        address {
          name
          street
        }
        store {
          id
          name
          logoUrl
        }
      }
      page
      pageSize
      total
    }
  }
`;

const GET_ALL_SHIPMENTS = gql`
  query GetAllShipments {
    shipments {
      id
      orderId
      provider
      trackingNumber
      shippingCost
      totalWeight
      shippedAt
      estimatedDeliveryAt
      status
      trackingUrl
      notes
      createdAt
      updatedAt
    }
  }
`;

export default function OrderPage() {
  const [pedidos, setPedidos] = useState<Order[]>([]);
  const [pedidosFiltrados, setPedidosFiltrados] = useState<Order[]>([]);
  const [busqueda, setBusqueda] = useState('');
  const [filtroEstado, setFiltroEstado] = useState('all');
  const [filtroProveedor, setFiltroProveedor] = useState('all');
  const [currentPage, setCurrentPage] = useState(1);
  const [expandedOrders, setExpandedOrders] = useState<Set<string>>(new Set());
  const [shipmentModalOpen, setShipmentModalOpen] = useState(false);
  const [selectedOrderIdForShipment, setSelectedOrderIdForShipment] = useState<string>('');
  const [currentShipment, setCurrentShipment] = useState<Shipment | null>(null);
  const pageSize = 10;
  const params = useParams();

  const { setSelectedOrderId, setOrderDrawerOpen } = useDashboardUIStore();
  const { currentStore } = useSessionStore();

  // Obtener el storeId correctamente
  const urlStoreId = params?.slug as string;
  const storeId = urlStoreId || currentStore?.id;
  const userData = JSON.parse(localStorage.getItem('user') || '{}');

  const isAdmin =
    userData?.role === 'ADMIN' ||
    (Array.isArray(userData?.roles) && userData.roles.includes('ADMIN'));

  const {
    data: storeData,
    loading: storeLoading,
    error: storeError,
    refetch: refetchStoreData,
  } = useQuery(GET_ORDERS_BY_STORE, {
    variables: { storeId: userData?.storeId || '' },
    skip: isAdmin || !storeId,
    fetchPolicy: 'network-only',
  });

  const {
    data: adminData,
    loading: adminLoading,
    error: adminError,
    refetch: refetchAdminData,
  } = useQuery(PAGINATED_ORDERS, {
    variables: {
      pagination: { page: currentPage, pageSize },
      // Enviar storeId de forma opcional: usar el storeId del usuario (no el slug de la URL)
      // Si el usuario tiene asociado un storeId, lo enviamos para filtrar por esa tienda.
      storeId: userData?.storeId || currentStore?.id || undefined,
    },

    fetchPolicy: 'network-only',
  });

  const {
    data: shipmentsData,
    loading: shipmentsLoading,
    refetch: refetchShipments,
  } = useQuery(GET_ALL_SHIPMENTS, {
    fetchPolicy: 'network-only',
  });

  // Fetch payments data
  const {
    data: paymentsData,
    loading: paymentsLoading,
    error: paymentsError,
  } = useQuery(GET_PAYMENTS, {
    variables: {
      pagination: { skip: 0, take: 100 },
    },
    skip: !storeId && !isAdmin,
    fetchPolicy: 'network-only',
  });

  const data = isAdmin ? adminData : storeData;
  const loading = storeLoading || adminLoading;
  const error = storeError || adminError;

  // Buscar envío existente cuando se selecciona una orden
  useEffect(() => {
    if (selectedOrderIdForShipment && shipmentsData?.shipments) {
      const existingShipment = shipmentsData.shipments.find(
        (s: Shipment) => s.orderId === selectedOrderIdForShipment
      );
      setCurrentShipment(existingShipment || null);
    } else if (!selectedOrderIdForShipment) {
      setCurrentShipment(null);
    }
  }, [selectedOrderIdForShipment, shipmentsData]);

  useEffect(() => {
    if (!isAdmin && data?.ordersByStore) {
      const mapped: Order[] = data.ordersByStore.map((o: any) => ({
        id: o.id,
        storeId: o.store?.id || storeId,
        customerId: '',
        customerName: o.userName || (o.address?.name ?? 'Cliente'),
        customerEmail: '',
        items: (o.items || []).map((it: any) => ({
          id: it.id,
          name: it.productName || it.product?.name || '',
          quantity: it.quantity,
          price: it.price,
          product: it.product
            ? {
                name: it.product.name,
                images: it.product.images || [],
              }
            : null,
        })),
        total: o.total || 0,
        status: (o.status || 'pending').toLowerCase(),
        createdAt: o.createdAt,
        updatedAt: o.updatedAt || o.createdAt,
      }));

      setPedidos(mapped);
      setPedidosFiltrados(mapped);
    }

    if (isAdmin && data?.paginatedOrders?.items) {
      const mapped: Order[] = data.paginatedOrders.items.map((o: any) => ({
        id: o.id,
        storeId: o.store?.id || storeId,
        customerId: '',
        customerName: o.userName || (o.address?.name ?? 'Cliente'),
        customerEmail: '',
        items: (o.items || []).map((it: any) => ({
          id: it.id,
          name: it.productName || it.product?.name || '',
          quantity: it.quantity,
          price: it.price,
          product: it.product
            ? {
                name: it.product.name,
                images: it.product.images || [],
              }
            : null,
        })),
        total: o.total || 0,
        status: (o.status || 'pending').toLowerCase(),
        createdAt: o.createdAt,
        updatedAt: o.updatedAt || o.createdAt,
      }));

      setPedidos(mapped);
      setPedidosFiltrados(mapped);
    }
  }, [data, storeId, isAdmin]);

  // Get unique providers from payments data
  const uniqueProviders = React.useMemo(() => {
    if (!paymentsData?.payments) return [];
    const methods = new Set<string>();
    const paymentsList = paymentsData.payments.filter((p: any) =>
      storeId ? p.store?.id === storeId : true
    );
    paymentsList.forEach((payment: any) => {
      if (payment.provider) {
        methods.add(payment.provider);
      }
    });
    return Array.from(methods);
  }, [paymentsData, storeId]);

  // Create a map of orderId to provider
  const orderProviderMap = React.useMemo(() => {
    if (!paymentsData?.payments) return new Map<string, string>();
    const map = new Map<string, string>();
    const paymentsList = paymentsData.payments.filter((p: any) =>
      storeId ? p.store?.id === storeId : true
    );
    paymentsList.forEach((payment: any) => {
      if (payment.order?.id && payment.provider) {
        map.set(payment.order.id, payment.provider);
      }
    });
    return map;
  }, [paymentsData, storeId]);

  useEffect(() => {
    let filtrados = pedidos;

    if (busqueda) {
      filtrados = filtrados.filter(
        (order) =>
          order.customerName.toLowerCase().includes(busqueda.toLowerCase()) ||
          order.customerEmail.toLowerCase().includes(busqueda.toLowerCase()) ||
          order.id.toLowerCase().includes(busqueda.toLowerCase())
      );
    }

    if (filtroEstado !== 'all') {
      filtrados = filtrados.filter((order) => order.status === filtroEstado);
    }

    if (filtroProveedor !== 'all') {
      filtrados = filtrados.filter((order) => {
        const provider = orderProviderMap.get(order.id);
        return provider === filtroProveedor;
      });
    }

    setPedidosFiltrados(filtrados);
    setCurrentPage(1);
  }, [pedidos, busqueda, filtroEstado, filtroProveedor, orderProviderMap]);

  const totalPages =
    isAdmin && adminData?.paginatedOrders?.total
      ? Math.ceil(adminData.paginatedOrders.total / pageSize)
      : Math.ceil(pedidosFiltrados.length / pageSize);

  const paginatedOrders = isAdmin
    ? pedidosFiltrados
    : pedidosFiltrados.slice((currentPage - 1) * pageSize, currentPage * pageSize);

  const handlePageChange = (page: number) => {
    setCurrentPage(page);
  };

  const toggleOrderExpansion = (orderId: string) => {
    const newExpanded = new Set(expandedOrders);
    if (newExpanded.has(orderId)) {
      newExpanded.delete(orderId);
    } else {
      newExpanded.add(orderId);
    }
    setExpandedOrders(newExpanded);
  };

  const obtenerBadgeEstado = (estado: string) => {
    const estilos: Record<string, string> = {
      pending: 'bg-yellow-900/30 text-yellow-300 border-yellow-700',
      confirmed: 'bg-green-900/30 text-green-300 border-green-700',
      processing: 'bg-blue-900/30 text-blue-300 border-blue-700',
      shipped: 'bg-purple-900/30 text-purple-300 border-purple-700',
      delivered: 'bg-green-900/30 text-green-300 border-green-700',
      cancelled: 'bg-red-900/30 text-red-300 border-red-700',
    };

    const labels: Record<string, string> = {
      pending: 'Pendiente',
      confirmed: 'Confirmado',
      processing: 'Procesando',
      shipped: 'Enviado',
      delivered: 'Entregado',
      cancelled: 'Cancelado',
    };

    const key = (estado || '').toLowerCase();

    return (
      <span
        className={`px-3 py-1 text-xs font-semibold rounded-full border ${estilos[key] || estilos.pending}`}
      >
        {labels[key] || estado.charAt(0).toUpperCase() + estado.slice(1)}
      </span>
    );
  };

  const verPedido = (idPedido: string) => {
    setSelectedOrderId(idPedido);
    setOrderDrawerOpen(true);
  };

  const exportarCSV = () => {
    const csvContent = [
      ['ID Pedido', 'Cliente', 'Correo', 'Total', 'Estado', 'Fecha'].join(','),
      ...pedidosFiltrados.map((order) =>
        [
          order.id,
          order.customerName,
          order.customerEmail,
          order.total,
          // translate status for export
          (function (s: string) {
            const map: Record<string, string> = {
              pending: 'Pendiente',
              confirmed: 'Confirmado',
              processing: 'Procesando',
              shipped: 'Enviado',
              delivered: 'Entregado',
              cancelled: 'Cancelado',
            };
            return map[(s || '').toLowerCase()] || s;
          })(order.status),
          new Date(order.createdAt).toLocaleDateString(),
        ].join(',')
      ),
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'pedidos.csv';
    a.click();
    window.URL.revokeObjectURL(url);
  };

  if (loading) {
    return (
      <div className="space-y-6">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
          <div>
            <h1 className="text-2xl font-bold text-white">Pedidos</h1>
            <p className="text-gray-400">Cargando pedidos...</p>
          </div>
        </div>
        <div className="animate-pulse space-y-4 p-6">
          {[...Array(5)].map((_, i) => (
            <div key={i} className="flex space-x-4">
              <div className="h-4 bg-gray-700 rounded w-1/6"></div>
              <div className="h-4 bg-gray-700 rounded w-1/4"></div>
              <div className="h-4 bg-gray-700 rounded w-1/6"></div>
              <div className="h-4 bg-gray-700 rounded w-1/6"></div>
              <div className="h-4 bg-gray-700 rounded w-1/6"></div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="space-y-6">
        <div className="bg-red-900/20 border border-red-700 rounded-lg p-4">
          <h2 className="text-lg font-semibold text-red-300">Error</h2>
          <p className="text-red-400">Error al cargar los pedidos: {error.message}</p>
        </div>
      </div>
    );
  }

  if (
    !storeId &&
    userData.role !== 'ADMIN' &&
    !(Array.isArray(userData?.roles) && userData.roles.includes('ADMIN'))
  ) {
    return (
      <div className="space-y-6">
        <div className="bg-yellow-900/20 border border-yellow-700 rounded-lg p-4">
          <h2 className="text-lg font-semibold text-yellow-300">Tienda no seleccionada</h2>
          <p className="text-yellow-400">No se ha seleccionado una tienda.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white">Pedidos</h1>
          <p className="text-gray-400">Administra y rastrea los pedidos de tu tienda</p>
          <p className="text-sm text-gray-500">Mostrando {pedidosFiltrados.length} pedidos</p>
        </div>

        <button
          onClick={exportarCSV}
          disabled={pedidosFiltrados.length === 0}
          className="inline-flex items-center px-4 py-2 bg-fourth-base text-black rounded-lg hover:bg-fourth-base/90 transition-colors disabled:opacity-50"
        >
          <Download className="h-4 w-4 mr-2" />
          Exportar CSV
        </button>
      </div>

      {/* Search and Filters */}
      <div className="flex flex-col lg:flex-row gap-4">
        <div className="flex-1 relative">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
          <input
            type="text"
            value={busqueda}
            onChange={(e) => setBusqueda(e.target.value)}
            placeholder="Buscar por cliente, email o ID de orden..."
            className="w-full pl-10 pr-3 py-3 border border-gray-600 rounded-lg bg-gray-800 text-white focus:ring-2 focus:ring-fourth-base focus:border-fourth-base transition-all placeholder-gray-400"
          />
        </div>

        <div className="flex items-center gap-2">
          <Filter className="w-4 h-4 text-gray-400" />
          <select
            value={filtroEstado}
            onChange={(e) => setFiltroEstado(e.target.value)}
            className="px-3 py-3 border border-gray-600 rounded-lg bg-gray-800 text-white focus:ring-2 focus:ring-fourth-base focus:border-fourth-base"
          >
            <option value="all">Todos los estados</option>
            <option value="pending">Pendiente</option>
            <option value="confirmed">Confirmado</option>
            <option value="processing">Procesando</option>
            <option value="shipped">Enviado</option>
            <option value="delivered">Entregado</option>
            <option value="cancelled">Cancelado</option>
          </select>
        </div>
      </div>

      {/* Payment Method Tabs (simple, below search) */}
      <div className="mt-4">
        <div className="bg-transparent rounded-lg">
          <div className="flex items-center space-x-6 overflow-auto scrollbar-hide">
            <button
              onClick={() => setFiltroProveedor('all')}
              className={`relative pb-3 text-sm font-medium transition-colors whitespace-nowrap ${
                filtroProveedor === 'all' ? 'text-fourth-base' : 'text-gray-400'
              }`}
            >
              <span>Todos</span>
              <span
                className={`absolute left-0 right-0 mx-auto bottom-0 h-0.5 rounded-full transition-all ${
                  filtroProveedor === 'all' ? 'bg-fourth-base w-10' : 'bg-transparent w-0'
                }`}
              />
            </button>

            {uniqueProviders.map((provider) => {
              const count = pedidos.filter(
                (order) => orderProviderMap.get(order.id) === provider
              ).length;

              const label = (p: string) => {
                const map: Record<string, string> = {
                  woompi: 'Wompi',
                  mercadopago: 'MercadoPago',
                  epayco: 'ePayco',
                };
                return map[p.toLowerCase()] || p;
              };

              return (
                <button
                  key={provider}
                  onClick={() => setFiltroProveedor(provider)}
                  className={`relative pb-3 text-sm font-medium transition-colors whitespace-nowrap ${
                    filtroProveedor === provider ? 'text-fourth-base' : 'text-gray-400'
                  }`}
                >
                  <span>
                    {label(provider)} {count > 0 ? `(${count})` : ''}
                  </span>
                  <span
                    className={`absolute left-0 right-0 mx-auto bottom-0 h-0.5 rounded-full transition-all ${
                      filtroProveedor === provider ? 'bg-fourth-base w-10' : 'bg-transparent w-0'
                    }`}
                  />
                </button>
              );
            })}
          </div>
        </div>
      </div>

      {/* Desktop Table */}
      <div className="hidden lg:block bg-gray-900 border border-gray-700 rounded-xl overflow-hidden shadow-sm">
        <table className="min-w-full divide-y divide-gray-700">
          <thead className="bg-gray-800">
            <tr>
              <th className="px-6 py-4 text-left text-xs font-semibold text-gray-300 uppercase">
                Productos
              </th>
              <th className="px-6 py-4 text-left text-xs font-semibold text-gray-300 uppercase">
                Cliente
              </th>
              <th className="px-6 py-4 text-left text-xs font-semibold text-gray-300 uppercase">
                Total
              </th>
              <th className="px-6 py-4 text-left text-xs font-semibold text-gray-300 uppercase">
                Estado
              </th>
              <th className="px-6 py-4 text-left text-xs font-semibold text-gray-300 uppercase">
                Fecha
              </th>
              <th className="px-6 py-4 text-right text-xs font-semibold text-gray-300 uppercase">
                Acciones
              </th>
            </tr>
          </thead>
          <tbody className="bg-gray-900 divide-y divide-gray-800">
            {paginatedOrders.map((order) => (
              <React.Fragment key={order.id}>
                <tr className="hover:bg-gray-800 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center space-x-3">
                      {order.items.slice(0, 2).map((item: any, index) => {
                        const imageKey = item?.product?.images?.[0]?.url;
                        const imageUrl = imageKey
                          ? `https://emprendyup-images.s3.us-east-1.amazonaws.com/${imageKey}`
                          : '/assets/default-product.jpg';

                        return (
                          <div key={item.id} className="relative">
                            <div className="relative w-12 h-12 rounded-lg overflow-hidden bg-gray-700 border border-gray-600">
                              <img
                                src={imageUrl}
                                alt={item.name}
                                className="w-full h-full object-cover"
                                onError={(e) => {
                                  e.currentTarget.src = '/assets/default-product.jpg';
                                }}
                              />
