                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end space-x-2">
                      <button
                        onClick={() => {
                          setSelectedOrderIdForShipment(order.id);
                          setShipmentModalOpen(true);
                        }}
                        className="p-2 text-gray-400 hover:bg-gray-800 hover:text-fourth-base rounded-lg transition-colors"
                        title="Gestionar envío"
                      >
                        <Truck className="w-4 h-4" />
                      </button>
                      <button
                        onClick={() => toggleOrderExpansion(order.id)}
                        className="p-2 text-gray-400 hover:bg-gray-800 hover:text-white rounded-lg transition-colors"
                        title="Ver detalles"
                      >
                        <Eye className="w-4 h-4" />
                      </button>
                    </div>
                  </td>
                </tr>
                {expandedOrders.has(order.id) && (
                  <tr key={order.id + '-expanded'}>
                    <td colSpan={6} className="px-6 py-4 bg-gray-800">
                      <div className="space-y-4">
                        <div>
                          <h4 className="text-sm font-semibold text-white mb-3">
                            Productos ({order.items.length})
                          </h4>
                          <div className="grid gap-3 md:grid-cols-2">
                            {order.items.map((item: any) => {
                              const imageKey = item?.product?.images?.[0]?.url;
                              const imageUrl = imageKey
                                ? `https://emprendyup-images.s3.us-east-1.amazonaws.com/${imageKey}`
                                : '/assets/default-product.jpg';

                              return (
                                <div
                                  key={item.id}
                                  className="flex items-center space-x-3 p-3 bg-gray-700 rounded-lg border border-gray-600"
                                >
                                  <div className="flex-shrink-0">
                                    <div className="relative w-12 h-12 rounded-lg overflow-hidden bg-gray-600 border border-gray-500">
                                      <img
                                        src={imageUrl}
                                        alt={item.name}
                                        className="w-full h-full object-cover"
                                        onError={(e) => {
                                          e.currentTarget.src = '/assets/default-product.jpg';
                                        }}
                                      />
                                    </div>
                                  </div>
                                  <div className="flex-grow min-w-0">
                                    <p className="text-sm font-medium text-white truncate">
                                      {item.name}
                                    </p>
                                    <div className="flex items-center justify-between mt-1">
                                      <span className="text-xs text-gray-400">
                                        Cantidad:{' '}
                                        <span className="font-semibold text-white">
                                          {item.quantity}
                                        </span>
                                      </span>
                                      <div className="text-right">
                                        <div className="text-sm font-semibold text-white">
                                          ${(item.price * item.quantity).toLocaleString('es-CO')}
                                        </div>
                                        <div className="text-xs text-gray-400">
                                          ${item.price.toLocaleString('es-CO')} c/u
                                        </div>
                                      </div>
                                    </div>
                                  </div>
                                </div>
                              );
                            })}
                          </div>
                        </div>
                      </div>
                    </td>
                  </tr>
                )}
              </React.Fragment>
            ))}
          </tbody>
        </table>
      </div>

      {/* Mobile Cards */}
      <div className="lg:hidden space-y-4">
        {paginatedOrders.map((order) => (
          <div
            key={order.id}
            className="p-4 bg-gray-800 rounded-lg border border-gray-700 shadow-sm"
          >
            <div className="flex items-center justify-between mb-3">
              <div>
                <h3 className="text-sm font-medium text-white">#{order.id}</h3>
                <p className="text-sm text-gray-400">{order.customerName}</p>
              </div>
              {obtenerBadgeEstado(order.status)}
            </div>

            <div className="flex items-center justify-between mb-3">
              <div className="text-sm text-gray-400">
                <p>
                  <strong className="text-white">Total:</strong> $
                  {order.total.toLocaleString('es-CO')}
                </p>
                <p>
                  <strong className="text-white">Fecha:</strong>{' '}
                  {new Date(order.createdAt).toLocaleDateString('es-CO')}
                </p>
              </div>
            </div>

            {/* Items con imágenes */}
            <div className="mt-3 space-y-3">
              {order.items.map((item: any) => {
                const imageKey = item?.product?.images?.[0]?.url;
                const imageUrl = imageKey
                  ? `https://emprendyup-images.s3.us-east-1.amazonaws.com/${imageKey}`
                  : '/assets/default-product.jpg';

                return (
                  <div
                    key={item.id}
                    className="flex items-center space-x-3 p-3 bg-gray-700 rounded-lg border border-gray-600"
                  >
                    <div className="flex-shrink-0">
                      <div className="relative w-12 h-12 rounded-lg overflow-hidden bg-gray-600 border border-gray-500">
                        <img
                          src={imageUrl}
                          alt={item.name}
                          className="w-full h-full object-cover"
                          onError={(e) => {
                            e.currentTarget.src = '/assets/default-product.jpg';
                          }}
                        />
                      </div>
                    </div>
                    <div className="flex-grow min-w-0">
                      <p className="text-sm font-medium text-white truncate">{item.name}</p>
                      <div className="flex items-center justify-between mt-1">
                        <span className="text-xs text-gray-400">
                          Cantidad:{' '}
                          <span className="font-semibold text-white">{item.quantity}</span>
                        </span>
                        <div className="text-right">
                          <div className="text-sm font-semibold text-white">
                            ${(item.price * item.quantity).toLocaleString('es-CO')}
                          </div>
                          <div className="text-xs text-gray-400">
                            ${item.price.toLocaleString('es-CO')} c/u
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>

            <div className="mt-3 flex justify-end gap-2">
              <button
                onClick={() => {
                  setSelectedOrderIdForShipment(order.id);
                  setShipmentModalOpen(true);
                }}
                className="px-3 py-2 bg-gray-700 text-white rounded-lg text-sm hover:bg-gray-600 transition-colors flex items-center gap-1"
              >
                <Truck className="w-4 h-4" />
                Envío
              </button>
              <button
                onClick={() => verPedido(order.id)}
                className="px-3 py-2 bg-fourth-base text-black rounded-lg text-sm hover:bg-fourth-base/90 transition-colors"
              >
                Ver Detalles
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* Empty State */}
      {pedidosFiltrados.length === 0 && !loading && (
        <div className="text-center py-12">
          <div className="w-16 h-16 mx-auto mb-4 bg-gray-800 rounded-full flex items-center justify-center">
            <Package className="w-6 h-6 text-gray-400" />
          </div>
          <h3 className="text-lg font-medium text-white mb-2">
            {busqueda || filtroEstado !== 'all'
              ? 'No se encontraron pedidos'
              : 'No hay pedidos aún'}
          </h3>
          <p className="text-gray-400">
            {busqueda || filtroEstado !== 'all'
              ? 'Prueba ajustando tus filtros para ver más resultados.'
              : 'Los pedidos realizados por los clientes aparecerán aquí.'}
          </p>
        </div>
      )}

      {/* Pagination */}
      {pedidosFiltrados.length > pageSize && (
        <div className="flex items-center justify-between border-t border-gray-700 pt-4">
          <div className="text-sm text-gray-400">
            Mostrando {Math.min((currentPage - 1) * pageSize + 1, pedidosFiltrados.length)} a{' '}
            {Math.min(currentPage * pageSize, pedidosFiltrados.length)} de {pedidosFiltrados.length}{' '}
            pedidos
          </div>
          <div className="flex items-center space-x-2">
            <button
              onClick={() => handlePageChange(currentPage - 1)}
              disabled={currentPage === 1}
              className="flex items-center px-3 py-2 rounded-lg border border-gray-600 bg-gray-800 text-white text-sm disabled:opacity-50 hover:bg-gray-700 transition-colors"
            >
              <ChevronLeft className="w-4 h-4 mr-1" />
              Anterior
            </button>
            <span className="px-3 py-2 text-sm text-gray-400">
              Página {currentPage} de {totalPages}
            </span>
            <button
              onClick={() => handlePageChange(currentPage + 1)}
              disabled={currentPage === totalPages}
              className="flex items-center px-3 py-2 rounded-lg border border-gray-600 bg-gray-800 text-white text-sm disabled:opacity-50 hover:bg-gray-700 transition-colors"
            >
              Siguiente
              <ChevronRight className="w-4 h-4 ml-1" />
            </button>
          </div>
        </div>
      )}

      {/* Shipment Modal */}
      <ShipmentFormModal
        key={selectedOrderIdForShipment || 'new'}
        isOpen={shipmentModalOpen}
        onClose={() => {
          setCurrentShipment(null);
          setSelectedOrderIdForShipment('');
          setShipmentModalOpen(false);
        }}
        orderId={selectedOrderIdForShipment}
        shipment={currentShipment}
        onSuccess={() => {
          // Refetch orders and shipments to get updated data
          if (isAdmin) {
            refetchAdminData();
          } else {
            refetchStoreData();
          }
          refetchShipments();
        }}
      />
    </div>
  );
}

'use client';

import { useState, useEffect, useMemo } from 'react';
import Script from 'next/script';
import { useQuery } from '@apollo/client';
import PricingPlans, { Plan } from '../components/PricingPlans';
import { getUserFromLocalStorage } from '@/lib/utils/localAuth';
import OrderCreationModal from '../components/OrderCreationModal';
import { GET_SUBSCRIPTION_PRODUCTS } from '@/lib/graphql/queries';

interface PlanConfig {
  planId: string;
  amount: number;
  description: string;
  productId?: string;
  features?: string[];
  name?: string;
}

interface EPaycoPlans {
  [key: string]: {
    monthly?: PlanConfig;
    annual?: PlanConfig;
  };
}

declare global {
  interface Window {
    ePayco: any;
  }
}

export default function PlansPage() {
  const [selectedCycle, setSelectedCycle] = useState<'monthly' | 'annual'>('annual');
  const [scriptLoaded, setScriptLoaded] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedPlanData, setSelectedPlanData] = useState<{
    planId: string;
    billingCycle: 'monthly' | 'annual';
    planConfig: any;
  } | null>(null);
  const user = getUserFromLocalStorage();
  const storeId = process.env.NEXT_PUBLIC_DEFAULT_STORE_ID;

  // Fetch subscription products from database
  const {
    data: productsData,
    loading: loadingProducts,
    error: errorProducts,
  } = useQuery(GET_SUBSCRIPTION_PRODUCTS, {
    variables: { storeId },
    skip: !storeId,
  });

  // Get subscription products directly from DB
  const subscriptionProducts = useMemo(() => {
    if (!productsData?.productsByStore?.items) {
      return [];
    }

    const products = productsData.productsByStore.items;

    // Filter only subscription products
    return products.filter((product: any) => {
      const metadata = product.metadata ? JSON.parse(product.metadata) : {};
      return metadata.type === 'subscription' || metadata.isSubscription;
    });
  }, [productsData]);

  // Transform products into Plan[] format for PricingPlans component
  const transformedPlans = useMemo(() => {
    console.log(
      'Building transformedPlans from productsData:',
      productsData?.productsByStore?.items
    );

    const getDefaultFeatures = (planType: string): string[] => {
      const defaultFeatures: { [key: string]: string[] } = {
        basic: [
          'Tienda básica con subdominio .emprendy',
          'CRM básico para gestionar clientes',
          'Plantillas básicas personalizables',
          'Soporte por email',
          'Analytics básicos',
        ],
        pro: [
          'Todo lo incluido en Basic',
          'Chatbot integrado WhatsApp',
          'Automatizaciones de WhatsApp',
          'Agente IA conversacional de ventas',
          'CRM avanzado con automatizaciones',
          'Integración de productos en marketplace',
          'Marketing automation',
        ],
        partner: [
          'Todo lo incluido en Pro',
          'Acceso directo a ferias anticipadas',
          'Prioridad en asesorías personalizadas',
          'Automatización a la medida de procesos',
          'Capacitación continua personalizada',
          'Gestor de cuenta dedicado',
          'Integración APIs personalizadas',
        ],
      };
      return defaultFeatures[planType] || [];
    };

    const getPlanColor = (planType: string): string => {
      const colors: { [key: string]: string } = {
        basic: 'from-blue-400 to-blue-600',
        pro: 'from-purple-500 to-pink-600',
        partner: 'from-emerald-400 to-teal-600',
      };
      return colors[planType] || 'from-gray-400 to-gray-600';
    };

    // Use productsData directly, not filtered subscriptionProducts
    if (!productsData?.productsByStore?.items || productsData.productsByStore.items.length === 0) {
      console.log('No products data available, returning empty array');
      return [];
    }

    const allProducts = productsData.productsByStore.items;
    console.log('Total products from endpoint:', allProducts.length);
    console.log(
      'All product names:',
      allProducts.map((p: any) => p.name)
    );

    // Filter products by selected billing cycle (monthly or annual)
    const filteredProducts = allProducts.filter((product: any) => {
      const productName = product.name.toLowerCase();
      if (selectedCycle === 'annual') {
        // Check for both 'anual' (Spanish) and 'annual' (English)
        return productName.includes('anual') || productName.includes('annual');
      } else {
        // Check for both 'mensual' (Spanish) and 'monthly' (English)
        return productName.includes('mensual') || productName.includes('monthly');
      }
    });

    console.log(`Selected cycle: ${selectedCycle}`);
    console.log(`Filtered products for ${selectedCycle}:`, filteredProducts.length);
    console.log(
      'Filtered product names:',
      filteredProducts.map((p: any) => p.name)
    );

    // Transform each product into a plan card
    const plans = filteredProducts.map((product: any) => {
      const metadata = product.metadata ? JSON.parse(product.metadata) : {};
      const planType = (
        metadata.planType || product.name.toLowerCase().split('-')[0]
      ).toLowerCase();
      const billingCycle =
        metadata.billingCycle ||
        (product.name.toLowerCase().includes('annual') ? 'annual' : 'monthly');
      const displayName = metadata.displayName || product.title || product.name;
      const features = metadata.features || getDefaultFeatures(planType);

      console.log('Transforming product:', product.name, '-> Plan ID:', product.id);

      return {
        id: product.id,
        name: displayName,
        price: product.price.toString(),
        period: billingCycle === 'annual' ? 'año' : 'mes',
        description: product.description || product.title || product.name,
        features: features,
        popular: planType === 'pro',
        color: getPlanColor(planType),
        stripeMonthlyPriceId: product.id,
        stripeAnnualPriceId: product.id,
      };
    });

    // Sort plans by price (ascending order)
    const sortedPlans = plans.sort((a: Plan, b: Plan) => parseFloat(a.price) - parseFloat(b.price));

    console.log('Total transformed plans:', sortedPlans.length);
    return sortedPlans;
  }, [productsData, selectedCycle]);

  useEffect(() => {
    if (errorProducts) {
      console.error('Error loading products:', errorProducts);
    }
    if (productsData) {
      console.log('Products loaded:', productsData.productsByStore?.items);
      console.log('Subscription products:', subscriptionProducts);
      console.log('Transformed plans:', transformedPlans);
    }
  }, [productsData, errorProducts, subscriptionProducts, transformedPlans]);

  // Verificar periódicamente si ePayco está disponible
  useEffect(() => {
    const checkEpayco = () => {
      if (window.ePayco) {
        console.log('ePayco está disponible:', window.ePayco);
        setScriptLoaded(true);
        return true;
      }
      return false;
    };

    // Verificar inmediatamente
    if (checkEpayco()) return;

    // Si no está disponible, verificar cada 500ms hasta 10 segundos
    const interval = setInterval(() => {
      if (checkEpayco()) {
        clearInterval(interval);
      }
    }, 500);

    // Limpiar después de 10 segundos
    const timeout = setTimeout(() => {
      clearInterval(interval);
      if (!window.ePayco) {
        console.error('ePayco script failed to load after 10 seconds');
      }
    }, 10000);

    return () => {
      clearInterval(interval);
      clearTimeout(timeout);
    };
  }, []);

  const handlePlanSelect = async (planId: string, billingCycle: 'monthly' | 'annual') => {
    console.log('Script loaded:', scriptLoaded);
    console.log('window.ePayco:', window.ePayco);
    console.log('Selected plan ID:', planId);

    if (!scriptLoaded || !window.ePayco) {
      console.error('ePayco script not loaded yet');
      alert(
        'El sistema de pagos aún se está cargando. Por favor espera un momento e intenta nuevamente.'
      );
      return;
    }

    try {
      // Find the selected product from all products in productsData
      const allProducts = productsData?.productsByStore?.items || [];
      const selectedProduct = allProducts.find((p: any) => p.id === planId);

      if (!selectedProduct) {
        console.error('Product not found:', planId, 'Available products:', allProducts);
        throw new Error('Plan no encontrado');
      }

      const metadata = selectedProduct.metadata ? JSON.parse(selectedProduct.metadata) : {};
      const productBillingCycle =
        metadata.billingCycle ||
        (selectedProduct.name.toLowerCase().includes('annual') ? 'annual' : 'monthly');

      // Create plan config from product
      const planConfig = {
        planId: selectedProduct.id,
        productId: selectedProduct.id,
        amount: selectedProduct.price,
        description: selectedProduct.description || selectedProduct.title || selectedProduct.name,
        name: metadata.displayName || selectedProduct.title || selectedProduct.name,
        features: metadata.features || [],
      };

      console.log('Selected plan config:', planConfig);

      // Guardar datos del plan seleccionado y abrir modal
      setSelectedPlanData({
        planId,
        billingCycle: productBillingCycle as 'monthly' | 'annual',
        planConfig,
      });
      setIsModalOpen(true);
    } catch (error) {
      console.error('Error al seleccionar el plan:', error);
      alert('Error al seleccionar el plan. Por favor intenta nuevamente.');
    }
  };

  const handleOrderCreated = async (orderId: string, paymentId: string) => {
    console.log('Order created with ID:', orderId);
    console.log('Payment created with ID:', paymentId);

    if (!selectedPlanData) {
      console.error('No plan data available');
      return;
    }

    try {
      const { planConfig } = selectedPlanData;

      // Usar el orderId como referencia
      const reference = orderId;

      // Obtener datos del usuario o usar valores por defecto
      const customerData = {
        name: user?.name || 'Cliente',
        email: user?.email || 'cliente@example.com',
        phone: (user as any)?.phone || '3000000000',
        document: (user as any)?.document || '12345678',
        documentType: (user as any)?.documentType || 'CC',
      };

      // Crear un handler para ePayco sin test mode en la configuración
      const handler = window.ePayco.checkout.configure({
        key: process.env.NEXT_PUBLIC_EPAYCO_PUBLIC_KEY,
        test: true, // Hardcoded para pruebas
      });

      // Datos del checkout - usando el formato correcto de ePayco
      const checkoutData = {
        // Información del comercio
        name: 'Emprendy.ai',
        description: planConfig.description,
        invoice: reference,
        currency: 'cop',
        amount: planConfig.amount,
        tax_base: 0,
        tax: 0,
        country: 'co',
        lang: 'es',

        // Información del cliente - usando formato correcto
        external: false,

        // Datos de facturación
        name_billing: customerData.name,
        address_billing: 'Calle 1 # 1-1',
        type_doc_billing: customerData.documentType,
        mobilephone_billing: customerData.phone,
        number_doc_billing: customerData.document,

        // URLs de respuesta - pasar el orderId como parámetro
        response: `${window.location.origin}/payment/response?orderId=${orderId}`,
        confirmation: `${window.location.origin}/api/payments/epayco/confirmation?orderId=${orderId}`,

        // Método de confirmación
        methodconfirmation: 'post',
      };

      console.log('Opening ePayco checkout with data:', checkoutData);

      // Abrir el checkout de ePayco usando el handler
      handler.open(checkoutData);
    } catch (error) {
      console.error('Error al procesar el pago:', error);
      alert('Error al procesar el pago. Por favor intenta nuevamente.');
    }
  };

  console.log('transformedPlans', transformedPlans, selectedPlanData);
  return (
    <>
      {/* Script de ePayco */}
      <Script
        src="https://checkout.epayco.co/checkout.js"
        strategy="afterInteractive"
        onLoad={() => {
          console.log('Script de ePayco cargado exitosamente');
          setScriptLoaded(true);
        }}
        onError={(error) => {
          console.error('Error cargando el script de ePayco:', error);
          alert('Error cargando el sistema de pagos. Por favor recarga la página.');
        }}
      />

      <div className="min-h-screen bg-slate-900">
        {(user?.planStatus === 'ACTIVE' || user?.membershipLevel || user?.plan) && (
          <div className="rounded-xl bg-green-500/10 p-4 text-green-400 mx-4 my-4">
            🙌 Gracias por confiar en <b>Emprendy.ai</b> y ser parte de la comunidad.
            <br />
            Tu plan actual es <b>{user?.plan || user?.membershipLevel || 'N/A'}</b> (
            {(user as any)?.planPeriod === 'MONTHLY'
              ? 'Mensual'
              : (user as any)?.planPeriod === 'ANNUAL'
                ? 'Anual'
                : '—'}
            ).
          </div>
        )}
        {loadingProducts ? (
          <div className="flex items-center justify-center min-h-screen">
            <div className="text-center space-y-4">
              <div className="w-16 h-16 border-4 border-fourth-base border-t-transparent rounded-full animate-spin mx-auto"></div>
              <p className="text-gray-400">Cargando planes...</p>
            </div>
          </div>
        ) : (
          <>
            <PricingPlans
              mode="landing"
              onPlanSelect={handlePlanSelect}
              selectedCycle={selectedCycle}
              onCycleChange={setSelectedCycle}
              customPlans={transformedPlans}
            />

            {/* Modal de creación de orden */}
            {selectedPlanData && (
              <OrderCreationModal
                isOpen={isModalOpen}
                onClose={() => {
                  setIsModalOpen(false);
                  setSelectedPlanData(null);
                }}
                planId={selectedPlanData.planId}
                onOrderCreated={handleOrderCreated}
                planName={selectedPlanData.planConfig.name || selectedPlanData.planId}
                planAmount={selectedPlanData.planConfig.amount}
                billingCycle={selectedPlanData.billingCycle}
              />
            )}
          </>
        )}
      </div>
    </>
  );
}

'use client';

import { useState, useRef, ChangeEvent } from 'react';
import { Upload, FileText, AlertCircle, CheckCircle, X, Eye, ArrowLeft } from 'lucide-react';
import { useRouter } from 'next/navigation';
import toast from 'react-hot-toast';

interface ImportResult {
  success: boolean;
  totalImported: number;
  totalErrors: number;
  errors?: Array<{
    row: number;
    message: string;
  }>;
  message?: string;
}

interface CSVPreview {
  headers: string[];
  rows: string[][];
}

export default function ImportProductsPage() {
  const router = useRouter();
  const fileInputRef = useRef<HTMLInputElement>(null);
  const userData =
    typeof window !== 'undefined' ? JSON.parse(localStorage.getItem('user') || '{}') : {};

  // Estados
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [importResult, setImportResult] = useState<ImportResult | null>(null);
  const [showPreview, setShowPreview] = useState(false);
  const [csvPreview, setCsvPreview] = useState<CSVPreview | null>(null);
  const [showConfirmDialog, setShowConfirmDialog] = useState(false);
  const [logs, setLogs] = useState<string[]>([]);

  // Constantes
  const MAX_FILE_SIZE = 20 * 1024 * 1024; // 20MB
  const ALLOWED_TYPES = ['.csv', 'text/csv', 'application/vnd.ms-excel'];

  // Función para agregar logs
  const addLog = (message: string) => {
    const timestamp = new Date().toLocaleTimeString();
    setLogs((prev) => [...prev, `[${timestamp}] ${message}`]);
  };

  // Validar archivo
  const validateFile = (file: File): string | null => {
    // Validar tipo
    const fileExtension = file.name.toLowerCase().split('.').pop();
    if (fileExtension !== 'csv' && !ALLOWED_TYPES.includes(file.type)) {
      return 'El archivo debe ser formato CSV';
    }

    // Validar tamaño
    if (file.size > MAX_FILE_SIZE) {
      return `El archivo excede el tamaño máximo de ${MAX_FILE_SIZE / (1024 * 1024)}MB`;
    }

    // Validar que no esté vacío
    if (file.size === 0) {
      return 'El archivo está vacío';
    }

    return null;
  };

  // Leer y previsualizar CSV
  const previewCSV = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const text = e.target?.result as string;
      const lines = text.split('\n').filter((line) => line.trim() !== '');

      if (lines.length === 0) {
        addLog('⚠️ El archivo CSV está vacío');
        return;
      }

      const headers = lines[0].split(',').map((h) => h.trim());
      const rows = lines
        .slice(1, 11) // Primeras 10 filas
        .map((line) => line.split(',').map((cell) => cell.trim()));

      setCsvPreview({ headers, rows });
      setShowPreview(true);
      addLog(
        `✅ Vista previa cargada: ${headers.length} columnas, ${lines.length - 1} filas totales`
      );
    };

    reader.onerror = () => {
      addLog('❌ Error al leer el archivo para vista previa');
      toast.error('Error al leer el archivo');
    };

    reader.readAsText(file);
  };

  // Manejar selección de archivo
  const handleFileSelect = (event: ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    addLog(`📄 Archivo seleccionado: ${file.name}`);

    const validationError = validateFile(file);
    if (validationError) {
      addLog(`❌ ${validationError}`);
      toast.error(validationError);
      setSelectedFile(null);
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
      return;
    }

    setSelectedFile(file);
    setImportResult(null);
    setLogs([]);
    addLog(`✅ Archivo válido: ${(file.size / 1024).toFixed(2)} KB`);

    // Generar vista previa automáticamente
    previewCSV(file);
  };

  // Importar productos
  const handleImport = async () => {
    if (!selectedFile) {
      toast.error('Por favor selecciona un archivo CSV');
      return;
    }

    setShowConfirmDialog(false);
    setIsUploading(true);
    setUploadProgress(0);
    setImportResult(null);

    addLog('🚀 Iniciando importación de productos...');

    try {
      const formData = new FormData();
      formData.append('file', selectedFile);
      // Backend expects storeId and filePath in the body
      const storeId = userData?.storeId || '';
      if (!storeId) {
        throw new Error('No se encontró storeId en localStorage. Por favor inicia sesión.');
      }
      formData.append('storeId', storeId);
      formData.append('filePath', selectedFile.name);

      // Simular progreso (en producción, usar XMLHttpRequest para progreso real)
      const progressInterval = setInterval(() => {
        setUploadProgress((prev) => {
          if (prev >= 90) {
            clearInterval(progressInterval);
            return 90;
          }
          return prev + 10;
        });
      }, 200);

      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/products/import`, {
        method: 'POST',
        body: formData,
      });

      clearInterval(progressInterval);
      setUploadProgress(100);

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        throw new Error(errorData.message || `Error del servidor: ${response.status}`);
      }

      const result: ImportResult = await response.json();

      setImportResult(result);

      if (result.success) {
        addLog(`✅ Importación completada exitosamente`);
        addLog(`📦 Productos importados: ${result.totalImported}`);
        if (result.totalErrors > 0) {
          addLog(`⚠️ Errores encontrados: ${result.totalErrors}`);
        }
        toast.success(`¡${result.totalImported} productos importados exitosamente!`);
      } else {
        addLog(`❌ Error en la importación: ${result.message || 'Error desconocido'}`);
        toast.error(result.message || 'Error al importar productos');
      }

      // Mostrar errores específicos por fila
      if (result.errors && result.errors.length > 0) {
        result.errors.forEach((error) => {
          addLog(`❌ Fila ${error.row}: ${error.message}`);
        });
      }
    } catch (error) {
      console.error('Error importing products:', error);
      const errorMessage = error instanceof Error ? error.message : 'Error al importar productos';
      addLog(`❌ ${errorMessage}`);
      toast.error(errorMessage);
      setImportResult({
        success: false,
        totalImported: 0,
        totalErrors: 1,
        message: errorMessage,
      });
    } finally {
      setIsUploading(false);
    }
  };

  // Limpiar y resetear
  const handleReset = () => {
    setSelectedFile(null);
    setImportResult(null);
    setLogs([]);
    setCsvPreview(null);
    setShowPreview(false);
    setUploadProgress(0);
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
    addLog('🔄 Formulario reiniciado');
  };

  // Formatear tamaño de archivo
  const formatFileSize = (bytes: number): string => {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(2)} KB`;
    return `${(bytes / (1024 * 1024)).toFixed(2)} MB`;
  };

  return (
    <div className="min-h-screen bg-gray-900 p-4 md:p-8">
      <div className="max-w-6xl mx-auto">
        {/* Header */}
        <div className="mb-8">
          <button
            onClick={() => router.push('/dashboard/products')}
            className="flex items-center text-gray-400 hover:text-white mb-4 transition-colors"
          >
            <ArrowLeft className="w-4 h-4 mr-2" />
            Volver a productos
          </button>
          <h1 className="text-3xl font-bold text-white mb-2">Importar Productos desde CSV</h1>
          <p className="text-gray-400">
            Importa productos en masa desde un archivo CSV exportado de Tienda Nube
          </p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Panel principal - Uploader */}
          <div className="lg:col-span-2 space-y-6">
            {/* Zona de carga de archivo */}
            <div className="bg-gray-800 border border-gray-700 rounded-xl p-6">
              <h2 className="text-xl font-semibold text-white mb-4 flex items-center">
                <Upload className="w-5 h-5 mr-2" />
                Seleccionar archivo CSV
              </h2>

              <div
                className={`border-2 border-dashed rounded-xl p-8 text-center transition-all ${
                  selectedFile
                    ? 'border-green-500 bg-green-900/20'
                    : 'border-gray-600 bg-gray-900/50 hover:border-blue-500 hover:bg-gray-900'
                }`}
              >
                <input
                  ref={fileInputRef}
                  type="file"
                  accept=".csv"
                  onChange={handleFileSelect}
                  className="hidden"
                  id="csv-upload"
                  disabled={isUploading}
                />

                {!selectedFile ? (
                  <label htmlFor="csv-upload" className="cursor-pointer block">
                    <Upload className="w-16 h-16 text-gray-500 mx-auto mb-4" />
                    <p className="text-white font-medium mb-2">
                      Haz clic o arrastra un archivo CSV aquí
                    </p>
                    <p className="text-sm text-gray-400 mb-4">Tamaño máximo: 20MB</p>
                    <div className="inline-block px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors">
                      Seleccionar archivo
                    </div>
                  </label>
                ) : (
                  <div className="space-y-4">
                    <FileText className="w-16 h-16 text-green-500 mx-auto" />
                    <div>
                      <p className="text-white font-medium mb-1">{selectedFile.name}</p>
                      <p className="text-sm text-gray-400">{formatFileSize(selectedFile.size)}</p>
                    </div>

                    <div className="flex items-center justify-center gap-3 pt-4">
                      <label
                        htmlFor="csv-upload"
                        className="px-4 py-2 bg-gray-700 text-white rounded-lg hover:bg-gray-600 transition-colors cursor-pointer"
                      >
                        Cambiar archivo
                      </label>

                      <button
                        onClick={handleReset}
                        className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors flex items-center"
                        disabled={isUploading}
                      >
                        <X className="w-4 h-4 mr-2" />
                        Limpiar
                      </button>
                    </div>
                  </div>
                )}
              </div>
            </div>

            {/* Botón de importación */}
            {selectedFile && !isUploading && (
              <div className="bg-gradient-to-r from-blue-900/50 to-purple-900/50 border border-blue-700 rounded-xl p-6">
                <div className="flex items-center justify-between">
                  <div>
                    <h3 className="text-lg font-semibold text-white mb-1">¿Listo para importar?</h3>
                    <p className="text-sm text-gray-300">
                      Se procesará el archivo y se crearán los productos en tu tienda
                    </p>
                  </div>
                  <button
                    onClick={() => setShowConfirmDialog(true)}
                    className="px-6 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-all hover:shadow-lg flex items-center font-medium"
                  >
                    <Upload className="w-5 h-5 mr-2" />
                    Importar Productos
                  </button>
                </div>
              </div>
            )}

            {/* Barra de progreso */}
            {isUploading && (
              <div className="bg-gray-800 border border-gray-700 rounded-xl p-6">
                <h3 className="text-lg font-semibold text-white mb-4">Importando productos...</h3>
                <div className="space-y-3">
                  <div className="w-full bg-gray-700 rounded-full h-4 overflow-hidden">
                    <div
                      className="h-full bg-gradient-to-r from-blue-500 to-purple-500 transition-all duration-300 flex items-center justify-center text-xs font-medium text-white"
                      style={{ width: `${uploadProgress}%` }}
                    >
                      {uploadProgress}%
                    </div>
                  </div>
                  <p className="text-sm text-gray-400 text-center">
                    Por favor espera mientras procesamos tu archivo...
                  </p>
                </div>
              </div>
            )}

            {/* Resultado de la importación */}
            {importResult && !isUploading && (
              <div
                className={`border rounded-xl p-6 ${
                  importResult.success
                    ? 'bg-green-900/20 border-green-700'
                    : 'bg-red-900/20 border-red-700'
                }`}
              >
                <div className="flex items-start">
                  {importResult.success ? (
                    <CheckCircle className="w-6 h-6 text-green-500 mr-3 flex-shrink-0 mt-1" />
                  ) : (
                    <AlertCircle className="w-6 h-6 text-red-500 mr-3 flex-shrink-0 mt-1" />
                  )}
                  <div className="flex-1">
                    <h3
                      className={`text-lg font-semibold mb-2 ${
                        importResult.success ? 'text-green-400' : 'text-red-400'
                      }`}
                    >
                      {importResult.success ? '¡Importación Exitosa!' : 'Error en la Importación'}
                    </h3>
                    <div className="space-y-2 text-sm">
                      <p className="text-gray-300">
                        <strong>Productos importados:</strong> {importResult.totalImported}
                      </p>
                      {importResult.totalErrors > 0 && (
                        <p className="text-yellow-400">
                          <strong>Errores encontrados:</strong> {importResult.totalErrors}
                        </p>
                      )}
                      {importResult.message && (
                        <p className="text-gray-300 mt-2">{importResult.message}</p>
                      )}
                    </div>

                    {/* Errores por fila */}
                    {importResult.errors && importResult.errors.length > 0 && (
                      <div className="mt-4 p-3 bg-gray-800/50 rounded-lg max-h-48 overflow-y-auto">
                        <p className="text-sm font-medium text-gray-300 mb-2">
                          Detalles de errores:
                        </p>
                        <ul className="space-y-1 text-xs text-gray-400">
                          {importResult.errors.map((error, idx) => (
                            <li key={idx}>
                              <strong className="text-red-400">Fila {error.row}:</strong>{' '}
                              {error.message}
                            </li>
                          ))}
                        </ul>
                      </div>
                    )}

                    <div className="mt-4 flex gap-3">
                      <button
                        onClick={() => router.push('/dashboard/products')}
                        className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
                      >
                        Ver Productos
                      </button>
                      <button
                        onClick={handleReset}
                        className="px-4 py-2 bg-gray-700 text-white rounded-lg hover:bg-gray-600 transition-colors"
                      >
                        Nueva Importación
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>

          {/* Panel lateral - Instrucciones y Logs */}
          <div className="space-y-6">
            {/* Logs */}
            <div className="bg-gray-800 border border-gray-700 rounded-xl p-6">
              <h3 className="text-lg font-semibold text-white mb-4 flex items-center">
                <FileText className="w-5 h-5 mr-2 text-purple-400" />
                Registro de Actividad
              </h3>
              <div className="bg-gray-900 rounded-lg p-4 max-h-96 overflow-y-auto font-mono text-xs">
                {logs.length === 0 ? (
                  <p className="text-gray-500 italic">No hay actividad aún...</p>
                ) : (
                  <div className="space-y-1">
                    {logs.map((log, idx) => (
                      <p key={idx} className="text-gray-300">
                        {log}
                      </p>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Modal de confirmación */}
      {showConfirmDialog && (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 p-4">
          <div className="bg-gray-800 border border-gray-700 rounded-xl p-6 max-w-md w-full">
            <h3 className="text-xl font-semibold text-white mb-4 flex items-center">
              <AlertCircle className="w-6 h-6 mr-2 text-yellow-500" />
              Confirmar Importación
            </h3>
            <p className="text-gray-300 mb-6">
              ¿Estás seguro de que deseas importar los productos desde el archivo{' '}
              <strong className="text-white">{selectedFile?.name}</strong>?
            </p>
            <div className="flex gap-3">
              <button
                onClick={handleImport}
                className="flex-1 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors font-medium"
              >
                Sí, Importar
              </button>
              <button
                onClick={() => setShowConfirmDialog(false)}
                className="flex-1 px-4 py-2 bg-gray-700 text-white rounded-lg hover:bg-gray-600 transition-colors"
              >
                Cancelar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

