export default function ProductsPage() {
  const apolloClient = useApolloClient();
  const [searchTerm, setSearchTerm] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [selectedProducts, setSelectedProducts] = useState<string[]>([]);
  const [openDropdown, setOpenDropdown] = useState<string | null>(null);
  const [generatingLanding, setGeneratingLanding] = useState<Set<string>>(new Set());
  const userData = JSON.parse(localStorage.getItem('user') || '{}');
  // Pagination state
  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 15; // Fixed page size

  const isAdmin =
    userData?.role === 'ADMIN' ||
    (Array.isArray(userData?.roles) && userData.roles.includes('ADMIN'));

  // Fetch store data for domain information
  const { data: storeInfo } = useQuery(GET_STORE, {
    variables: { storeId: userData?.storeId || '' },
    skip: !userData?.storeId,
  });

  const {
    data: storeData,
    loading: storeLoading,
    refetch: refetchStoreProducts,
  } = useQuery(GET_PRODUCTS_BY_STORE, {
    variables: {
      storeId: userData?.storeId || '',
      page: currentPage,
      pageSize,
      internal: 'true',
      available: 'true',
    },
    skip: isAdmin || !userData?.storeId,
    fetchPolicy: 'network-only',
  });

  const {
    data: adminData,
    loading: adminLoading,
    refetch: refetchAdminProducts,
  } = useQuery(PAGINATED_PRODUCTS_QUERY, {
    variables: { page: currentPage, pageSize },
    skip: !isAdmin,
    fetchPolicy: 'network-only',
  });

  const productsData = isAdmin ? adminData : storeData;
  const loadingProducts = storeLoading || adminLoading;

  const refetchProducts = async (vars?: any) => {
    if (isAdmin) {
      return (
        refetchAdminProducts &&
        refetchAdminProducts({
          page: vars?.page || currentPage,
          pageSize: vars?.pageSize || pageSize,
        })
      );
    }
    return (
      refetchStoreProducts &&
      refetchStoreProducts({
        storeId: userData?.storeId || '',
        page: vars?.page || currentPage,
        pageSize: vars?.pageSize || pageSize,
      })
    );
  };
  const [createProduct, { loading: creating }] = useMutation(CREATE_PRODUCT);
  const [updateProduct, { loading: updating }] = useMutation(UPDATE_PRODUCT);
  const [deleteProduct, { loading: deleting }] = useMutation(DELETE_PRODUCT);
  const [deleteProducts, { loading: deletingMultiple }] = useMutation(DELETE_PRODUCTS);
  const [duplicateProduct, { loading: duplicating }] = useMutation(DUPLICATE_PRODUCT);

  // Use server-side search hook when the search term has 2+ characters
  const {
    products: searchedProducts,
    page: searchPage,
    pageSize: searchPageSize,
    total: searchTotal,
    totalPages: searchTotalPages,
    loading: searchLoading,
  } = useSearchProducts(searchTerm, currentPage, pageSize);

  if (!productsData) {
    return null;
  }

  // Use data from GraphQL
  const products: Product[] = isAdmin
    ? productsData?.paginatedProducts?.items || []
    : productsData?.productsByStore?.items || [];
  const totalProducts = isAdmin
    ? productsData?.paginatedProducts?.total || 0
    : productsData?.productsByStore?.total || 0;
  const totalPages = Math.ceil(totalProducts / pageSize) || 1;

  const searchActive = (searchTerm || '').trim().length >= 2;

  const displayedProducts = searchActive ? searchedProducts : products;
  const displayedTotal = searchActive ? searchTotal : totalProducts;
  const displayedTotalPages = searchActive ? searchTotalPages : totalPages;
  const displayedLoading = searchActive ? searchLoading : loadingProducts;

  const filteredProducts = displayedProducts.filter(
    (product) =>
      product.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      product.title?.toLowerCase().includes(searchTerm.toLowerCase())
  );
  console.log('Filtered products:', filteredProducts);

  // Colors from store - usando slate-900 como color principal
  const primaryColor = '#0F172A'; // slate-900

  // Pagination handlers
  const handlePageChange = (page: number) => {
    setCurrentPage(page);
    setSelectedProducts([]);
  };

  const handleCreateProduct = () => {
    setEditingProduct(null);
    setShowForm(true);
  };

  const handleEditProduct = (product: Product) => {
    setEditingProduct(product);
    setShowForm(true);
    setOpenDropdown(null);
  };

  const handleSaveProduct = async (productData: CreateProductInput) => {
    try {
      if (editingProduct) {
        const storeId = userData?.storeId || 'default-store';
        const { data } = await updateProduct({
          variables: {
            id: editingProduct.id,
            input: {
              name: productData.name,
              title: productData.title,
              description: productData.description,
              price: productData.price,
              currency: productData.currency,
              available: productData.available,
              inStock: productData.inStock,
              stock: productData.stock,
              categories: productData.categoryIds || [],
              images: productData.images.map((img: any) => ({
                url: img.url,
                order: img.order,
              })),
              variants: [
                // Convert colors to variants
                ...productData.colors.map((color: any) => ({
                  typeVariant: 'COLOR',
                  nameVariant: color.name,
                  jsonData: {
                    hex: color.hex,
                    name: color.name,
                  },
                })),
                // Add size variants if available
                ...(productData.sizes || []).map((size: any) => ({
                  typeVariant: 'SIZE',
                  nameVariant: size.name || size,
                  jsonData: {
                    name: size.name || size,
                    value: size.name || size,
                  },
                })),
              ],
              stocks: [
                {
                  price: productData.price,
                  stock: productData.stock,
                },
              ],
            },
          },
        });

        if (data?.updateProduct) {
          await refetchProducts({
            storeId,
            page: currentPage,
            pageSize,
          });
          toast.success('Producto actualizado exitosamente');
        }
      } else {
        const { data } = await createProduct({
          variables: {
            input: {
              name: productData.name,
              title: productData.title,
              description: productData.description,
              price: productData.price,
              currency: productData.currency,
              available: productData.available,
              inStock: productData.inStock,
              stock: productData.stock,
              storeId: userData.storeId || 'default-store',
              categories: productData.categoryIds || [],
              images: productData.images.map((img: any) => ({
                url: img.url,
                order: img.order,
              })),
              variants: [
                // Convert colors to variants
                ...productData.colors.map((color: any) => ({
                  typeVariant: 'COLOR',
                  nameVariant: color.name,
                  jsonData: {
                    hex: color.hex,
                    name: color.name,
                  },
                })),
                // Add size variants if available
                ...(productData.sizes || []).map((size: any) => ({
                  typeVariant: 'SIZE',
                  nameVariant: size.name || size,
                  jsonData: {
                    name: size.name || size,
                    value: size.name || size,
                  },
                })),
              ],
              stocks: [
                {
                  price: productData.price,
                  stock: productData.stock,
                },
              ],
            },
          },
        });
        const storeId = userData?.storeId || 'default-store';
        if (data?.createProduct) {
          await refetchProducts({
            storeId,
            page: currentPage,
            pageSize,
          });
          toast.success('Producto creado exitosamente');
        }
      }
      setShowForm(false);
      setEditingProduct(null);
    } catch (error: any) {
      console.error('Error saving product:', error);
      const errorMessage = error.message || 'Error al guardar el producto';
      toast.error(errorMessage);
      throw error;
    }
  };

  const handleDeleteProduct = async (productId: string) => {
    if (
      !confirm(
        '¿Estás seguro de que deseas eliminar este producto? Esta acción no se puede deshacer.'
      )
    ) {
      return;
    }

    try {
      const { data } = await deleteProduct({
        variables: { id: productId },
      });
      const storeId = userData?.storeId || 'default-store';
      if (data?.deleteProduct) {
        setSelectedProducts((prev) => prev.filter((id) => id !== productId));
        await refetchProducts({
          storeId,
          page: currentPage,
          pageSize,
        });
        toast.success('Producto eliminado exitosamente');
      }
    } catch (error: any) {
      console.error('Error deleting product:', error);
      const errorMessage = error.message || 'Error al eliminar el producto';
      toast.error(errorMessage);
    }
    setOpenDropdown(null);
  };

  const handleDeleteSelected = async () => {
    if (selectedProducts.length === 0) {
      toast.error('No hay productos seleccionados para eliminar');
      return;
    }

    if (
      !confirm(
        `¿Estás seguro de que deseas eliminar ${selectedProducts.length} producto(s)? Esta acción no se puede deshacer.`
      )
    ) {
      return;
    }

    try {
      const { data } = await deleteProducts({
        variables: { ids: selectedProducts },
      });
      const storeId = userData?.storeId || 'default-store';
      if (data?.deleteProducts) {
        setSelectedProducts([]);
        await refetchProducts({
          storeId,
          page: currentPage,
          pageSize,
        });
        toast.success(`${data.deleteProducts.count} producto(s) eliminado(s) exitosamente`);
      }
    } catch (error: any) {
      console.error('Error deleting products:', error);
      const errorMessage = error.message || 'Error al eliminar los productos';
      toast.error(errorMessage);
    }
  };

  const handleDuplicateProduct = async (productId: string) => {
    try {
      const { data } = await duplicateProduct({ variables: { id: productId } });
      // Debug log to inspect server response when errors occur
      // eslint-disable-next-line no-console
      console.log('duplicateProduct response:', data);

      if (data?.duplicateProduct) {
        // Refetch list to show duplicated product
        await refetchProducts({ page: currentPage, pageSize });
        toast.success('Producto duplicado exitosamente');
      } else {
        console.warn('duplicateProduct returned no product', data);
      }
    } catch (error: any) {
      console.error('Error duplicando producto:', error);
      toast.error(error.message || 'Error al duplicar el producto');
    }
    setOpenDropdown(null);
  };

  const handleViewLanding = (product: Product) => {
    // Construct the landing page URL using store domain
    const store = storeInfo?.store;
    if (store) {
      const domain = store.customDomain || `${store.storeId}.emprendyup.com`;
      const url = `https://${domain}/products/landing/${product.externalSKU}`;
      window.open(url, '_blank');
    } else {
      // Fallback to relative URL if store data is not available
      window.open(`/products/landing/${product.externalSKU}`, '_blank');
    }
  };

  const handleGenerateLanding = async (product: Product) => {
    setGeneratingLanding((prev) => new Set(prev).add(product.id));
    try {
      // Extract features from description or other fields
      const features: string[] = [];

      // Prepare the payload for the landing page configuration
      const payload = {
        brand: '',
        features,
        specifications: {},
      };

      // Make the API call to generate the landing page
      const response = await fetch(
        `${process.env.NEXT_PUBLIC_API_URL}/product/${product.id}/generate-landing`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${localStorage.getItem('token')}`,
          },
          body: JSON.stringify(payload),
        }
      );

      if (!response.ok) {
        const errorData = await response.json();
        console.error('Error response:', errorData);
        throw new Error(errorData.message || 'Error al generar la landing page');
      }

      const data = await response.json();

      // Update the Apollo cache to reflect the change
      apolloClient.cache.modify({
        id: apolloClient.cache.identify({ __typename: 'Product', id: product.id }),
        fields: {
          landing() {
            return true;
          },
        },
      });

      toast.success('Landing page generada exitosamente');

      // Optionally redirect to the landing page or show a preview
      // window.open(`/landing/${product.id}`, '_blank');
    } catch (error: any) {
      console.error('Error generando landing page:', error);
      toast.error(error.message || 'Error al generar la landing page');
    } finally {
      setGeneratingLanding((prev) => {
        const newSet = new Set(prev);
        newSet.delete(product.id);
        return newSet;
      });
      setOpenDropdown(null);
    }
  };

  const toggleProductSelection = (productId: string) => {
    setSelectedProducts((prev) =>
      prev.includes(productId) ? prev.filter((id) => id !== productId) : [...prev, productId]
    );
  };

  const toggleSelectAll = () => {
    setSelectedProducts((prev) =>
      prev.length === filteredProducts.length
        ? []
        : (filteredProducts as Product[]).map((p) => p.id)
    );
  };

  if (showForm) {
    return (
      <ProductFormWizard
        product={editingProduct || undefined}
        onSave={handleSaveProduct}
        onCancel={() => {
          setShowForm(false);
          setEditingProduct(null);
        }}
        onSaved={async () => {
          const storeId = userData?.storeId || '';
          await refetchProducts({ storeId, page: currentPage, pageSize });
        }}
        loading={creating || updating}
      />
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h3 className="text-lg font-semibold text-white">Gestión de Productos</h3>
          <p className="text-sm text-gray-400">Administra el catálogo de productos de tu tienda</p>
        </div>
        <div className="flex gap-3">
          <button
            onClick={() => (window.location.href = '/dashboard/products/import')}
            className="text-white px-4 py-2 rounded-lg flex items-center justify-center font-medium shadow-sm hover:shadow-md transition-all duration-200 bg-purple-700 hover:bg-purple-600"
          >
            <Upload className="w-4 h-4 mr-2" />
            Importar CSV
          </button>
          <button
            onClick={handleCreateProduct}
            className="text-white px-4 py-2 rounded-lg flex items-center justify-center font-medium shadow-sm hover:shadow-md transition-all duration-200 bg-slate-700 hover:bg-slate-600"
          >
            <Plus className="w-4 h-4 mr-2" />
            Nuevo Producto
          </button>
        </div>
      </div>

      {/* Search and Actions */}
      <div className="flex flex-col sm:flex-row items-stretch sm:items-center justify-between gap-4">
        <div className="flex-1 relative">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-500" />
          <input
            type="text"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            placeholder="Buscar productos..."
            className="w-full pl-10 pr-3 py-2 border border-gray-600 bg-gray-800 text-white rounded-lg focus:ring-2 focus:ring-slate-500 focus:border-slate-500 transition-all placeholder-gray-400"
          />
        </div>

        {selectedProducts.length > 0 && (
          <button
            onClick={handleDeleteSelected}
            disabled={deletingMultiple}
            className="bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700 flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed font-medium shadow-sm hover:shadow-md transition-all duration-200"
          >
            <Trash2 className="w-4 h-4 mr-2" />
            {deletingMultiple ? 'Eliminando...' : `Eliminar (${selectedProducts.length})`}
          </button>
        )}
      </div>

      {/* Mobile Select All */}
      {filteredProducts.length > 0 && (
        <div className="md:hidden bg-gray-800 border border-gray-700 rounded-lg p-3">
          <label className="flex items-center space-x-3">
            <input
              type="checkbox"
              checked={
                selectedProducts.length === filteredProducts.length && filteredProducts.length > 0
              }
              onChange={toggleSelectAll}
              className="w-4 h-4 rounded border-gray-600 bg-gray-700"
              style={
                {
                  accentColor: primaryColor,
                  '--tw-ring-color': primaryColor,
                } as React.CSSProperties
              }
            />
            <span className="text-sm text-white font-medium">
              {selectedProducts.length === filteredProducts.length && filteredProducts.length > 0
                ? 'Deseleccionar todos'
                : 'Seleccionar todos'}
            </span>
            {selectedProducts.length > 0 && (
              <span className="text-xs text-gray-400">
                ({selectedProducts.length} seleccionados)
              </span>
            )}
          </label>
        </div>
      )}

      {/* Products Table/Cards */}
      {displayedLoading ? (
        <div className="text-center py-12">
          <div className="w-8 h-8 border-2 border-gray-600 border-t-slate-400 rounded-full animate-spin mx-auto mb-4" />
          <p className="text-gray-400">Cargando productos...</p>
        </div>
      ) : filteredProducts.length > 0 ? (
        <>
          {/* Desktop Table */}
          <div className="hidden md:block bg-gray-800 border border-gray-700 rounded-xl overflow-hidden shadow-sm">
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-700">
                <thead className="bg-gray-900">
                  <tr>
                    <th className="px-6 py-4 text-left">
                      <input
                        type="checkbox"
                        checked={
                          selectedProducts.length === filteredProducts.length &&
                          filteredProducts.length > 0
                        }
                        onChange={toggleSelectAll}
                        className="w-4 h-4 rounded border-gray-600 text-slate-500 focus:ring-slate-500 bg-gray-700"
                      />
                    </th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-gray-300 uppercase tracking-wider">
                      Producto
                    </th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-gray-300 uppercase tracking-wider">
                      Precio
                    </th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-gray-300 uppercase tracking-wider">
                      Stock
                    </th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-gray-300 uppercase tracking-wider">
                      Estado
                    </th>
                    <th className="px-6 py-4 text-right text-xs font-semibold text-gray-300 uppercase tracking-wider">
                      Acciones
                    </th>
                  </tr>
                </thead>
                <tbody className="bg-gray-800 divide-y divide-gray-700">
                  {filteredProducts.map((product: Product) => (
                    <tr key={product.id} className="hover:bg-gray-700 transition-colors">
                      <td className="px-6 py-4">
                        <input
                          type="checkbox"
                          checked={selectedProducts.includes(product.id)}
                          onChange={() => toggleProductSelection(product.id)}
                          className="w-4 h-4 rounded border-gray-600 text-slate-500 focus:ring-slate-500 bg-gray-700"
                        />
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center">
                          <div className="flex-shrink-0 w-12 h-12">
                            {product.images && product.images.length > 0 ? (
                              <Image
                                src={`https://emprendyup-images.s3.us-east-1.amazonaws.com/${product?.images[0].url}`}
                                alt={product.name}
                                width={32}
                                height={32}
                                className="w-12 h-12 rounded-xl object-cover shadow-sm"
                                style={{
                                  border: `2px solid ${primaryColor}40`,
                                }}
                              />
                            ) : (
                              <div className="w-12 h-12 rounded-xl bg-gray-700 border-2 border-gray-600 flex items-center justify-center">
                                <Package className="w-6 h-6 text-slate-400" />
                              </div>
                            )}
                          </div>
                          <div className="ml-4">
                            <div className="text-sm font-semibold text-white">{product.name}</div>
                            <div className="text-sm text-gray-400 truncate max-w-xs">
                              {product.title}
                            </div>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="text-sm font-medium text-white">
                          ${product.price.toLocaleString()} {product.currency}
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="text-sm font-medium text-white">{product.stock}</div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex flex-col space-y-1">
                          <span
                            className={`inline-flex px-2 py-1 text-xs font-semibold rounded-full w-fit ${
                              product.available
                                ? 'bg-green-900 text-green-300'
                                : 'bg-red-900 text-red-300'
                            }`}
                          >
                            {product.available ? 'Disponible' : 'No disponible'}
                          </span>
                          <span
                            className={`inline-flex px-2 py-1 text-xs font-semibold bg-fourth-base text-white rounded-full w-fit`}
                          >
                            {product.inStock ? 'En stock' : 'Sin stock'}
                          </span>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex items-center justify-end space-x-2">
                          <button
                            onClick={() => handleEditProduct(product)}
                            className="p-2 text-slate-400 hover:bg-gray-700 hover:text-white rounded-lg transition-colors"
                          >
                            <Edit className="w-4 h-4" />
                          </button>
                          <button
                            onClick={
                              product.landing
                                ? () => handleViewLanding(product)
                                : () => handleGenerateLanding(product)
                            }
                            disabled={generatingLanding.has(product.id)}
                            className="p-2 text-slate-400 hover:bg-gray-700 hover:text-white rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                            title={product.landing ? 'Ver landing' : 'Generar landing'}
                          >
                            {product.landing ? (
                              <Eye className="w-4 h-4" />
                            ) : generatingLanding.has(product.id) ? (
                              <div className="w-4 h-4 border-2 border-slate-400 border-t-transparent rounded-full animate-spin" />
                            ) : (
                              <Layout className="w-4 h-4" />
                            )}
                          </button>
                          <button
                            onClick={() => handleDuplicateProduct(product.id)}
                            disabled={duplicating}
                            className="p-2 text-slate-400 hover:bg-gray-700 hover:text-white rounded-lg transition-colors"
                            title="Duplicar producto"
                          >
                            <Copy className="w-4 h-4" />
                          </button>
                          <button
                            onClick={() => handleDeleteProduct(product.id)}
                            disabled={deleting}
                            className="p-2 text-red-400 hover:bg-red-900 hover:text-red-300 rounded-lg disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                            title="Eliminar producto"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* Mobile Cards */}
          <div className="md:hidden space-y-3">
            {filteredProducts.map((product) => (
              <div
                key={product.id}
                className="bg-gray-800 border border-gray-700 rounded-xl p-4 shadow-sm"
                style={{
                  borderColor: selectedProducts.includes(product.id) ? primaryColor : '#374151',
                }}
              >
                <div className="flex items-center justify-between">
                  <div className="flex items-center space-x-3 flex-1 min-w-0">
                    {/* Checkbox */}
                    <input
                      type="checkbox"
                      checked={selectedProducts.includes(product.id)}
                      onChange={() => toggleProductSelection(product.id)}
                      className="w-4 h-4 rounded border-gray-600 bg-gray-700 flex-shrink-0"
                      style={
                        {
                          accentColor: primaryColor,
                          '--tw-ring-color': primaryColor,
                        } as React.CSSProperties
                      }
                    />

                    {/* Image */}
                    <div className="flex-shrink-0">
                      {product.images && product.images.length > 0 ? (
                        <Image
                          src={`https://emprendyup-images.s3.us-east-1.amazonaws.com/${product.images[0].url}`}
                          alt={product.name}
                          width={64}
                          height={64}
                          className="w-16 h-16 rounded-lg object-cover shadow-sm"
                          style={{ border: `2px solid ${primaryColor}40` }}
                        />
                      ) : (
                        <div
                          className="w-16 h-16 rounded-lg flex items-center justify-center"
                          style={{
                            backgroundColor: `${primaryColor}20`,
                            border: `2px solid ${primaryColor}40`,
                          }}
                        >
                          <Package className="w-8 h-8" style={{ color: primaryColor }} />
                        </div>
                      )}
                    </div>

                    {/* Product Info */}
                    <div className="flex-1 min-w-0">
                      <h4 className="text-sm font-semibold text-white truncate">{product.name}</h4>
                      <p className="text-xs text-gray-400 truncate">{product.title}</p>
                      <div className="flex items-center space-x-2 mt-1">
                        <span className="text-sm font-medium text-white">
                          ${product.price.toLocaleString()} {product.currency}
                        </span>
                        <span className="text-xs text-gray-400">• Stock: {product.stock}</span>
                      </div>
                      <div className="flex space-x-1 mt-2">
                        <span
                          className={`inline-flex px-2 py-0.5 text-xs font-medium rounded-full ${
                            product.available
                              ? 'bg-green-900 text-green-300'
                              : 'bg-red-900 text-red-300'
                          }`}
                        >
                          {product.available ? 'Disponible' : 'No disponible'}
                        </span>
                        <span className="inline-flex px-2 py-0.5 text-xs font-medium bg-fourth-base text-white rounded-full">
                          {product.inStock ? 'En stock' : 'Sin stock'}
                        </span>
                      </div>
                    </div>
                  </div>

                  {/* Actions */}
                  <div className="relative flex-shrink-0">
                    <button
                      onClick={() =>
                        setOpenDropdown(openDropdown === product.id ? null : product.id)
                      }
                      className="p-2 rounded-lg hover:bg-gray-700 transition-colors"
                    >
                      <MoreVertical className="w-4 h-4 text-gray-400" />
                    </button>

                    {openDropdown === product.id && (
                      <div className="absolute right-0 mt-1 w-48 bg-gray-800 rounded-lg shadow-lg border border-gray-700 z-10">
                        <div className="py-1">
                          <button
                            onClick={() => handleEditProduct(product)}
                            className="flex items-center w-full px-4 py-2 text-sm text-gray-300 hover:bg-gray-700"
                          >
                            <Edit className="w-4 h-4 mr-2" style={{ color: primaryColor }} />
                            Editar
                          </button>
                          <button
                            onClick={() => handleGenerateLanding(product)}
                            disabled={generatingLanding.has(product.id)}
                            className="flex items-center w-full px-4 py-2 text-sm text-gray-300 hover:bg-gray-700 disabled:opacity-50 disabled:cursor-not-allowed"
                          >
                            {generatingLanding.has(product.id) ? (
                              <div className="w-4 h-4 mr-2 border-2 border-gray-300 border-t-transparent rounded-full animate-spin" />
                            ) : (
                              <Layout className="w-4 h-4 mr-2" />
                            )}
                            {generatingLanding.has(product.id) ? <Loader /> : 'Generar Landing'}
                          </button>
                          <button
                            onClick={() => handleDuplicateProduct(product.id)}
                            disabled={duplicating}
                            className="flex items-center w-full px-4 py-2 text-sm text-gray-300 hover:bg-gray-700"
                          >
                            <Copy className="w-4 h-4 mr-2" />
                            Duplicar
                          </button>
                          <button
                            onClick={() => handleDeleteProduct(product.id)}
                            disabled={deleting}
                            className="flex items-center w-full px-4 py-2 text-sm text-red-400 hover:bg-red-900 hover:text-red-300 disabled:opacity-50 disabled:cursor-not-allowed"
                          >
                            <Trash2 className="w-4 h-4 mr-2" />
                            Eliminar
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </>
      ) : (
        <div className="text-center py-16">
          <div
            className="w-16 h-16 rounded-full mx-auto mb-4 flex items-center justify-center"
            style={{ backgroundColor: `${primaryColor}20` }}
          >
            <Package className="w-8 h-8" style={{ color: primaryColor }} />
          </div>
          <p className="text-white text-lg font-medium mb-2">
            {searchTerm ? 'No se encontraron productos' : 'No tienes productos todavía'}
          </p>
          <p className="text-gray-400 text-sm mb-6 max-w-md mx-auto">
            {searchTerm
              ? 'Intenta con otros términos de búsqueda'
              : 'Crea tu primer producto para empezar a vender'}
          </p>
          {!searchTerm && (
            <button
              onClick={handleCreateProduct}
              className="text-white px-6 py-3 rounded-lg hover:shadow-md flex items-center mx-auto font-medium transition-all duration-200"
              style={{ backgroundColor: primaryColor }}
            >
              <Plus className="w-4 h-4 mr-2" />
              Crear Primer Producto
            </button>
          )}
        </div>
      )}

      {/* Pagination */}
      {!displayedLoading && displayedTotal > 0 && (
        <div className="bg-gray-800 border border-gray-700 rounded-xl px-4 py-3 sm:px-6 shadow-sm">
          <div className="flex flex-1 justify-between sm:hidden">
            <button
              onClick={() => handlePageChange(currentPage - 1)}
              disabled={currentPage === 1}
              className="relative inline-flex items-center rounded-lg border border-gray-600 bg-gray-800 px-4 py-2 text-sm font-medium text-gray-300 hover:bg-gray-700 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Anterior
            </button>
            <span className="text-sm text-gray-300 flex items-center">
              Página {currentPage} de {displayedTotalPages}
            </span>
            <button
              onClick={() => handlePageChange(currentPage + 1)}
              disabled={currentPage === displayedTotalPages}
              className="relative inline-flex items-center rounded-lg border border-gray-600 bg-gray-800 px-4 py-2 text-sm font-medium text-gray-300 hover:bg-gray-700 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Siguiente
            </button>
          </div>

          <div className="hidden sm:flex sm:flex-1 sm:items-center sm:justify-between">
            <div>
              <p className="text-sm text-gray-300">
                Mostrando{' '}
                <span className="font-medium">
                  {Math.min(currentPage * pageSize, displayedTotal)}
                </span>{' '}
                de <span className="font-medium">{displayedTotal}</span> productos
              </p>
            </div>

            <div>
              <nav
                className="isolate inline-flex -space-x-px rounded-lg shadow-sm"
                aria-label="Pagination"
              >
                <button
                  onClick={() => handlePageChange(currentPage - 1)}
                  disabled={currentPage === 1}
                  className="relative inline-flex items-center rounded-l-lg px-2 py-2 text-gray-500 ring-1 ring-inset ring-gray-600 hover:bg-gray-700 focus:z-20 focus:outline-offset-0 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  <ChevronLeft className="h-5 w-5" />
                </button>

                {(() => {
                  const maxVisiblePages = 3;
                  let startPage = 1;
                  let endPage = displayedTotalPages;

                  if (displayedTotalPages > maxVisiblePages) {
                    // Calcular el rango de páginas a mostrar
                    if (currentPage <= 2) {
                      // Si estamos en las primeras páginas, mostrar 1, 2, 3
                      startPage = 1;
                      endPage = maxVisiblePages;
                    } else if (currentPage >= displayedTotalPages - 1) {
                      // Si estamos en las últimas páginas, mostrar las últimas 3
                      startPage = displayedTotalPages - maxVisiblePages + 1;
                      endPage = displayedTotalPages;
                    } else {
                      // Si estamos en el medio, mostrar página actual y vecinas
                      startPage = currentPage - 1;
                      endPage = currentPage + 1;
                    }
                  }

                  const pages = [];
                  for (let i = startPage; i <= endPage; i++) {
                    pages.push(
                      <button
                        key={i}
                        onClick={() => handlePageChange(i)}
                        className={`relative inline-flex items-center px-4 py-2 text-sm font-semibold transition-colors ${
                          currentPage === i
                            ? 'z-10 text-white focus:z-20'
                            : 'text-gray-300 ring-1 ring-inset ring-gray-600 hover:bg-gray-700 focus:z-20 focus:outline-offset-0'
                        }`}
                        style={currentPage === i ? { backgroundColor: primaryColor } : {}}
                      >
                        {i}
                      </button>
                    );
                  }

                  return pages;
                })()}

                <button
                  onClick={() => handlePageChange(currentPage + 1)}
                  disabled={currentPage === displayedTotalPages}
                  className="relative inline-flex items-center rounded-r-lg px-2 py-2 text-gray-500 ring-1 ring-inset ring-gray-600 hover:bg-gray-700 focus:z-20 focus:outline-offset-0 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  <ChevronRight className="h-5 w-5" />
                </button>
              </nav>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import React, { useState, useMemo } from 'react';
import { gql, useQuery, useMutation } from '@apollo/client';
import { useSessionStore } from '@/lib/store/dashboard';
import {
  FileText,
  Search,
  ChevronDown,
  ChevronUp,
  ChevronLeft,
  ChevronRight,
  Eye,
  X,
  Package,
  Clock,
  User,
  Mail,
  Building2,
  MapPin,
  Phone,
  AlertCircle,
  Loader2,
  RefreshCw,
  CheckCircle,
} from 'lucide-react';

// ─── GraphQL ────────────────────────────────────────────────────────────────

const QUOTES_BY_STORE = gql`
  query QuotesByStore($storeId: ID!) {
    quotesByStore(storeId: $storeId) {
      id
      referencia
      nombreEmpresa
      nombreContacto
      correoElectronico
      estado
      origen
      fechaSolicitud
      createdAt
      items {
        id
        productName
        quantity
        unit
      }
      history {
        estadoNuevo
        accion
        fechaCambio
      }
    }
  }
`;

const GET_QUOTE = gql`
  query Quote($id: ID!) {
    quote(id: $id) {
      id
      referencia
      nombreEmpresa
      industria
      ciudad
      volumenEstimado
      nombreContacto
      correoElectronico
      telefono
      requerimientosAdicionales
      estado
      notas
      origen
      fechaSolicitud
      storeId
      createdAt
      updatedAt
      items {
        id
        productName
        productCategory
        quantity
        unit
        productSku
        posicion
      }
      history {
        id
        estadoAnterior
        estadoNuevo
        accion
        descripcion
        fechaCambio
      }
    }
  }
`;

const UPDATE_QUOTE = gql`
  mutation UpdateQuote($id: ID!, $input: UpdateQuoteInput!) {
    updateQuote(id: $id, input: $input) {
      id
      referencia
      estado
      notas
      updatedAt
      history {
        id
        estadoAnterior
        estadoNuevo
        accion
        descripcion
        fechaCambio
      }
    }
  }
`;

// ─── Types ───────────────────────────────────────────────────────────────────

interface QuoteItem {
  id: string;
  productName: string;
  productCategory?: string;
  quantity: number;
  unit: string;
  productSku?: string;
  posicion?: number;
}

interface QuoteHistory {
  id?: string;
  estadoAnterior?: string;
  estadoNuevo: string;
  accion: string;
  descripcion?: string;
  fechaCambio: string;
}

interface Quote {
  id: string;
  referencia: string;
  nombreEmpresa: string;
  industria?: string;
  ciudad?: string;
  volumenEstimado?: string;
  nombreContacto: string;
  correoElectronico: string;
  telefono?: string;
  requerimientosAdicionales?: string;
  estado: string;
  notas?: string;
  origen: string;
  fechaSolicitud: string;
  storeId?: string;
  createdAt: string;
  updatedAt?: string;
  items: QuoteItem[];
  history: QuoteHistory[];
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

const STATUS_COLORS: Record<string, string> = {
  PENDIENTE: 'bg-yellow-100 text-yellow-800',
  CONTACTADO: 'bg-blue-100 text-blue-800',
  GANADO: 'bg-green-100 text-green-800',
  PERDIDO: 'bg-red-100 text-red-800',
  EN_PROCESO: 'bg-indigo-100 text-indigo-800',
  COMPLETADO: 'bg-green-200 text-green-900',
  RECHAZADO: 'bg-red-200 text-red-900',
  CANCELADO: 'bg-gray-100 text-gray-700',
  APROVADO_POR_CLIENTE: 'bg-teal-100 text-teal-800',
  PENDIENTE_DE_ENVIO_COTIZACION: 'bg-orange-100 text-orange-800',
  COTIZACION_ENVIADA: 'bg-cyan-100 text-cyan-800',
  PENDIENTE_DE_CONFIRMACION: 'bg-purple-100 text-purple-800',
  CONFIRMADO: 'bg-emerald-100 text-emerald-800',
};

function StatusBadge({ estado }: { estado: string }) {
  const cls = STATUS_COLORS[estado] ?? 'bg-gray-100 text-gray-700';
  return (
    <span
      className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${cls}`}
    >
      {estado}
    </span>
  );
}

function formatDate(dateStr: string) {
  if (!dateStr) return '—';
  try {
    return new Date(dateStr).toLocaleDateString('es-CO', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });
  } catch {
    return dateStr;
  }
}

// ─── Detail Modal ─────────────────────────────────────────────────────────────

function QuoteDetailModal({ quoteId, onClose }: { quoteId: string; onClose: () => void }) {
  const { data, loading, error, refetch } = useQuery(GET_QUOTE, {
    variables: { id: quoteId },
    fetchPolicy: 'network-only',
  });

  const [updateQuote, { loading: updating }] = useMutation(UPDATE_QUOTE);

  const [updateForm, setUpdateForm] = useState({
    estado: '',
    accion: '',
    descripcion: '',
    notas: '',
  });
  const [updateSuccess, setUpdateSuccess] = useState(false);
  const [updateError, setUpdateError] = useState('');

  const QUOTE_STATES: { value: string; label: string }[] = [
    { value: 'PENDIENTE', label: 'Pendiente' },
    { value: 'CONTACTADO', label: 'Contactado' },
    { value: 'PENDIENTE_DE_ENVIO_COTIZACION', label: 'Pendiente de envío de cotización' },
    { value: 'COTIZACION_ENVIADA', label: 'Cotización enviada' },
    { value: 'PENDIENTE_DE_CONFIRMACION', label: 'Pendiente de confirmación' },
    { value: 'APROVADO_POR_CLIENTE', label: 'Aprobado por cliente' },
    { value: 'CONFIRMADO', label: 'Confirmado' },
    { value: 'EN_PROCESO', label: 'En proceso' },
    { value: 'GANADO', label: 'Ganado' },
    { value: 'COMPLETADO', label: 'Completado' },
    { value: 'PERDIDO', label: 'Perdido' },
    { value: 'RECHAZADO', label: 'Rechazado' },
    { value: 'CANCELADO', label: 'Cancelado' },
  ];

  async function handleUpdate(e: React.FormEvent) {
    e.preventDefault();
    setUpdateError('');
    setUpdateSuccess(false);
    const input: Record<string, string> = { accion: updateForm.accion };
    if (updateForm.estado) input.estado = updateForm.estado;
    if (updateForm.descripcion) input.descripcion = updateForm.descripcion;
    if (updateForm.notas) input.notas = updateForm.notas;
    try {
      await updateQuote({ variables: { id: quoteId, input } });
      setUpdateSuccess(true);
      setUpdateForm({ estado: '', accion: '', descripcion: '', notas: '' });
      refetch();
    } catch (err: unknown) {
      setUpdateError(err instanceof Error ? err.message : 'Error al actualizar');
    }
  }

  const quote: Quote | undefined = data?.quote;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
      <div className="bg-gray-900 border border-gray-700 rounded-xl shadow-2xl w-full max-w-3xl max-h-[90vh] overflow-y-auto">
        {/* Header */}
        <div className="flex items-center justify-between p-6 bg-fourth-base text-black">
          <div className="flex items-center gap-3">
            <FileText className="w-6 h-6" />
            <div>
              <h2 className="text-lg font-bold">
                {quote ? `Cotización ${quote.referencia}` : 'Detalle de cotización'}
              </h2>
              {quote && <p className="text-sm text-gray-800">{quote.nombreEmpresa}</p>}
            </div>
          </div>
          <button
            onClick={onClose}
            className="p-2 rounded-full hover:bg-black/10 transition-colors"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Body */}
        <div className="p-6">
          {loading && (
            <div className="flex items-center justify-center py-16">
              <Loader2 className="w-8 h-8 animate-spin text-indigo-400" />
            </div>
          )}

          {error && (
            <div className="flex items-center gap-2 text-red-400 bg-red-900/30 border border-red-700 rounded-lg p-4">
              <AlertCircle className="w-5 h-5 flex-shrink-0" />
              <p className="text-sm">Error al cargar la cotización: {error.message}</p>
            </div>
          )}

          {quote && (
            <div className="space-y-6">
              {/* Status + meta */}
              <div className="flex flex-wrap items-center gap-3">
                <StatusBadge estado={quote.estado} />
                <span className="text-sm text-gray-400">Origen: {quote.origen}</span>
                <span className="text-sm text-gray-400">
                  Solicitada: {formatDate(quote.fechaSolicitud)}
                </span>
              </div>

              {/* Contact info */}
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <InfoRow
                  icon={<User className="w-4 h-4" />}
                  label="Contacto"
                  value={quote.nombreContacto}
                />
                <InfoRow
                  icon={<Mail className="w-4 h-4" />}
                  label="Correo"
                  value={quote.correoElectronico}
                />
                {quote.telefono && (
                  <InfoRow
                    icon={<Phone className="w-4 h-4" />}
                    label="Teléfono"
                    value={quote.telefono}
                  />
                )}
                {quote.industria && (
                  <InfoRow
                    icon={<Building2 className="w-4 h-4" />}
                    label="Industria"
                    value={quote.industria}
                  />
                )}
                {quote.ciudad && (
                  <InfoRow
                    icon={<MapPin className="w-4 h-4" />}
                    label="Ciudad"
                    value={quote.ciudad}
                  />
                )}
                {quote.volumenEstimado && (
                  <InfoRow
                    icon={<Package className="w-4 h-4" />}
                    label="Volumen estimado"
                    value={quote.volumenEstimado}
                  />
                )}
              </div>

              {/* Additional requirements */}
              {quote.requerimientosAdicionales && (
                <div>
                  <h3 className="text-sm font-medium text-gray-300 mb-1">
                    Requerimientos adicionales
                  </h3>
                  <p className="text-sm text-gray-400 bg-gray-800 border border-gray-700 rounded-lg p-3">
                    {quote.requerimientosAdicionales}
                  </p>
                </div>
              )}

              {/* Notes */}
              {quote.notas && (
                <div>
                  <h3 className="text-sm font-medium text-gray-300 mb-1">Notas</h3>
                  <p className="text-sm text-gray-400 bg-gray-800 border border-gray-700 rounded-lg p-3">
                    {quote.notas}
                  </p>
                </div>
              )}

              {/* Items */}
              {quote.items?.length > 0 && (
                <div>
                  <h3 className="text-sm font-semibold text-gray-200 mb-2 flex items-center gap-2">
                    <Package className="w-4 h-4 text-indigo-400" />
                    Productos solicitados ({quote.items.length})
                  </h3>
                  <div className="overflow-x-auto rounded-lg">
                    <table className="min-w-full text-sm">
                      <thead className="bg-gray-800">
                        <tr>
                          <th className="px-4 py-2 text-left text-xs font-semibold text-gray-300 uppercase">
                            #
                          </th>
                          <th className="px-4 py-2 text-left text-xs font-semibold text-gray-300 uppercase">
                            Producto
                          </th>
                          <th className="px-4 py-2 text-left text-xs font-semibold text-gray-300 uppercase">
                            Categoría
                          </th>
                          <th className="px-4 py-2 text-left text-xs font-semibold text-gray-300 uppercase">
                            Cant.
                          </th>
                          <th className="px-4 py-2 text-left text-xs font-semibold text-gray-300 uppercase">
                            Unidad
                          </th>
                          <th className="px-4 py-2 text-left text-xs font-semibold text-gray-300 uppercase">
                            SKU
                          </th>
                        </tr>
                      </thead>
                      <tbody className="bg-gray-900 divide-y divide-gray-800">
                        {quote.items.map((item, idx) => (
                          <tr key={item.id} className="hover:bg-gray-800">
                            <td className="px-4 py-2 text-gray-400">{item.posicion ?? idx + 1}</td>
                            <td className="px-4 py-2 font-semibold text-white">
                              {item.productName}
                            </td>
                            <td className="px-4 py-2 text-gray-400">
                              {item.productCategory ?? '—'}
                            </td>
                            <td className="px-4 py-2 text-gray-400">{item.quantity}</td>
                            <td className="px-4 py-2 text-gray-400">{item.unit}</td>
                            <td className="px-4 py-2 text-gray-500 font-mono text-xs">
                              {item.productSku ?? '—'}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}

              {/* Update state form */}
              <div className="border border-gray-700 rounded-lg overflow-hidden">
                <div className="bg-gray-800 px-4 py-3 flex items-center gap-2">
                  <RefreshCw className="w-4 h-4 text-indigo-400" />
                  <h3 className="text-sm font-semibold text-gray-200">Actualizar cotización</h3>
                </div>
                <form onSubmit={handleUpdate} className="p-4 space-y-3">
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    <div>
                      <label className="block text-xs font-medium text-gray-400 mb-1">
                        Nuevo estado <span className="text-gray-500">(opcional)</span>
                      </label>
                      <select
                        value={updateForm.estado}
                        onChange={(e) => setUpdateForm((f) => ({ ...f, estado: e.target.value }))}
                        className="w-full px-3 py-2 bg-gray-800 border border-gray-600 rounded-lg text-sm text-white focus:outline-none focus:ring-2 focus:ring-indigo-500"
                      >
                        <option value="">— Sin cambio —</option>
                        {QUOTE_STATES.map(({ value, label }) => (
                          <option key={value} value={value}>
                            {label}
                          </option>
                        ))}
                      </select>
                    </div>
                    <div>
                      <label className="block text-xs font-medium text-gray-400 mb-1">
                        Acción <span className="text-red-400">*</span>
                      </label>
                      <input
                        type="text"
                        required
                        placeholder="Ej: Primer contacto realizado"
                        value={updateForm.accion}
                        onChange={(e) => setUpdateForm((f) => ({ ...f, accion: e.target.value }))}
                        className="w-full px-3 py-2 bg-gray-800 border border-gray-600 rounded-lg text-sm text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                      />
                    </div>
                  </div>
                  <div>
                    <label className="block text-xs font-medium text-gray-400 mb-1">
                      Descripción
                    </label>
                    <input
                      type="text"
                      placeholder="Detalles del cambio…"
                      value={updateForm.descripcion}
                      onChange={(e) =>
                        setUpdateForm((f) => ({ ...f, descripcion: e.target.value }))
                      }
                      className="w-full px-3 py-2 bg-gray-800 border border-gray-600 rounded-lg text-sm text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-medium text-gray-400 mb-1">
                      Notas internas
                    </label>
                    <textarea
                      rows={2}
                      placeholder="Notas visibles sólo para el equipo…"
                      value={updateForm.notas}
                      onChange={(e) => setUpdateForm((f) => ({ ...f, notas: e.target.value }))}
                      className="w-full px-3 py-2 bg-gray-800 border border-gray-600 rounded-lg text-sm text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-indigo-500 resize-none"
                    />
                  </div>

                  {updateError && (
                    <div className="flex items-center gap-2 text-red-400 bg-red-900/30 border border-red-700 rounded-lg px-3 py-2 text-xs">
                      <AlertCircle className="w-4 h-4 flex-shrink-0" />
                      {updateError}
                    </div>
                  )}
                  {updateSuccess && (
                    <div className="flex items-center gap-2 text-green-400 bg-green-900/30 border border-green-700 rounded-lg px-3 py-2 text-xs">
                      <CheckCircle className="w-4 h-4 flex-shrink-0" />
                      Cotización actualizada correctamente.
                    </div>
                  )}

                  <div className="flex justify-end">
                    <button
                      type="submit"
                      disabled={updating}
                      className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 text-white text-sm font-medium rounded-lg transition-colors"
                    >
                      {updating ? (
                        <Loader2 className="w-4 h-4 animate-spin" />
                      ) : (
                        <RefreshCw className="w-4 h-4" />
                      )}
                      Guardar cambios
                    </button>
                  </div>
                </form>
              </div>

              {/* History */}
              {quote.history?.length > 0 && (
                <div>
                  <h3 className="text-sm font-semibold text-gray-200 mb-2 flex items-center gap-2">
                    <Clock className="w-4 h-4 text-indigo-400" />
                    Historial de cambios
                  </h3>
                  <ol className="relative border-l border-gray-700 space-y-4 ml-3">
                    {quote.history.map((h, idx) => (
                      <li key={h.id ?? idx} className="ml-4">
                        <div className="absolute w-2.5 h-2.5 bg-indigo-500 rounded-full -left-1.5 mt-1" />
                        <div className="bg-gray-800 border border-gray-700 rounded-lg p-3">
                          <p className="text-xs font-semibold text-indigo-400">{h.accion}</p>
                          {h.estadoAnterior && (
                            <p className="text-xs text-gray-400 mt-0.5">
                              {h.estadoAnterior} → {h.estadoNuevo}
                            </p>
                          )}
                          {h.descripcion && (
                            <p className="text-xs text-gray-400 mt-1">{h.descripcion}</p>
                          )}
                          <p className="text-xs text-gray-500 mt-1">{formatDate(h.fechaCambio)}</p>
                        </div>
                      </li>
                    ))}
                  </ol>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

function InfoRow({ icon, label, value }: { icon: React.ReactNode; label: string; value: string }) {
  return (
    <div className="flex items-start gap-2">
      <span className="mt-0.5 text-gray-500">{icon}</span>
      <div>
        <p className="text-xs text-gray-500">{label}</p>
        <p className="text-sm font-medium text-gray-200">{value}</p>
      </div>
    </div>
  );
}

