const GET_RESTAURANT = gql`
  query GetRestaurant($id: ID!) {
    restaurant(id: $id) {
      id
      name
      description
      cuisineType
      city
      address
      phone
      coverImage
      customDomain
      googleLocation
      lat
      lng
      address
      menu {
        id
        name
      }
      brandingId
      businessConfigId
      createdAt
      updatedAt
      menuImages {
        id
        imageUrl
        title
        description
      }
    }
  }
