const GET_MENU_ITEMS = gql`
  query GetMenuItems($restaurantId: ID, $category: String, $isAvailable: Boolean) {
    menuItems(restaurantId: $restaurantId, category: $category, isAvailable: $isAvailable) {
      id
      name
      description
      category
      price
      currency
      imageUrl
      isAvailable
      order
      menuId
      createdAt
      updatedAt
    }
  }
`;

