const FREQUENT_CLIENTS = gql`
  query FrequentClients(
    $serviceProviderId: String!
    $startDate: DateTime
    $endDate: DateTime
    $limit: Float
  ) {
    frequentClients(
      serviceProviderId: $serviceProviderId
      startDate: $startDate
      endDate: $endDate
      limit: $limit
    ) {
      customerId
      customerName
      customerEmail
      customerPhone
      totalAppointments
      totalRevenue
      lastAppointmentDate
      firstAppointmentDate
      isRecurrent
      isVIP
      appointmentHistory {
        id
        date
        serviceName
        status
        paymentStatus
        amount
      }
    }
  }
`;

const NEW_VS_RECURRENT = gql`
  query NewVsRecurrent($serviceProviderId: String!, $startDate: DateTime!, $endDate: DateTime!) {
    newVsRecurrentClients(
      serviceProviderId: $serviceProviderId
