const formatCOP = (n: number) =>
  new Intl.NumberFormat('es-CO', {
    style: 'currency',
    currency: 'COP',
    maximumFractionDigits: 0,
  }).format(n);

const STATUS_LABELS: Record<string, string> = {
  PENDING: 'Pendiente',
  CONFIRMED: 'Confirmada',
  CANCELLED: 'Cancelada',
  CANCELLED_BY_CLIENT: 'Cancelada (cliente)',
  CANCELLED_BY_PROVIDER: 'Cancelada (proveedor)',
  COMPLETED: 'Completada',
};
const PAYMENT_LABELS: Record<string, string> = {
  PENDING: 'Pendiente',
  PAID: 'Pagado',
  PARTIAL: 'Parcial',
  CANCELLED: 'Cancelado',
  REFUNDED: 'Reembolsado',
};

type SortKey = 'totalAppointments' | 'totalRevenue' | 'lastAppointmentDate';

export default function ServiceCRM() {
  const { user } = useSessionStore();
  const serviceProviderId = user?.serviceProviderId;

  const [sortKey, setSortKey] = useState<SortKey>('totalAppointments');
  const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');
  const [expandedEmail, setExpandedEmail] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<'clients' | 'appointments'>('clients');
  const [dateRange, setDateRange] = useState<'week' | 'month' | 'all'>('month');
  const [filterType, setFilterType] = useState<'all' | 'recurring' | 'vip'>('all');

  // Calculate date range based on selection
  const { dateFrom, dateTo } = useMemo(() => {
    const now = new Date();
    let from = new Date();
    let to = new Date();

    switch (dateRange) {
      case 'week':
        // Esta semana completa (lunes a domingo)
        const day = now.getDay();
        const diff = now.getDate() - day + (day === 0 ? -6 : 1);
        from = new Date(now.getFullYear(), now.getMonth(), diff);
        from.setHours(0, 0, 0, 0);
        to = new Date(from);
        to.setDate(from.getDate() + 6); // Hasta el domingo
        to.setHours(23, 59, 59, 999);
        break;

      case 'month':
        // Todo el mes actual (del 1 al último día)
        from = new Date(now.getFullYear(), now.getMonth(), 1);
        from.setHours(0, 0, 0, 0);
        to = new Date(now.getFullYear(), now.getMonth() + 1, 0); // Último día del mes
        to.setHours(23, 59, 59, 999);
        break;

      case 'all':
        // Todas las citas (sin restricción de fecha)
        from = new Date('2000-01-01');
        from.setHours(0, 0, 0, 0);
        to = new Date('2099-12-31');
        to.setHours(23, 59, 59, 999);
        break;
    }

    return {
      dateFrom: from.toISOString().split('T')[0],
      dateTo: to.toISOString().split('T')[0],
    };
  }, [dateRange]);

  // Convert dates to DateTime format for GraphQL
  const startDateTime = useMemo(() => {
    const d = new Date(dateFrom);
    d.setHours(0, 0, 0, 0);
    return d.toISOString();
  }, [dateFrom]);

  const endDateTime = useMemo(() => {
    const d = new Date(dateTo);
    d.setHours(23, 59, 59, 999);
    return d.toISOString();
  }, [dateTo]);

  const { data: clientsData, loading: loadingClients } = useQuery(FREQUENT_CLIENTS, {
    variables: {
      serviceProviderId: serviceProviderId || '',
      startDate: startDateTime,
      endDate: endDateTime,
      limit: null,
    },
    skip: !serviceProviderId,
  });

  const { data: statsData } = useQuery(NEW_VS_RECURRENT, {
    variables: {
      serviceProviderId: serviceProviderId || '',
      startDate: startDateTime,
      endDate: endDateTime,
    },
    skip: !serviceProviderId,
  });

  const { data: appointmentsData } = useQuery(GET_ALL_APPOINTMENTS, {
    variables: { serviceProviderId: serviceProviderId || '' },
    skip: !serviceProviderId,
  });

  const { data: servicesData } = useQuery(GET_SERVICES, {
    variables: { serviceProviderId: serviceProviderId || '' },
    skip: !serviceProviderId,
  });

  const clients: FrequentClient[] = useMemo(
    () => clientsData?.frequentClients || [],
    [clientsData]
  );

  const newVsRecurrentStats = useMemo(() => statsData?.newVsRecurrentClients, [statsData]);

  const appointments: Appointment[] = useMemo(
    () => appointmentsData?.appointmentsByProvider || [],
    [appointmentsData]
  );

  const services: Service[] = useMemo(() => servicesData?.servicesByProvider || [], [servicesData]);

  // Filter appointments by date range
  const filteredAppointments = useMemo(() => {
    const from = new Date(dateFrom);
    from.setHours(0, 0, 0, 0);
    const to = new Date(dateTo);
    to.setHours(23, 59, 59, 999);

    return appointments
      .filter((apt) => {
        const aptDate = new Date(parseInt(apt.startDatetime));
        return aptDate >= from && aptDate <= to;
      })
      .sort((a, b) => {
        return parseInt(b.startDatetime) - parseInt(a.startDatetime);
      });
  }, [appointments, dateFrom, dateTo]);

  const filtered = useMemo(() => {
    let list = clients;
    if (filterType === 'recurring') list = list.filter((c) => c.isRecurrent);
    if (filterType === 'vip') list = list.filter((c) => c.isVIP);
    return list.sort((a, b) => {
      let diff = 0;
      if (sortKey === 'totalAppointments') diff = a.totalAppointments - b.totalAppointments;
      if (sortKey === 'totalRevenue') diff = a.totalRevenue - b.totalRevenue;
      if (sortKey === 'lastAppointmentDate') {
        diff =
          new Date(a.lastAppointmentDate).getTime() - new Date(b.lastAppointmentDate).getTime();
      }
      return sortDir === 'desc' ? -diff : diff;
    });
  }, [clients, filterType, sortKey, sortDir]);

  const toggleSort = (key: SortKey) => {
    if (sortKey === key) {
      setSortDir((d) => (d === 'asc' ? 'desc' : 'asc'));
    } else {
      setSortKey(key);
      setSortDir('desc');
    }
  };

  const handleExportCSV = () => {
    if (viewMode === 'clients') {
      const headers = [
        'Nombre',
        'Correo',
        'Teléfono',
        'Total Citas',
        'Ingresos Totales',
        'Primera Visita',
        'Última Visita',
        'Tipo',
      ];
      const rows = filtered.map((c) => [
        c.customerName,
        c.customerEmail,
        c.customerPhone,
        c.totalAppointments,
        c.totalRevenue,
        new Date(c.firstAppointmentDate).toLocaleDateString('es-CO'),
        new Date(c.lastAppointmentDate).toLocaleDateString('es-CO'),
        c.isVIP ? 'VIP' : c.isRecurrent ? 'Recurrente' : 'Nuevo',
      ]);
      const csv = [headers, ...rows].map((r) => r.map(String).join(',')).join('\n');
      const blob = new Blob(['\uFEFF' + csv], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `clientes.csv`;
      link.click();
      URL.revokeObjectURL(url);
    } else {
      const headers = [
        'Fecha',
        'Hora',
        'Cliente',
        'Correo',
        'Teléfono',
        'Servicio',
        'Dirección',
        'Ciudad',
        'Referencia',
        'Estado',
        'Estado Pago',
        'Monto',
        'Notas',
      ];
      const rows = filteredAppointments.map((apt) => {
        const service = services.find((s) => s.id === apt.serviceId);
        const aptDate = new Date(parseInt(apt.startDatetime));
        return [
          aptDate.toLocaleDateString('es-CO'),
          aptDate.toLocaleTimeString('es-CO', { hour: '2-digit', minute: '2-digit' }),
          apt.customerName,
          apt.customerEmail,
          apt.customerPhone,
          service?.name || '',
          apt.serviceAddress || '',
          apt.serviceCity || '',
          apt.serviceReference || '',
          STATUS_LABELS[apt.status] || apt.status,
          PAYMENT_LABELS[apt.paymentStatus] || apt.paymentStatus,
          service?.priceAmount || 0,
          apt.notes || '',
        ];
      });
      const csv = [headers, ...rows].map((r) => r.map(String).join(',')).join('\n');
      const blob = new Blob(['\uFEFF' + csv], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `citas.csv`;
      link.click();
      URL.revokeObjectURL(url);
    }
  };

  if (!serviceProviderId) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <div className="text-center">
          <AlertCircle className="h-12 w-12 text-yellow-500 mx-auto mb-3" />
          <p className="text-gray-500">No se encontró el proveedor de servicios.</p>
        </div>
      </div>
    );
  }

  const SortIcon = ({ k }: { k: SortKey }) =>
    sortKey !== k ? null : sortDir === 'desc' ? (
      <ChevronDown className="h-3.5 w-3.5 inline ml-1" />
    ) : (
      <ChevronUp className="h-3.5 w-3.5 inline ml-1" />
    );

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">
            {viewMode === 'clients' ? 'Clientes Frecuentes' : 'Todas las Citas'}
          </h1>
          <p className="text-gray-600 dark:text-gray-400">
            {viewMode === 'clients'
              ? 'Historial, pagos y ranking de clientes'
              : 'Listado completo de citas programadas'}
          </p>
        </div>
        <div className="flex gap-2 flex-wrap">
          <div className="flex gap-1 bg-gray-100 dark:bg-gray-700 rounded-lg p-1">
            <button
              onClick={() => setViewMode('clients')}
              className={`px-3 py-1.5 rounded-md text-sm font-medium transition-colors ${
                viewMode === 'clients'
                  ? 'bg-fourth-base text-white'
                  : 'text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600'
              }`}
            >
              <Users className="h-4 w-4 inline mr-1" />
              Clientes
            </button>
            <button
              onClick={() => setViewMode('appointments')}
              className={`px-3 py-1.5 rounded-md text-sm font-medium transition-colors ${
                viewMode === 'appointments'
                  ? 'bg-fourth-base text-white'
                  : 'text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600'
              }`}
            >
              <Calendar className="h-4 w-4 inline mr-1" />
              Citas
            </button>
          </div>
          <button
            onClick={handleExportCSV}
            className="inline-flex items-center gap-2 px-4 py-2 bg-fourth-base text-white rounded-lg hover:opacity-90 text-sm font-medium"
          >
            <Download className="h-4 w-4" />
            Exportar CSV
          </button>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-4 flex flex-wrap gap-4 items-center">
        <Filter className="h-4 w-4 text-gray-400 flex-shrink-0" />

        {/* Date range selector */}
        <div className="flex items-center gap-2">
          <label className="text-sm text-gray-500 whitespace-nowrap">Período:</label>
          <div className="flex gap-1 bg-gray-100 dark:bg-gray-700 rounded-lg p-1">
            <button
              onClick={() => setDateRange('week')}
              className={`px-4 py-1.5 rounded-md text-sm font-medium transition-colors whitespace-nowrap ${
                dateRange === 'week'
                  ? 'bg-fourth-base text-white'
                  : 'text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600'
              }`}
            >
              Semanal
            </button>
            <button
              onClick={() => setDateRange('month')}
              className={`px-4 py-1.5 rounded-md text-sm font-medium transition-colors whitespace-nowrap ${
                dateRange === 'month'
                  ? 'bg-fourth-base text-white'
                  : 'text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600'
              }`}
            >
              Mensual
            </button>
            <button
              onClick={() => setDateRange('all')}
              className={`px-4 py-1.5 rounded-md text-sm font-medium transition-colors whitespace-nowrap ${
                dateRange === 'all'
                  ? 'bg-fourth-base text-white'
                  : 'text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600'
              }`}
            >
              Todas
            </button>
          </div>
        </div>

        {/* Type filter - only for clients view */}
        {viewMode === 'clients' && (
          <div className="flex gap-2 ml-auto">
            {(['all', 'recurring', 'vip'] as const).map((t) => (
              <button
                key={t}
                onClick={() => setFilterType(t)}
                className={`px-3 py-1.5 rounded-lg text-sm transition-colors ${
                  filterType === t
                    ? 'bg-fourth-base text-white'
                    : 'bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600'
                }`}
              >
                {t === 'all' ? 'Todos' : t === 'recurring' ? '⭐ Recurrentes' : '👑 VIP'}
              </button>
            ))}
          </div>
        )}
      </div>

      {/* Summary - only for clients view */}
      {viewMode === 'clients' && (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {[
            {
              label: 'Total Clientes',
              value: newVsRecurrentStats?.totalClients || clients.length,
              icon: Users,
              color: 'blue',
            },
            {
              label: 'Recurrentes',
              value: clients.filter((c) => c.isRecurrent).length,
              icon: Star,
              color: 'yellow',
            },
            {
              label: 'VIP (Top 10%)',
              value: clients.filter((c) => c.isVIP).length,
              icon: Crown,
              color: 'purple',
            },
            {
              label: 'Total Ingresos',
              value: formatCOP(clients.reduce((s, c) => s + c.totalRevenue, 0)),
              icon: DollarSign,
              color: 'green',
            },
          ].map(({ label, value, icon: Icon, color }) => (
            <div
              key={label}
              className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-4 flex items-center gap-3"
            >
              <div className={`p-2.5 rounded-full bg-${color}-100 dark:bg-${color}-900/30`}>
                <Icon className={`h-5 w-5 text-${color}-600 dark:text-${color}-400`} />
              </div>
              <div>
                <p className="text-xs text-gray-500 dark:text-gray-400">{label}</p>
                <p className="text-lg font-bold text-gray-900 dark:text-white">{value}</p>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Summary for appointments view */}
      {viewMode === 'appointments' && (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {[
            {
              label: 'Total Citas',
              value: filteredAppointments.length,
              icon: Calendar,
              color: 'blue',
            },
            {
              label: 'Confirmadas',
              value: filteredAppointments.filter((a) => a.status === 'CONFIRMED').length,
              icon: Star,
              color: 'blue',
            },
            {
              label: 'Completadas',
              value: filteredAppointments.filter((a) => a.status === 'COMPLETED').length,
              icon: Star,
              color: 'green',
            },
            {
              label: 'Total Ingresos',
              value: formatCOP(
                filteredAppointments.reduce((sum, apt) => {
                  const service = services.find((s) => s.id === apt.serviceId);
                  return sum + (service?.priceAmount || 0);
                }, 0)
              ),
              icon: DollarSign,
              color: 'green',
            },
          ].map(({ label, value, icon: Icon, color }) => (
            <div
              key={label}
              className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-4 flex items-center gap-3"
            >
              <div className={`p-2.5 rounded-full bg-${color}-100 dark:bg-${color}-900/30`}>
                <Icon className={`h-5 w-5 text-${color}-600 dark:text-${color}-400`} />
              </div>
              <div>
                <p className="text-xs text-gray-500 dark:text-gray-400">{label}</p>
                <p className="text-lg font-bold text-gray-900 dark:text-white">{value}</p>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Table */}
      {loadingClients ? (
        <div className="flex items-center justify-center py-16">
          <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-fourth-base" />
        </div>
      ) : viewMode === 'clients' ? (
        // Clients Table
        filtered.length === 0 ? (
          <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-12 text-center text-gray-500 dark:text-gray-400">
            No se encontraron clientes con los filtros aplicados.
          </div>
        ) : (
          <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
                <thead className="bg-gray-50 dark:bg-gray-900">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-300 uppercase tracking-wider">
                      Cliente
                    </th>
                    <th
                      className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-300 uppercase tracking-wider cursor-pointer hover:text-gray-900 dark:hover:text-white select-none"
                      onClick={() => toggleSort('totalAppointments')}
                    >
                      Citas <SortIcon k="totalAppointments" />
                    </th>
                    <th
                      className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-300 uppercase tracking-wider cursor-pointer hover:text-gray-900 dark:hover:text-white select-none"
                      onClick={() => toggleSort('totalRevenue')}
                    >
                      Ingresos <SortIcon k="totalRevenue" />
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-300 uppercase tracking-wider">
                      Estado de Pagos
                    </th>
                    <th
                      className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-300 uppercase tracking-wider cursor-pointer hover:text-gray-900 dark:hover:text-white select-none"
                      onClick={() => toggleSort('lastAppointmentDate')}
                    >
                      Última visita <SortIcon k="lastAppointmentDate" />
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-300 uppercase tracking-wider">
                      Tipo
                    </th>
                    <th className="px-6 py-3" />
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
                  {filtered.map((client, idx) => {
                    const paidAmount = client.appointmentHistory
                      .filter((apt) => apt.paymentStatus === 'PAID')
                      .reduce((sum, apt) => sum + apt.amount, 0);
                    const pendingAmount = client.totalRevenue - paidAmount;

                    return (
                      <>
                        <tr
                          key={client.customerEmail}
                          className="hover:bg-gray-50 dark:hover:bg-gray-700/50 transition cursor-pointer"
                          onClick={() =>
                            setExpandedEmail(
                              expandedEmail === client.customerEmail ? null : client.customerEmail
                            )
                          }
                        >
                          <td className="px-6 py-4">
                            <div className="font-medium text-gray-900 dark:text-white text-sm">
                              #{idx + 1} {client.customerName}
                            </div>
                            <div className="flex items-center gap-3 mt-1">
                              <span className="text-xs text-gray-500 dark:text-gray-400 flex items-center gap-1">
                                <Mail className="h-3 w-3" /> {client.customerEmail}
                              </span>
                              <span className="text-xs text-gray-500 dark:text-gray-400 flex items-center gap-1">
                                <Phone className="h-3 w-3" /> {client.customerPhone}
                              </span>
                            </div>
                          </td>
                          <td className="px-6 py-4 text-sm font-semibold text-gray-900 dark:text-white">
                            <span className="flex items-center gap-1">
                              <Calendar className="h-3.5 w-3.5 text-gray-400" />
                              {client.totalAppointments}
                            </span>
                          </td>
                          <td className="px-6 py-4 text-sm font-semibold text-fourth-base">
                            {formatCOP(client.totalRevenue)}
                          </td>
                          <td className="px-6 py-4">
                            <div className="text-xs font-medium text-green-600 dark:text-green-400">
                              ✓ {formatCOP(paidAmount)}
                            </div>
                            <div className="text-xs text-yellow-600 dark:text-yellow-400">
                              ⏳ {formatCOP(pendingAmount)}
                            </div>
                          </td>
                          <td className="px-6 py-4 text-sm text-gray-600 dark:text-gray-400">
                            {new Date(client.lastAppointmentDate).toLocaleDateString('es-CO', {
                              day: 'numeric',
                              month: 'short',
                              year: 'numeric',
                            })}
                          </td>
                          <td className="px-6 py-4">
                            {client.isVIP ? (
                              <span className="inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-medium bg-purple-100 text-purple-800 dark:bg-purple-900 dark:text-purple-300">
                                <Crown className="h-3 w-3" /> VIP
                              </span>
                            ) : client.isRecurrent ? (
                              <span className="inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-medium bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-300">
                                <Star className="h-3 w-3" /> Recurrente
                              </span>
                            ) : (
                              <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-gray-100 text-gray-700 dark:bg-gray-700 dark:text-gray-300">
                                Nuevo
                              </span>
                            )}
                          </td>
                          <td className="px-6 py-4 text-gray-400">
                            {expandedEmail === client.customerEmail ? (
                              <ChevronUp className="h-4 w-4" />
                            ) : (
                              <ChevronDown className="h-4 w-4" />
                            )}
                          </td>
                        </tr>

                        {/* Expanded appointment history */}
                        {expandedEmail === client.customerEmail && (
                          <tr key={client.customerEmail + '-detail'}>
                            <td colSpan={7} className="px-6 pb-4 bg-gray-50 dark:bg-gray-900/30">
                              <p className="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase mt-3 mb-2">
                                Historial de Citas
                              </p>
                              <div className="rounded-lg border border-gray-200 dark:border-gray-700 overflow-hidden">
                                <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700 text-sm">
                                  <thead className="bg-white dark:bg-gray-800">
                                    <tr>
                                      {['Fecha', 'Servicio', 'Estado', 'Pago', 'Monto'].map((h) => (
                                        <th
                                          key={h}
                                          className="px-4 py-2 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase"
                                        >
                                          {h}
                                        </th>
                                      ))}
                                    </tr>
                                  </thead>
                                  <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
                                    {client.appointmentHistory
                                      .slice()
                                      .sort(
                                        (a, b) =>
                                          new Date(b.date).getTime() - new Date(a.date).getTime()
                                      )
                                      .map((apt) => (
                                        <tr
                                          key={apt.id}
                                          className="hover:bg-gray-50 dark:hover:bg-gray-700/30"
                                        >
                                          <td className="px-4 py-2 text-gray-700 dark:text-gray-300">
                                            {new Date(apt.date).toLocaleDateString('es-CO', {
                                              day: 'numeric',
                                              month: 'short',
                                              year: 'numeric',
                                            })}
                                          </td>
                                          <td className="px-4 py-2 text-gray-700 dark:text-gray-300">
                                            {apt.serviceName || '—'}
                                          </td>
                                          <td className="px-4 py-2">
                                            <span className="text-xs px-2 py-0.5 rounded-full bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300">
                                              {STATUS_LABELS[apt.status] || apt.status}
                                            </span>
                                          </td>
                                          <td className="px-4 py-2">
                                            <span
                                              className={`text-xs px-2 py-0.5 rounded-full ${
                                                apt.paymentStatus === 'PAID'
                                                  ? 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-300'
                                                  : 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-300'
                                              }`}
                                            >
                                              {PAYMENT_LABELS[apt.paymentStatus] ||
                                                apt.paymentStatus}
                                            </span>
                                          </td>
                                          <td className="px-4 py-2 text-gray-700 dark:text-gray-300 font-medium">
                                            {formatCOP(apt.amount)}
                                          </td>
                                        </tr>
                                      ))}
                                  </tbody>
                                </table>
                              </div>
                            </td>
                          </tr>
                        )}
                      </>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        )
      ) : // Appointments Table
      filteredAppointments.length === 0 ? (
        <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-12 text-center text-gray-500 dark:text-gray-400">
          No se encontraron citas en el rango de fechas seleccionado.
        </div>
      ) : (
        <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
              <thead className="bg-gray-50 dark:bg-gray-900">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-300 uppercase tracking-wider">
                    Fecha y Hora
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-300 uppercase tracking-wider">
                    Cliente
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-300 uppercase tracking-wider">
                    Servicio
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-300 uppercase tracking-wider">
                    Ubicación
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-300 uppercase tracking-wider">
                    Estado
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-300 uppercase tracking-wider">
                    Pago
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-300 uppercase tracking-wider">
                    Monto
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
                {filteredAppointments.map((apt) => {
                  const service = services.find((s) => s.id === apt.serviceId);
                  const aptDate = new Date(parseInt(apt.startDatetime));
                  const location = [apt.serviceAddress, apt.serviceCity].filter(Boolean).join(', ');

                  return (
                    <tr
                      key={apt.id}
                      className="hover:bg-gray-50 dark:hover:bg-gray-700/50 transition"
                    >
                      <td className="px-6 py-4">
                        <div className="text-sm font-medium text-gray-900 dark:text-white">
                          {aptDate.toLocaleDateString('es-CO', {
                            day: 'numeric',
                            month: 'short',
                            year: 'numeric',
                          })}
                        </div>
                        <div className="text-xs text-gray-500 dark:text-gray-400">
                          {aptDate.toLocaleTimeString('es-CO', {
                            hour: '2-digit',
                            minute: '2-digit',
                          })}
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="text-sm font-medium text-gray-900 dark:text-white">
                          {apt.customerName}
                        </div>
                        <div className="flex items-center gap-2 mt-1">
                          <span className="text-xs text-gray-500 dark:text-gray-400 flex items-center gap-1">
                            <Mail className="h-3 w-3" /> {apt.customerEmail}
                          </span>
                        </div>
                        <div className="text-xs text-gray-500 dark:text-gray-400 flex items-center gap-1 mt-0.5">
                          <Phone className="h-3 w-3" /> {apt.customerPhone}
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="text-sm text-gray-900 dark:text-white font-medium">
                          {service?.name || 'Sin servicio'}
                        </div>
                        {apt.notes && (
                          <div className="text-xs text-gray-500 dark:text-gray-400 mt-1 max-w-xs truncate">
                            {apt.notes}
                          </div>
                        )}
                      </td>
                      <td className="px-6 py-4">
                        {location ? (
                          <div className="text-sm text-gray-700 dark:text-gray-300 max-w-xs">
                            {location}
                            {apt.serviceReference && (
                              <div className="text-xs text-gray-500 dark:text-gray-400 mt-1">
                                {apt.serviceReference}
                              </div>
                            )}
                          </div>
                        ) : (
                          <span className="text-xs text-gray-400">—</span>
                        )}
                      </td>
                      <td className="px-6 py-4">
                        <span className="inline-flex px-2.5 py-0.5 rounded-full text-xs font-medium bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300">
                          {STATUS_LABELS[apt.status] || apt.status}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <span
                          className={`inline-flex px-2.5 py-0.5 rounded-full text-xs font-medium ${
                            apt.paymentStatus === 'PAID'
                              ? 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-300'
                              : apt.paymentStatus === 'PENDING'
                                ? 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-300'
                                : 'bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-300'
                          }`}
                        >
                          {PAYMENT_LABELS[apt.paymentStatus] || apt.paymentStatus}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <div className="text-sm font-semibold text-fourth-base">
                          {service ? formatCOP(service.priceAmount) : '—'}
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';
import { useQuery, useMutation, gql } from '@apollo/client';
import { useRouter } from 'next/navigation';
import { useState, useEffect } from 'react';
import {
  Save,
  CheckCircle,
  AlertCircle,
  Info,
  MapPin,
  Phone,
  Mail,
  Globe,
  Image as ImageIcon,
} from 'lucide-react';
import { useSessionStore } from '@/lib/store/dashboard';
import FileUpload from '@/app/components/FileUpload';
import Image from 'next/image';

const GET_SERVICE_PROVIDER = gql`
  query GetServiceProvider($id: String!) {
    serviceProvider(id: $id) {
      id
      businessName
      type
      phone
      email
      description
      location
      customDomain
      address
      whatsappNumber
      coverImage
      slug
      brandingId
      businessConfigId
      isActive
      createdAt
      updatedAt
    }
  }
`;

const UPDATE_SERVICE_PROVIDER = gql`
  mutation UpdateServiceProvider($id: String!, $data: UpdateServiceProviderInput!) {
    updateServiceProvider(id: $id, data: $data) {
      id
      businessName
      type
      phone
      coverImage
      email
      description
      location
      address
      whatsappNumber
      isActive
    }
  }
`;

export default function ServiceDetailPage() {
  const router = useRouter();
  const { user } = useSessionStore();
  const serviceId = user?.serviceProviderId;

  const { data, loading, error } = useQuery(GET_SERVICE_PROVIDER, {
    variables: { id: serviceId },
    skip: !serviceId,
  });

  const [updateService] = useMutation(UPDATE_SERVICE_PROVIDER);
  const [formData, setFormData] = useState<any>({});
  const [activeTab, setActiveTab] = useState('details');
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'success' | 'error'>('idle');

  useEffect(() => {
    if (data?.serviceProvider) {
      setFormData(data.serviceProvider);
    }
  }, [data]);

  const handleInputChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>
  ) => {
    const { name, value } = e.target;
    setFormData((prev: any) => ({ ...prev, [name]: value }));
  };

  const handleSave = async () => {
    setSaveStatus('saving');
    try {
      const {
        id,
        brandingId,
        businessConfigId,
        createdAt,
        updatedAt,
        slug,
        customDomain: _customDomain,
        __typename,
        ...inputData
      } = formData;

      await updateService({
        variables: {
          id: serviceId,
          data: inputData,
        },
      });

      setSaveStatus('success');
      setTimeout(() => setSaveStatus('idle'), 3000);
    } catch (err: any) {
      setSaveStatus('error');
      setTimeout(() => setSaveStatus('idle'), 3000);
    }
  };

  const tabs = [
    { id: 'details', label: 'Detalles', icon: Info },
    { id: 'location', label: 'Ubicación', icon: MapPin },
    { id: 'contact', label: 'Contacto', icon: Phone },
    { id: 'images', label: 'Imágenes', icon: ImageIcon },
  ];

  if (!serviceId) {
    return (
      <div className="min-h-screen bg-gray-50 dark:bg-gray-900 flex items-center justify-center">
        <div className="text-center">
          <AlertCircle className="h-12 w-12 text-red-500 mx-auto mb-4" />
          <p className="text-gray-600 dark:text-gray-400">No se encontró el ID del servicio</p>
        </div>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 dark:bg-gray-900 flex items-center justify-center">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-fourth-base"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gray-50 dark:bg-gray-900 flex items-center justify-center">
        <div className="text-center">
          <AlertCircle className="h-12 w-12 text-red-500 mx-auto mb-4" />
          <p className="text-red-600 dark:text-red-400">Error: {error.message}</p>
        </div>
      </div>
    );
  }

  const inputClassName =
    'w-full px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-fourth-base focus:border-transparent';
  const resolveImageUrl = (value?: string) => {
    if (!value) return '';
    if (
      value.startsWith('http') ||
      value.startsWith('https') ||
      value.startsWith('blob:') ||
      value.startsWith('data:')
    ) {
      return value;
    }
    return `https://emprendyup-images.s3.us-east-1.amazonaws.com/${value}`;
  };
  const resolveDomainUrl = (value?: string) => {
    if (!value) return '';
    if (value.startsWith('http') || value.startsWith('https')) return value;
    return `https://${value}`;
  };
  const handleRemoveImage = (field: string) => {
    setFormData((prev: any) => ({ ...prev, [field]: '' }));
  };
  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900">
      {/* Header */}
      <div className="bg-white dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700">
        <div className="px-6 py-6">
          <div className="flex justify-between items-start">
            <div>
              <button
                onClick={() => router.back()}
                className="text-sm text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white mb-2"
              >
                ← Volver
              </button>
              <h1 className="text-2xl font-bold text-gray-900 dark:text-white">
                Configuración de Servicio
              </h1>
              <p className="text-gray-600 dark:text-gray-400 mt-1">{formData.businessName}</p>
              {(formData.customDomain || formData.slug) && (
                <a
                  href={`https://${formData.customDomain || `${formData.slug}.emprendyup.com`}`}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-sm text-fourth-base hover:underline mt-1 flex items-center gap-1"
                >
                  <Globe className="h-4 w-4" />
                  {formData.customDomain || `${formData.slug}.emprendyup.com`}
                </a>
              )}
            </div>
            <button
              onClick={handleSave}
              disabled={saveStatus === 'saving'}
              className="inline-flex items-center px-4 py-2 bg-fourth-base text-white rounded-lg hover:opacity-90 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
            >
              {saveStatus === 'saving' ? (
                <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
              ) : saveStatus === 'success' ? (
                <CheckCircle className="h-4 w-4 mr-2" />
              ) : (
                <Save className="h-4 w-4 mr-2" />
              )}
              {saveStatus === 'saving' ? 'Guardando...' : 'Guardar Cambios'}
            </button>
          </div>
        </div>
      </div>

      <div className="flex">
        {/* Sidebar Navigation */}
        <div className="w-full bg-white dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700">
          <nav className="container mx-auto px-6">
            <div className="flex gap-2 overflow-x-auto py-3">
              {tabs.map((tab) => {
                const Icon = tab.icon;
                const isActive = activeTab === tab.id;
                return (
                  <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id)}
                    className={`flex items-center gap-2 px-4 py-2 rounded-lg whitespace-nowrap transition-colors ${
                      isActive
                        ? 'bg-fourth-base text-white shadow'
                        : 'text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700'
                    }`}
                  >
                    <Icon className={`h-4 w-4 ${isActive ? 'text-white' : 'text-gray-500'}`} />
                    <span className="text-sm font-medium">{tab.label}</span>
                  </button>
                );
              })}
            </div>
          </nav>

          {/* Main Content */}
          <div className="flex-1 p-6 mt-6">
            <div className="w-full">
              {/* Details Tab */}
              {activeTab === 'details' && (
                <div className="space-y-6">
                  <div>
                    <h2 className="text-xl font-semibold text-gray-900 dark:text-white mb-6">
                      Información General
                    </h2>

                    <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-6">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div>
                          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                            Nombre del Negocio
                          </label>
                          <input
                            type="text"
                            name="businessName"
                            value={formData.businessName || ''}
                            onChange={handleInputChange}
                            className={inputClassName}
                            placeholder="Nombre del negocio"
                          />
                        </div>

                        <div>
                          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                            Tipo de Servicio
                          </label>
                          <input
                            type="text"
                            name="type"
                            value={formData.type || ''}
                            onChange={handleInputChange}
                            className={inputClassName}
                            placeholder="Ej: Plomería, Electricidad, etc."
                          />
                        </div>
                      </div>

                      <div className="mt-6">
                        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                          Descripción
                        </label>
                        <textarea
                          name="description"
                          value={formData.description || ''}
                          onChange={handleInputChange}
                          rows={4}
                          className={inputClassName}
                          placeholder="Describe tu servicio..."
                        />
                      </div>

                      <div className="mt-6">
                        <label className="flex items-center cursor-pointer">
                          <input
                            type="checkbox"
                            name="isActive"
                            checked={formData.isActive || false}
                            onChange={(e) =>
                              setFormData((prev: any) => ({
                                ...prev,
                                isActive: e.target.checked,
                              }))
                            }
                            className="w-4 h-4 text-fourth-base focus:ring-fourth-base border-gray-300 dark:border-gray-600 rounded bg-white dark:bg-gray-700"
                          />
                          <span className="ml-2 text-sm font-medium text-gray-700 dark:text-gray-300">
                            Servicio activo
                          </span>
                        </label>
                      </div>
                    </div>
                  </div>
                </div>
              )}

              {/* Location Tab */}
              {activeTab === 'location' && (
                <div className="space-y-6">
                  <div>
                    <h2 className="text-xl font-semibold text-gray-900 dark:text-white mb-6">
                      Ubicación
                    </h2>

                    <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-6">
                      <div className="space-y-6">
                        <div>
                          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                            Ciudad/Ubicación
                          </label>
                          <input
                            type="text"
                            name="location"
                            value={formData.location || ''}
                            onChange={handleInputChange}
                            className={inputClassName}
                            placeholder="Bogotá"
                          />
                        </div>

                        <div>
                          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                            Dirección Completa
                          </label>
                          <textarea
                            name="address"
                            value={formData.address || ''}
                            onChange={handleInputChange}
                            rows={3}
                            className={inputClassName}
                            placeholder="Calle 72 #10-15, Bogotá, Colombia"
                          />
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              )}
              {/* Images Tab */}
              {activeTab === 'images' && (
                <div className="space-y-6">
                  <div>
                    <h2 className="text-xl font-semibold text-gray-900 dark:text-white mb-6">
                      Imágenen de portada
                    </h2>

                    <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-6">
                      <div>
                        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                          Imagen de servicio
                        </label>
                        <div className="border-gray-300 dark:border-gray-600 rounded-lg p-4">
                          {formData.coverImage ? (
                            <div className="space-y-2">
                              <div className="relative inline-block">
                                <Image
                                  src={resolveImageUrl(formData.coverImage)}
                                  alt="Cover"
                                  width={400}
                                  height={200}
                                  className="w-full h-48 rounded object-cover"
                                  unoptimized={Boolean(
                                    formData.coverImage?.startsWith('blob:') ||
                                      formData.coverImage?.startsWith('data:')
                                  )}
                                />
                                <button
                                  type="button"
                                  onClick={() => handleRemoveImage('coverImage')}
                                  className="absolute top-2 right-2 w-8 h-8 bg-red-600 hover:bg-red-700 text-white rounded-full text-sm flex items-center justify-center transition-colors"
                                >
                                  ✕
                                </button>
                              </div>
                            </div>
                          ) : (
                            <div>
                              <FileUpload
                                onFile={(url) =>
                                  setFormData((prev: any) => ({ ...prev, coverImage: url }))
                                }
                                storeId={serviceId}
                              />
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              )}

              {/* Contact Tab */}
              {activeTab === 'contact' && (
                <div className="space-y-6">
                  <div>
                    <h2 className="text-xl font-semibold text-gray-900 dark:text-white mb-6">
                      Información de Contacto
                    </h2>

                    <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-6">
                      <div className="space-y-6">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                          <div>
                            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                              <Phone className="w-4 h-4 inline mr-2" />
                              Teléfono
                            </label>
                            <input
                              type="tel"
                              name="phone"
                              value={formData.phone || ''}
                              onChange={handleInputChange}
                              className={inputClassName}
                              placeholder="+57 300 123 4567"
                            />
                          </div>

                          <div>
                            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                              <Globe className="w-4 h-4 inline mr-2" />
                              WhatsApp
                            </label>
                            <input
                              type="tel"
                              name="whatsappNumber"
                              value={formData.whatsappNumber || ''}
                              onChange={handleInputChange}
                              className={inputClassName}
                              placeholder="+57 300 123 4567"
                            />
                          </div>
                        </div>

                        <div>
                          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                            <Mail className="w-4 h-4 inline mr-2" />
                            Email
                          </label>
                          <input
                            type="email"
                            name="email"
                            value={formData.email || ''}
                            onChange={handleInputChange}
                            className={inputClassName}
                            placeholder="contacto@servicio.com"
                          />
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Save Status Toast */}
      {saveStatus === 'success' && (
        <div className="fixed bottom-4 right-4 bg-green-500 text-white px-6 py-3 rounded-lg shadow-lg flex items-center">
          <CheckCircle className="h-5 w-5 mr-2" />
          Cambios guardados correctamente
        </div>
      )}

      {saveStatus === 'error' && (
        <div className="fixed bottom-4 right-4 bg-red-500 text-white px-6 py-3 rounded-lg shadow-lg flex items-center">
          <AlertCircle className="h-5 w-5 mr-2" />
          Error al guardar los cambios
        </div>
      )}
    </div>
  );
}

