        )}

        {!loading && filteredStores.length === 0 && (
          <div className="text-center py-12">
            <div className="text-gray-400 mb-4">
              <Store className="h-12 w-12 mx-auto" />
            </div>
            <h3 className="text-lg font-medium text-gray-900 dark:text-white mb-2">
              No stores found
            </h3>
            <p className="text-gray-500 dark:text-gray-400">
              {searchQuery || statusFilter !== 'all' || platformFilter !== 'all'
                ? 'Try adjusting your filters to see more results.'
                : 'Your stores will appear here once you create them.'}
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import React, { useState, useMemo } from 'react';
import { gql } from '@apollo/client';
import Link from 'next/link';
import {
  Package,
  Plus,
  Search,
  Edit,
  Trash2,
  Eye,
  Copy,
  Star,
  AlertTriangle,
  CheckCircle,
  XCircle,
  Image as ImageIcon,
  DollarSign,
} from 'lucide-react';
import Image from 'next/image';
import KPICard from '../../components/KPICard';

// Types
interface Product {
  id: string;
  name: string;
  description: string;
  sku: string;
  price: number;
  comparePrice?: number;
  cost: number;
  category: string;
  subcategory?: string;
  tags: string[];
  images: string[];
  status: 'active' | 'draft' | 'archived';
  inventory: {
    tracked: boolean;
    quantity: number;
    lowStockThreshold: number;
  };
  seo: {
    title: string;
    description: string;
    handle: string;
  };
  createdAt: string;
  updatedAt: string;
  sales: {
    totalSold: number;
    revenue: number;
    averageRating: number;
    reviewCount: number;
  };
}

const categories = [
  'All Categories',
  'Clothing',
  'Accessories',
  'Electronics',
  'Home & Garden',
  'Sports & Fitness',
  'Beauty',
];

// GraphQL queries & mutations
const GET_PRODUCTS_BY_STORE = gql`
  query GetProductsByStore($storeId: String!, $page: Int, $pageSize: Int) {
    productsByStore(storeId: $storeId, page: $page, pageSize: $pageSize) {
      items {
        id
        name
        title
        description
        price
        currency
        available
        inStock
        stock
        landing
        images {
          id
          url
          order
        }
        colors {
          id
          color
          colorHex
        }

        categories {
          category {
            id
            name
            slug
          }
        }
      }
      total
      page
      pageSize
    }
  }
`;

const UPDATE_PRODUCT = gql`
  mutation UpdateProduct($id: String!, $input: UpdateProductInput!) {
    updateProduct(id: $id, input: $input) {
      id
      name
      title
      description
      price
      currency
      available
      inStock
      stock
      storeId
      images {
        id
        url
        order
      }
      colors {
        id
        name
        hex
      }
      sizes {
        id
        name
        value
      }
      categories {
        id
        name
        slug
      }
      createdAt
      updatedAt
    }
  }
`;

const CREATE_PRODUCT = gql`
  mutation CreateProduct($input: CreateProductInput!) {
    createProduct(input: $input) {
      id
      name
      title
      description
      price
      currency
      available
      inStock
      stock
      storeId
      externalId
      images {
        id
        url
        order
      }
      colors {
        id
        color
        colorHex
      }
      variants {
        id
        typeVariant
        nameVariant
        jsonData
      }
      stocks {
        id
        price
      }
      categories {
        id
        name
        slug
      }
      createdAt
      updatedAt
    }
  }
`;

const DELETE_PRODUCT = gql`
  mutation DeleteProduct($id: String!) {
    deleteProduct(id: $id) {
      id
      name
    }
  }
`;

const DELETE_PRODUCTS = gql`
  mutation DeleteProducts($ids: [String!]!) {
    deleteProducts(ids: $ids) {
      count
    }
  }
`;

export default function ProductsPage() {
  // start with an empty list — replace with real data via GraphQL/useQuery when ready
  const [products, setProducts] = useState<Product[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('All Categories');
  const [statusFilter, setStatusFilter] = useState('all');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('list');

  // Calculate KPIs
  const kpis = useMemo(() => {
    const totalProducts = products.length;
    const activeProducts = products.filter((p) => p.status === 'active').length;
    const lowStockProducts = products.filter(
      (p) => p.inventory.tracked && p.inventory.quantity <= p.inventory.lowStockThreshold
    ).length;
    const totalRevenue = products.reduce((sum, p) => sum + p.sales.revenue, 0);
    const averageRating =
      products.length > 0
        ? products.reduce((sum, p) => sum + p.sales.averageRating, 0) / products.length
        : 0;

    return {
      totalProducts,
      activeProducts,
      lowStockProducts,
      totalRevenue,
      averageRating: Math.round(averageRating * 10) / 10,
    };
  }, [products]);

  // Filter products
  const filteredProducts = useMemo(() => {
    return products.filter((product) => {
      const matchesSearch =
        product.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        product.sku.toLowerCase().includes(searchTerm.toLowerCase()) ||
        product.description.toLowerCase().includes(searchTerm.toLowerCase());

      const matchesCategory =
        categoryFilter === 'All Categories' || product.category === categoryFilter;
      const matchesStatus = statusFilter === 'all' || product.status === statusFilter;

      return matchesSearch && matchesCategory && matchesStatus;
    });
  }, [products, searchTerm, categoryFilter, statusFilter]);

  // Get status color
  const getStatusColor = (status: string) => {
    switch (status) {
      case 'active':
        return 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-300';
      case 'draft':
        return 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-300';
      case 'archived':
        return 'bg-gray-100 text-gray-800 dark:bg-gray-900 dark:text-gray-300';
      default:
        return 'bg-gray-100 text-gray-800 dark:bg-gray-900 dark:text-gray-300';
    }
  };

  // Get stock status
  const getStockStatus = (product: Product) => {
    if (!product.inventory.tracked)
      return { status: 'unlimited', color: 'text-blue-600', icon: CheckCircle };

    const { quantity, lowStockThreshold } = product.inventory;
    if (quantity === 0) return { status: 'out of stock', color: 'text-red-600', icon: XCircle };
    if (quantity <= lowStockThreshold)
      return { status: 'low stock', color: 'text-orange-600', icon: AlertTriangle };
    return { status: 'in stock', color: 'text-green-600', icon: CheckCircle };
  };

  // Handle delete product
  const handleDelete = (id: string) => {
    setProducts((prev) => prev.filter((product) => product.id !== id));
  };

  // Handle duplicate product
  const handleDuplicate = (product: Product) => {
    const newProduct: Product = {
      ...product,
      id: `${Date.now()}`,
      name: `${product.name} (Copy)`,
      sku: `${product.sku}-COPY`,
      status: 'draft',
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      sales: {
        totalSold: 0,
        revenue: 0,
        averageRating: 0,
        reviewCount: 0,
      },
    };
    setProducts((prev) => [newProduct, ...prev]);
  };

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">Products</h1>
          <p className="text-gray-600 dark:text-gray-400 mt-1">
            Manage your product catalog and inventory
          </p>
        </div>
        <div className="flex items-center gap-3">
          <div className="flex bg-gray-100 dark:bg-gray-800 rounded-lg p-1">
            <button
              onClick={() => setViewMode('list')}
              className={`px-3 py-1 rounded text-sm font-medium transition-colors ${
                viewMode === 'list'
                  ? 'bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm'
                  : 'text-gray-600 dark:text-gray-400'
              }`}
            >
              List
            </button>
            <button
              onClick={() => setViewMode('grid')}
              className={`px-3 py-1 rounded text-sm font-medium transition-colors ${
                viewMode === 'grid'
                  ? 'bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm'
                  : 'text-gray-600 dark:text-gray-400'
              }`}
            >
              Grid
            </button>
          </div>
