const UPDATE_STORE_CONFIG = gql`
  mutation UpdateStore($storeId: String!, $input: UpdateStoreInput!) {
    updateStore(storeId: $storeId, input: $input) {
      id
      storeId
      name
      businessName
      primaryColor
      secondaryColor
      accentColor
      backgroundColor
