const GET_USERS_BY_RESTAURANT = gql`
  query GetUsersByRestaurant($restaurantId: String!) {
    usersByRestaurant(restaurantId: $restaurantId) {
      id
      name
      email
    }
  }
`;

// Tipos de TypeScript
interface User {
  id: string;
  name: string;
  email: string;
}

interface UserData {
  restaurantId?: string;
  restaurantName?: string;
  [key: string]: any;
}

// Componente KPICard
