const UsersByRestaurantPage = () => {
  const [userData, setUserData] = useState<UserData>({});
  const [searchTerm, setSearchTerm] = useState('');
  const [isClient, setIsClient] = useState(false);

  // Effect para obtener userData del localStorage
  useEffect(() => {
    setIsClient(true);
    try {
      const storedUserData = JSON.parse(localStorage.getItem('user') || '{}');
      setUserData(storedUserData);
    } catch (error) {
      console.error('Error parsing user data from localStorage:', error);
      setUserData({});
    }
  }, []);

  // Query para obtener usuarios por restaurante
  const {
    data: usersData,
    loading: usersLoading,
    error: usersError,
  } = useQuery(GET_USERS_BY_RESTAURANT, {
    variables: { restaurantId: userData?.restaurantId || '' },
    skip: !userData?.restaurantId || !isClient,
  });

  // Obtener usuarios
  const users: User[] = usersData?.usersByRestaurant || [];

  // Filtrar usuarios por búsqueda
  const filteredUsers = useMemo(() => {
    return users.filter((user) => {
      return (
        user.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        user.email.toLowerCase().includes(searchTerm.toLowerCase())
      );
    });
  }, [searchTerm, users]);

  // Estadísticas calculadas
  const stats = useMemo(() => {
    const totalUsers = users.length;
    const filteredCount = filteredUsers.length;

    return {
      totalUsers,
      filteredCount,
    };
  }, [users, filteredUsers]);

  const getInitials = (name: string) => {
    return name
      .split(' ')
      .map((n) => n[0])
      .join('')
      .toUpperCase();
  };

  // No mostrar nada hasta que se monte en el cliente
  if (!isClient) {
    return null;
  }

  if (usersLoading) {
    return (
      <div className="min-h-screen bg-gray-50 dark:bg-gray-900 p-4 sm:p-6 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-orange-600 mx-auto mb-4"></div>
          <p className="text-gray-600 dark:text-gray-400">Cargando usuarios...</p>
        </div>
      </div>
    );
  }

  if (usersError) {
    return (
      <div className="min-h-screen bg-gray-50 dark:bg-gray-900 p-4 sm:p-6 flex items-center justify-center">
        <div className="text-center">
          <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg p-6">
            <h3 className="text-lg font-semibold text-red-800 dark:text-red-400 mb-2">
              Error al cargar usuarios
            </h3>
            <p className="text-red-600 dark:text-red-400">{usersError.message}</p>
          </div>
